-- Reports 3001-3500 of 3671

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('3c3dd6d6-3a32-5a2c-8a27-316af37e8a52','8bcc6303-af49-5a2a-a3f9-2aaee5875939','2026-02-13 15:21:35','CESA SUB 16','Es exactamente lo que le enseñaría a cualquier persona nueva en la empresa como el perfil idóneo de central a firmar. 

Rápido fuerte contundente, buen desplazamiento y con capacidad de sacar el balón.','AV','Firmar'),
  ('33af0674-4796-5461-9e58-84106947f520','38bed638-5f1b-5460-9a41-a11070614fae','2026-02-13 15:24:01','CESA SUB 16','Espectacular despliegue, grandes capacidades defensivas y excelente con balón.','AV','Firmar'),
  ('6490ef93-27e6-598c-9a49-c63b7451e600','9fcd16af-6358-5246-bc75-e61af9a864f6','2026-02-13 15:25:42','CESA SUB 16','Jugador excelente a nivel técnico, pero con deficiencias físicas, a seguir si el jugador crece a nivel de estatura. 


Por capacidades individuales y capacidades técnicas el jugador está sobrado. 


Seguir en función de crecimiento. De no crecer está en la escuela equivocada.','AV','Seguir'),
  ('4ec39feb-3235-58a5-9560-398857f7dcab','e7c82991-587b-5d87-bd8b-f58d14e9a2d5','2026-02-13 15:28:11','CESA SUB 16','Jugador con un nivel técnico excelente. Y con buenas condiciones físicas tiene desborde y capacidad de ser vertical.','AV','Firmar'),
  ('4cfa7ee3-545f-5033-8af7-f67249158f78','51eb8cbb-308a-59df-b76a-04960033302c','2026-02-13 15:32:04','CESA SUB 16','Jugador con poco perfil físico para jugar de delantero en fútbol profesional y sin expectativa de crecer.','AV','Descartar'),
  ('b5b32c88-b644-554c-b062-d430002fb3e0','ba38fa3d-b857-5164-ac3a-8fe02332c5fa','2026-02-13 15:33:26','CESA SUB 16','Perfil idéntico a Pablo Reyes','AV','Descartar'),
  ('4af0fcaf-bb01-5017-8955-6f1ba2308c78','81a41bb7-02e4-5c9a-933c-0decedba6c05','2026-02-13 15:34:17','CESA SUB 16','Jugador con unas capacidades condicionales increíbles y que a nivel técnico va sobrado ya coordinado, le falta muscular para aparecer en élite.','AV','Firmar'),
  ('2098dbed-7b3c-56ab-9c89-ca9ad733012b','523530a9-25d2-5846-8bfb-ed21d7b5e5b9','2026-02-13 15:43:41','CESA SUB 16','Jugador Qi para ser sub 16 esta con un nivel condicional muy deficiente, aunque tenga grandes condiciones técnicas creo que es un gran handicap para apostar por el','AV','Descartar'),
  ('e15e7471-8bc8-5abe-bc1e-19971aea88e7','ee127d9a-a664-5ab4-b352-4440e4a7494d','2026-02-13 15:50:26','CESA SUB 16','Jugador para algo más, interesante a nivel técnico y que puede crecer a nivel físico','AV','Seguir'),
  ('d657dc53-7c34-5315-afd6-1d41b5a2b14c','68e1a3c0-d995-55aa-b52f-149878d61b2a','2026-02-13 16:16:53','TENERIFE JUV. A - Deportivo Juv. A','Central zurdo con una estatura algo superior a 1''85 m y complexión fuerte. No destaca por velocidad, pero no me ha parecido lento. Muy buen partido desde lo defensivo, pero sobre todo con balón. Tiene calidad para dar el primer pase y también sabe cuándo conducir y cambiar de ritmo para dejar atrás al atacante y ganar metros. En el partido también transmite mucha personalidad.','RP','Seguir'),
  ('80558fe4-44bd-56f6-aac5-550aa66a1cc9','2a613995-ada2-5508-a7dc-c89ec5ef3d3a','2026-02-13 16:34:26','TENERIFE JUV. A - Deportivo Juv. A','Mediapunta diestro con una estatura alrededor de 1''75 m y complexión más o menos delgada. Nivel técnico alto para controles, giros y desplazamiento de balón, también a balón parado. Retiene bien la pelota en campo rival y tiene cierta visión a partir de tres cuatros.','RP','Seguir'),
  ('b87a4bbd-276f-5ecf-9ae6-c510f1880e83','6b388a99-a830-5df1-b516-b6708e3b7802','2026-02-13 16:37:32','TENERIFE JUV. A - Deportivo Juv. A','Extremo diestro con una estatura algo inferior a 1''80 m y complexión fuerte. Sin parecer extremadamente rápido, tiene una carrera potente. En el partido no demuestra mucho, pero me gusta el perfil físico.','RP','Seguir'),
  ('e05566eb-5744-5e13-97c3-ab185f88a772','1df18ab1-3df1-5b64-a1ee-8019cfa81771','2026-02-13 16:43:49','Tenerife Juv. A - DEPORTIVO JUV. A','Lateral derecho con una estatura alrededor de 1''75 m y complexión normal, con una gran velocidad de reacción y en carrera. Agresivo en el duelo y muy bueno en la acción defensiva, especialmente en el 1vs1. En ataque tiene muhcísimo recorrido, calidad para intervenir en todas las alturas y visión en el último tercio para combinar con su extremo. Centra bien.','RP','Seguir'),
  ('8f22dae6-c7dc-5d68-b11b-e6bd1d5aa793','795ff7e0-dadd-5a42-ac46-97555f0b3469','2026-02-13 16:52:22','Tenerife Juv. A - DEPORTIVO JUV. A','Lateral izquierdo con una estatura algo inferior a 1''80 m y complexión delgada. No me ha parecido muy rápido, pero tiene buena zancada. Jugador ofensivo y con una gran calidad para aportar con balón en todas las alturas. En el último tercio desdobla bien y tiene un gran centro. Defensivamente me ha gustado, pero le he notado algo lento de movimientos, no sé si por condiciones físicas o por actitud.','RP','Seguir'),
  ('60346cda-83d6-5202-b003-c56c3591c31c','72b77ef2-273e-5ec6-be78-3b6ab9234e19','2026-02-13 16:56:40','Tenerife Juv. A - DEPORTIVO JUV. A','Extremo diestro, en el partido actuando a pierna natural, con un perfil físico medio. Técnicamente no es muy destacable y no es rápido.','RP',NULL),
  ('922198ad-7dbd-5f88-82a5-b784146c3357','95f92406-ac3b-59ea-9ed3-4c172f4a0f77','2026-02-14 12:44:18','vs Patacona y Torrent (octubre 2025)','Extremo zurdo por derecha. Estatura media, complexión robusta, tren inferior fuerte. Es jugador potente, rápido y con recorrido. 

Buen nivel técnico, primeros controles positivos, capaz de pasar de primeras, bien en conducción. Creativo en el 1v1 y vertical en sus acciones.  Busca progresar en carrera, le da continuidad a las jugadas con asociaciones cortas. Recibe la mayoría de veces al pie, debe buscar más el espacio. Se mueve bastante por dentro. Visión y sensibilidad para dar último pase. 

Es fuerte en el juego aéreo, intenso en presión, aguerrido en duelos individuales, con recorrido hacia atrás. 

Es perfil de extremo interesante. Sin estar tan inspirado en estos partidos, en su periodo de adaptación, deja detalles que llaman la atención. Me gustaría verlo próximo fin de semana en directo.','NB','Seguir'),
  ('b81ca98e-c834-5a5d-b00f-4d2ed6c4176a','8d710a95-ab1e-5c1e-8618-772e6a4b137e','2026-02-14 12:49:23','vs Atlético B','Central derecho de estatura aprox. 1.95, de complexión fuerte, físico compensado, da sensación de poco ágil en corto y no es veloz en largo. Aún con fundamentos por mejorar, pero es agresivo para salir de zona y afrontar duelos individuales. Con balón bien, sin ser excelente es capaz de romper líneas con pases y desplazar en largo. 

Jugador con potencial alto por perfil físico. Demostrando madurez y evolución en últimos meses.','NB','Firmar'),
  ('a1092598-54e3-5bad-8527-ac8880275058','dc38c4a7-384a-50c4-ae81-6fb90d124ca3','2026-02-14 12:54:18','vs Sanluqueño','Central zurdo ok pero que tampoco tiene potencial top. Es jugador que puede tener recorrido pero no es el perfil que buscamos precisamente.','NB','Seguir'),
  ('29948524-d0e3-5937-b9e8-62574a82b11a','551a445d-f976-56ec-8691-c06c64e6791b','2026-02-14 13:00:04','vs Sanluqueño','Julio es lateral izquierdo de físico promedio: estatura por debajo de 1.70 m, delgado, poco poderoso, rápido, con recorrido. 

En ataque tiene buen nivel técnico para asociarse, progresar por sí solo y llegar a último tercio. En fase defensiva es intenso y agresivo, pese a que sufre ante extremos potentes. Activo en presión, cómodo saliendo de zona. 

Es un lateral con posibilidades de ir hacia arriba aunque con físico bastante peor que los Salinas, Davinchi...Julio es lateral izquierdo de físico promedio: estatura por debajo de 1.70 m, delgado, poco poderoso, rápido, con recorrido. 

En ataque tiene buen nivel técnico para asociarse, progresar por sí solo y llegar a último tercio. En fase defensiva es intenso y agresivo, pese a que sufre ante extremos potentes. Activo en presión, cómodo saliendo de zona. 

Es un lateral con posibilidades de ir hacia arriba aunque con físico bastante peor que los Salinas, Davinchi...Aún así creo que es jugador a firmar.','NB','Firmar'),
  ('fd60cc35-d482-511c-8472-67c5cf338696','d3ec7413-221c-5360-8336-10c895d82e84','2026-02-14 13:01:03','vs Sanluqueño','#10 que puede evolucionar en #8 si crece más físicamente y en fase defensiva. Gran nivel técnico, llegada a último tercio, capacidad finalizadora. Activo en presión, aunque no se impone en duelos. Es jugador de nivel con perfil para ir hacia arriba.','NB','Firmar'),
  ('6c72ef6f-935a-5992-80e6-9e169ce4776c','3b81a6e9-a48a-58b1-b2cb-b1ce9dd17ec4','2026-02-14 13:03:15','vs Sanluqueño','Lo veo saltando directamente a club de Primera en la próxima temporada.','NB','Firmar'),
  ('f9456e38-5c2f-5851-90e3-40918ee61467','cb5ce986-a8a9-5d15-be14-da2354f0f724','2026-02-14 14:14:46','Carnaval Cup','Excel: delantero centro de condiciones físicas innatas privilegiadas. Actualmente +1.80 m, de piernas largas, delgado, con musculatura por hacer. Da sensación de que le faltan centímetros por ganar. Aún no coordinado del todo. Velocidad OK. Nada hecho, todo por desarrollar.

Es un jugador que actualmente está por debajo del nivel técnico medio del equipo, con problemas cuando entra en contacto con balón. También da sensación de que le falta comprensión del juego. 

Aún así, su físico es tan llamativo que vale la pena seguirlo de cerca.','NB','Seguir'),
  ('be7798cc-5460-5672-835b-498bae6aa427','4506ed3d-97ea-5ccc-9a46-1fed48482d76','2026-02-14 23:31:38','vs Betis B','Extremo de buen perfil físico-técnico. Es rápido, peligroso yendo al espacio, capaz de generar individualmente, pisa área. Perfil interesante.','NB','Seguir'),
  ('afcef72b-088c-5d5d-bdf6-52cc54aedd5c','0019ddbb-ea6a-56a5-a1c3-b8fa7c433242','2026-02-15 11:09:40','Nàstic - BETIS B','Centrocampista diestro de primera/segunda altura, para actuar como mediocentro, en doble pivote o como interior partiendo de la base y con algún recorrido. Estatura algo inferior a 1''90 m y complexión fuerte. No es muy rápido, pero choca muy bien y es muy poderoso en el duelo. Tiene una buena capacidad de robo y calidad y criterio para distribuir. En el partido además da una buena asistencia con un balón filtrado en la frontal del área.','RP','Firmar'),
  ('cc9c919d-1513-5ac4-b808-6454d123482e','eaa16d7a-934a-531c-9196-7b10147e96e0','2026-02-15 11:19:40','NÀSTIC - Betis B','Extremo zurdo con una estatura alrededor de 1''75 m y complexión normal. En el partido muestra un gran nivel técnico y mucha habilidad para fintar y eliminar rivales. Buen cambio de ritmo y centra bastante bien, incluso a balón parado. Jugador sin un gran perfil físico pero muy peligroso en el 1vs1.','RP','Seguir'),
  ('bfb280b2-a19c-5c93-91d2-989b6613a875','4506ed3d-97ea-5ccc-9a46-1fed48482d76','2026-02-15 11:21:50','NÀSTIC - Betis B','Extremo zurdo con una estatura alrededor de 1''75 m y complexión delgada pero potente. Jugador rápido, ágil y con un cambio de ritmo muy poderoso. Técnicamente muy bien y con una gran explosividad para fintar con el cuerpo y cambiar de dirección. Usa las dos piernas y, aunque es jugador de lado fuerte para recibir muchas veces y encarar, tiene llegada a área desde lado débil.','RP','Seguir'),
  ('b5a8896f-b828-565f-ad3c-37305d08ebfe','6d8db86e-9ac5-5b73-b19f-a9a2709b2f10','2026-02-15 11:32:44','NÀSTIC - Betis B','Segundo punta técnico pero con un perfil físico pobre','RP',NULL),
  ('08bd8b3f-4726-5062-96e7-7f54571282c9','32691a09-e321-555b-80bc-7edc74d72cc6','2026-02-15 11:34:28','Nàstic - BETIS B','Jugador diestro perfil mediapunta, en el partido actuando como delantero centro, con una estatura alrededro de 1''75 m y complexión normal. Técnicamente notable para quedarse la pelota y eliminar a uno o dos rivales con acciones sencillas, de dominio de balón. Buena visión de juego y sensación de peligro en el último tercio.','RP','Seguir'),
  ('1139ad0d-7b16-568f-9535-d23a924fff62','dc503b30-fe10-54fe-852c-8d76dd467bc9','2026-02-15 11:37:08','Nàstic - BETIS B','Centrocampista zurdo de primera/segunda altura, para actuar como mediocentro, en doble pivote o como interior, pero con capacidad para intervenir en todas las alturas. Estatura alrededor de 1''85m y complexión fuerte. Jugador poderoso en el duelo y con bastante alcance. Domina su zona, tiene capacidad de robo y después sabe hacer progresar al equipo, tanto a través del pase como de la conducción. Me sorprendería mucho que la temporada que viene no esté siendo importante en Segunda división si el Betis no le da oportunidades.','RP','Firmar'),
  ('7c0ef4c8-1939-57e7-b324-397da21cd257','5dcfea8b-88b0-5536-8d28-4fd59a4182c2','2026-02-15 11:40:36','Nàstic - BETIS B','Extremo diestro, en el partido actuando a pierna cambiada, con una estatura alrededor de 1''75 m y complexión normal. No tiene una gran velocidad, pero es técnico y sabe cambiar de ritmo para superar al rival en 1vs1. Buena visión de juego en campo rival.','RP','Seguir'),
  ('142d5a57-368e-55c9-94b3-d251a8d91079','d798ec05-56a8-58d6-b29a-f7ccddd102d6','2026-02-15 11:45:43','Nàstic - BETIS B','Extremo zurdo con una estatura alrededor de 1''85 m y complexión fuerte. No es muy explosivo, pero sabe cambiar de ritmo y sí tiene una buena zancada en carrera. Técnicamente muy bien, tiene un buen dominio del balón y sabe desbordar en el 1vs1. Muy agresivo cerca del área, suele buscar definir la acción con centro y sobre todo disparo. Bien chocando y en duelos.','RP','Firmar'),
  ('9ca2c5d6-4a85-5c2f-85b5-958b8f9fc0bb','29011403-ae34-53eb-adab-b32f35352634','2026-02-15 11:49:45','Nàstic - BETIS B','Lateral derecho con una estatura alrededor de 1''75 m y complexión normal. Va muy bien a duelos, choca fuerte y suele imponerse. Es muy inteligente para robar en el 1vs1 y también cuando el rival recibe de espaldas. Con balón tiene un nivel técnico muy alto y personalidad para arriesgar y hacer progresar al equipo a través del pase y la conducción escapando de presiones. Combina muy bien con los compañeros y tiene mucho recorrido.','PP','Firmar'),
  ('b7b102e7-8d80-53c3-8b79-1c9e7843e610','93a33854-d3c6-5709-8a6e-747de7f13f8f','2026-02-15 11:53:39','Nàstic - BETIS B','Central zurdo con una estatura algo inferior a 1''90 m y complexión fuerte. En el partido comete algunos errores, pero también acierta muchas veces por ser proactivo y agresivo a la hora de saltar y realizar la acción defensiva. Central de mucha jerarquía, muy imponente en el duelo y con potencial de mejora todavía. Con balón se muestra seguro y también valiente para filtrar algunos balones. Perfil top.','RP','Firmar'),
  ('a514a272-58f5-589b-b2df-acf6ade8f598','c93fece2-a8f8-5ae1-a1fd-f351db87e5ac','2026-02-15 17:23:06','vs Teruel','Juega por dentro primero, después de extremo. Jugador que da sensación de estar por encima de la categoría, tanto por ritmo como en recursos. Me parece que tiene más potencial por dentro. Con empuje y capacidad de llegada. Sacrificado y trabajador en fase defensiva.

Está para fútbol profesional.','NB','Firmar'),
  ('f815f306-1ac5-5d4b-befd-c57238204db8','657e7fdb-9b93-5ee4-bbe5-a2ad666eb656','2026-02-15 17:25:27','vs Teruel','Como #8 muestra grandes recursos, poderío físico, despliegue, llegada con conducciones. Es un jugador completo y con potencial de máximo nivel.','NB','Firmar'),
  ('33ac6906-6615-5985-9b4c-10ff2905d96d','19fe33a1-d72f-53ae-b01c-fa1d3cc75127','2026-02-15 22:07:35','CELTA B - Real Avilés','Atacante diestro, en el partido actuando como enganche por la derecha pero adaptable a un rol de falso extremo, mediapunta o segundo delantero. Estatura algo superior a 1''75 m, complexión normal. Jugador de gran calidad técnica sobre todo en el último tercio, donde muestra una gran visión de juego, último pase y disparo. Esta temporada tiene buenas cifras: 9 goles y 6 asistencias en 20 partidos en 1ª RFEF. Es un tipo de jugador por el que el Celta apuesta','RP','Seguir'),
  ('3d326a88-38d5-5b47-93bf-bb54d74d3ce5','8f1db253-3378-5624-b116-507cff75a0ec','2026-02-15 22:11:40','CELTA B - Real Avilés','Delantero centro con una estatura algo superior a 1''75 m y complexión normal. Jugador muy intenso en la presión y que soporta bien las cargas de los defensores. Buen juego de espaldas, aparece mucho y muy bien cuando el equipo necesita progresar directo por pasillo interior y es muy dinámico para alejar la pelota del rival con un control y descargar después. Buen nivel técnico y muy buena movilidad. Le falta mejorar cifras, pero creo que lo hará en las próximas dos temporadas. Buen delantero que si rompe a marcar puede valer muchos millones','RP','Firmar'),
  ('5f01724d-3528-50c0-b5a1-324cf389d9c5','2586033e-fd54-570c-97d5-ede8470701d6','2026-02-15 22:15:12','CELTA B - Real Avilés','Carrilero diestro con una estatura alrededor de 1''85 m y complexión fuerte. Es rápido en carrera para imponerse al extremo y muy poderoso en el choque, va muy bien a duelos y en muchas ocasiones progresa por pura potencia, llevándose rebotes en el balón dividido. Técnicamente correcto. Le falta mejorar y me cuesta verle como extremo, pero es muy joven y tiene un perfil físico brutal para jugar de lateral/carrilero.','RP','Firmar'),
  ('7127cf22-f60b-5afe-87b3-6c9d96f81688','446b45f2-cab9-597a-8537-072a82502164','2026-02-15 22:20:15','CELTA B - Real Avilés','Central diestro con una estatura algo inferior a 1''85 m y complexión normal. Partido correcto en defensa y con balón, pero sin grandes acciones. No me termina, pero el club apostará por él en el medio plazo.','RP','Seguir'),
  ('67b8266e-c3d0-5f5c-82a5-831913f5e6cc','171869a2-2e5e-576a-9103-e29ac09f38ba','2026-02-15 22:22:44','CELTA B - Real Avilés','Centrocampista diestro de segunda altura, para actuar como mediocentro, en doble pivote o como interior, con una estatura alrededor de 1''85 m y complexión fuerte. Técnicamente notable y con una capacidad física para ganar duelos y dominar en conducción sobresaliente. En el partido marca un golazo tras un eslalon superando a tres rivales.','RP','Firmar'),
  ('e5c5e066-4246-57f5-baae-90c3da08ce2b','bf08e968-5cc5-5b3f-b51c-a894e931dbfe','2026-02-15 22:24:28','CELTA B - Real Avilés','Jugador diestro con una estatura alrededor de 1''80 m y complexión normal, en el partido actuando como central en línea de tres aunque es centrocampista. Hace un partido muy correcto tanto en defensa como sobre todo con balón.','RP','Seguir'),
  ('8cf4a005-7b46-5b26-8783-4f42ad08693d','7b9bfb2f-ad83-534b-834b-44b14f395f85','2026-02-15 22:28:16','UD VALL D''UXÓ - Villarreal C','Delantero centro diestro con una estatura alrededor de 1''85 m y complexión más o menos fuerte. Choca bien y tiene cierto criterio con balón. Me gusta el perfil y en el partido marca un gol, pero tiene cifras muy pobres.','RP','Seguir'),
  ('804e2a14-0c13-562e-a6ab-52e85cf5e900','29011403-ae34-53eb-adab-b32f35352634','2026-02-16 09:01:06','informe general','Ágil en espacios cortos, agresivo sin balón aunque excesivamente dependiente del tackle, dudas sobre poderío a mayor nivel, muy intenso en duelos continuos dificil de superar, rápido en carrera, distancia larga le cuesta más. Acelera muy rápido. podría tener más impacto en ultimo tercio.','PP','Firmar'),
  ('cad2604a-5011-5f4e-849f-cca92f392dfa','aa0e4f48-67c7-59bd-a113-7f62c5376a14','2026-02-16 09:44:06','vs Bilbao athletic','Jugó de central. Contundente en duelos, capacidad de llegada. Algunos errores tácticos. Bien con balón','PP','Firmar'),
  ('231241ed-7895-574c-bc28-81c010764e3c','93a33854-d3c6-5709-8a6e-747de7f13f8f','2026-02-16 09:45:01','vs real madrid','errores puntuales en acciones técnica básicas, decisiones de riesgo donde comete errores sin soporte. Algo precipitado
En defensa defiende hacia delante, bien en duelos.','PP','Firmar'),
  ('cb4b36b9-3f9e-5d3f-956d-56410e2c70a9','6abc2a1b-06a0-5fa5-a57f-c69fe67ba43c','2026-02-16 09:45:58','Informe general','Jugador con buen perfil físico, alto y pierna larga. Cada recepción intenta desequilibrar, primera arrancada con zancada larga que le permite alejarse de rival. Extremo de ir al espacio. Protege bien con el cuerpo ante presión, aunque no es jugador de manejo. Después. de desequilibrio busca siempre profundidad.','PP','Firmar'),
  ('3f988b39-76fe-58d6-ac9b-028eabdb7288','7a52fe55-cc43-59e3-b3cb-4363c6892570','2026-02-16 11:19:32','CESA SUB 16','Buen jugador con buen perfil y buenas cualidades a seguir. 

Destaca a nivel técnico.','AV','Seguir'),
  ('d5de6cc7-9fe3-57ab-a362-d9543f8e50ce','1fc5073a-5a9f-5c8a-b0de-ff3f4d3cc964','2026-02-16 11:22:23','ETHAN Carbonell','Jugador que cumple con perfil, pero para mi gusto tiene que ser más rápido y mejorar en giros.','AV','Seguir'),
  ('9abed3ad-7d98-5e76-980c-6c22272276bc','47642bb4-5af7-5bc2-aa9c-5c963e7063c9','2026-02-16 11:24:05','CESA SUB 16','Perfil interesantísimo, jugador que es nuestro ejemplo perfecto de lo que buscamos en un lateral izquierdo.','AV','Firmar'),
  ('8ae02889-8e16-56a4-bb3e-b65bae89ad19','5755793f-c135-5b5b-b000-566964487348','2026-02-16 11:26:06','CESA SUB 16','Jugador con buenas condiciones, creo que todavía no puedo tener una opinión firme sobre si nos debe interesar o no, pero con condiciones técnicas sobresalientes.','AV','Seguir'),
  ('59daadc1-bab0-56d0-9b81-553c0d5c0f31','312836fc-fc81-54e8-8ec0-3f663b64771c','2026-02-16 11:27:15','CESA SUB 16','Jugador de perfil bajito con unas condiciones técnicas excelentes, creo que el handicap físico no cubre sus condiciones técnicas tan buenas.','AV','Descartar'),
  ('a45b264f-b69b-55c7-b74f-8a08652db4bc','5b26d956-89df-5f39-8ed6-ddd1e3cdaae4','2026-02-16 11:28:20','CESA SUB 16','Jugador con un perfil físico normal, para mi puede mejorar mucho más las acciones dentro de área y tiene un gran margen de mejora','AV','Seguir'),
  ('24675755-72ca-5a40-a10a-8eef7baba810','0642d9f6-8bbe-5d72-86f5-aff9f5ebf770','2026-02-16 11:29:16','CESA SUB 16','Es el perfil exacto que puede generar dudas pero que al fin y al cabo, no puede nunca tener cabida en fútbol profesional bajito y con tendencia a engordar es Pablo reyes en mediocentro','AV','Descartar'),
  ('cbdc058f-e50f-52e1-b1ea-45fac39e8d9c','c792d3dc-3015-5485-9fff-7139b941613e','2026-02-16 11:30:33','CESA SUB 16','Extremo que necesitamos, cumple con el perfil y es un jugador súper vertical.','AV','Firmar'),
  ('12e4c228-3de2-5a7f-9ed7-2bbd85d78822','c8e32de1-2dcd-5ffe-9d61-dc0adeec0f3c','2026-02-16 11:36:26','CESA SUB 16','Jugador para mí con poco recorrido, pongo en seguir por falta de convicción en lo que he visto','AV','Seguir'),
  ('f27308c3-91aa-5893-905b-08f3c78ad218','24289a04-e455-5289-ace4-9bb7da9e0e75','2026-02-16 11:37:21','CESA SUB 16','Gorka es un jugador   Con una calidad excepcional  y un nivel altísimo en espacios reducidos. 

Tiene pese a su físico un nivel increíble, jugador importantísimo y más donde se encuentra','AV','Firmar'),
  ('b54fccb7-b225-5b79-894e-26587b2c4e8a','8d710a95-ab1e-5c1e-8618-772e6a4b137e','2026-02-16 11:53:15','Va Nastic','Debuta y lo hace todo bien, espectacular perfil.','AV','Firmar'),
  ('f7314f37-edb5-539b-87d7-3656caaa4867','2586033e-fd54-570c-97d5-ede8470701d6','2026-02-16 12:12:29','Celta - Barakaldo','Es el lateral derecho perfecto para nosotros','AV','Firmar'),
  ('a1e5cd13-ffd7-5159-a8a1-ac3d0d021d2e','54276fa1-cba3-529a-93f0-46314b16a930','2026-02-16 12:27:21','Nastic - San Luqueño','Jugador cumplidor, que hace las cosas bien, pero que no tiene ninguna característica especial que nos haga verle un jugador diferencial para acudir a 1ª división.','AV','Descartar'),
  ('a11658c5-21b6-5f5b-8f74-fa43773c4259','8c04f16f-0cf8-5346-8e3c-2464197d760e','2026-02-16 14:32:26','CESA SUB 16','Jugador con un perfil físico engañoso, para mí en el futuro va a tender a engordar facilmente y no va a tener mucho recorrido, sensacion de qué el chico ahora es muy potente pero en el futuro se quedara corto','AV','Descartar'),
  ('ccd3fcf8-4587-5cef-80cf-90cf360f9951','dc004c59-56f6-55f6-9bcf-9f3994c1d90c','2026-02-16 14:38:18','CESA SUB 16','Jugador con un perfil físico bajito pero qué tiene mucha personalidad, con balón en los pies es excelente y tiene qué mejorar a nivel defensivo, sin embargo todo lo que puede mejorar, es poco critico, con su character y competitivkdad sera capaz de mejorar todos estos aspectos y creo que ira promocionando de menos a mucho mas','AV','Firmar'),
  ('7e0355f6-7d6a-57b7-949e-928269068140','9996a050-bc5a-56f8-bdc0-942a5982e5db','2026-02-16 15:28:02','CESA SUB 16','Lateral izquierdo con estatura media pero no problemática para su posición, perfil atlético y rápido, tiene buen trato de balón y se maneja bien con los pies, en el partido sufre mucho porque se quedan con uno menos,  volver a ver.','AV','Seguir'),
  ('5cd6c4f1-476e-5dc6-a450-1da87f314bf7','f455e623-550f-5ab1-b4cc-6e73f1585d54','2026-02-16 15:30:23','vs Nastic','Jugador que ha terminado teniendo un gran perfil físico, excelente en acciones a campo abierto con fisico y potencia para actuar en este tipo de acciones, calidad técnica en espacios reducidos y para mi determinante, tomando buenas decisiones, este jugador del año pasado a este ha cambiado mucho, ha progresado y para mi se le queda corta ya la categoría de jugador en 1ª RFEF.','AV','Firmar'),
  ('78f5bcd3-2e05-5c16-81cc-58eeb701a846','ea1e10b6-e115-5241-af6b-03c1493acff3','2026-02-16 15:41:48','CESA SUB 16','Perfil fisico que tendera a engordar y con poco nivel para mi, en defensa y a nivel técnico.','AV','Descartar'),
  ('316904b6-5269-54cd-9c76-6c28acdeff22','30283bd4-f551-547e-acf9-3ffbb0dee053','2026-02-16 15:40:19','ALGECIRAS - Juventud Torremolinos','Extremo zurdo, en el partido actuando a pierna natural, con una estatura alrededor de 1''85 m y complexión fuerte. Jugador rápido en carrera y explosivo para arrancar, aunque con sensación visual de ser algo pesado de movimientos. Con balón es agresivo en la toma de decisión y busca casi siempre 1vs1, pero técnicamente es justo y no termina de entender bien cómo moverse para recibir más veces y en mejores situaciones. Me gustaría ver cómo se comporta a pierna cambiada. Llega bien a línea de fondo y centra en bastantes ocasiones, y cuando la jugada va por banda contraria carga área. No tiene cifras muy destacables','RP',NULL),
  ('9410b356-45d8-50e8-88ca-ff8b5870ac45','740463c4-cc32-594a-a6f0-5771ff724a72','2026-02-16 15:43:22','CESA SUB 16 + CONVOCATORIAS CON ESPAÑOLA','Jugador con una gran capacidad cardiovascular, muy repetidor de esfuerzos, con inteligencia para ganar duelos y que con el balón se mueve muy bien, perfil de mediocentro muy interesante.  Para mi el jugador mas parecido a David Albelda jr.','AV','Firmar'),
  ('509c1727-db7b-512a-8e21-97fe79942b34','e82f5fe0-8b18-5ced-9eac-ffc77741505c','2026-02-16 15:46:17','CESA SUB 16 + CONVOCATORIAS','Delantero,  para mi con falta de nivel fisico de cara a futuro, le falta un poco de altura, pero tiene buenos movimientos y sabe moverse bien, para mi es un jugador que tiene que mejorar mucho en los cuerpo a cuerpo y aunque creo que seguirá mejorando, me cuesta verle crecer mas allá de 2ª rfef.','AV','Descartar'),
  ('b81a3542-82b8-503f-8d8e-c259d09f8e24','6190d33a-27c4-58d3-8292-3e000114117f','2026-02-16 15:51:09','cesa sub 16','Jugador bajito y muy muy pequeño, no es normal, debe estar teniendo problemas de crecimiento, el jugador es diferencial jugando contra gente de un año mas, tiene una calidad en acciones de espacio reducido muy muy interesantes , los padres no son tan bajitos como el y espero que en algún momento pueda crecer, para mi aunque sea un jugador contrario total a nuestro perfil, es el ejemplo perfecto junto con Gorka Buil de los jugadores en los que deberíamos hacer una excepción.','AV','Firmar'),
  ('723d7cfd-796c-596b-b810-01a96c7ee768','4277ddc7-0215-5a28-9e4a-0401b653c224','2026-02-16 16:23:54','CESA SUB 16','Portero con envergadura y aptitudes altas, creo que todavía tiene mucho que mejorar.','AV','Descartar'),
  ('514df66a-dc71-5104-b53b-f55df2df061d','2b90f848-9d7a-534d-9d22-b00059e0a420','2026-02-16 16:25:39','CESA SUB 16','Hace un torneo horrible, pero aun así demuestra que tiene mucho nivel y muchas capacidades, perfil fisico rápido y atlético, en nivel técnico va muy sobrado para la edad que tiene.','AV','Firmar'),
  ('912f1abb-4e13-5125-8c6f-c799776c0813','e37f069f-26ae-5186-8e65-8d31cb23bb05','2026-02-16 16:31:06','Cesa sub 16','Central excelente para enseñar a un scout nuevo, como deben ser los centrales que firmemos en esta empresa. 

Si no se lesiona será profesional seguro','AV','Firmar'),
  ('e8443d9e-f5dd-57c1-9f76-724a8d585439','3ed055bd-40c6-5fc3-9329-bfdc32ace474','2026-02-16 16:32:37','CESA SUB 16','Mediocentro de gran nivel con balón, muy altas capacidades,  y con buenismisas decisiónes con balón, sin embargo, creo que no es tan diferencial y que a nivel fisico aunque ahora no vaya bien, conforme vaya subiendo tendrá que ir mejorando mucho a ese nivel, y no lo veo con esas capacidades.','AV',NULL),
  ('d774fc37-87d1-567b-9be6-e64f0a19de83','a41401b7-0217-54cd-8a16-231ef8f06abb','2026-02-16 16:37:21','CESA SUB 16','No le gana una carrera ni a una tortuga, tiene buen desplazamiento, pero con eso no se come de central.','AV','Descartar'),
  ('68f17e20-1006-5bb8-8cbb-d3e619cfe193','d24eb8f3-cf61-5823-b1ca-dced3558ea4e','2026-02-16 16:38:22','cesa sub 16','Jugador vertical con ritmo altos de juego y que tienen una capacidad de jugar a muy altas velocidades competitivo y con mala leche, creo que en el futuro si sabe ordenar el desastre de cabeza que tiene.','AV','Seguir'),
  ('4f258de8-ae9d-572a-9966-58108a4cb52e','74b9292b-001d-5849-ae6d-943e5a6bde2f','2026-02-16 16:40:39','cesa sub 16','Hace un torneo muy malo, juega como delantero por primera vez este año y tiene unas altas capacidades a nivel de remate y saber moverse dentro del área, para mi un delantero que va a crecer mucho en los últimos años dentro del valencia.','AV','Firmar'),
  ('8e2033a9-35c2-5508-a39a-8d2a187bac38','70e5f80d-c6fa-5cd6-9d47-3b06d2140634','2026-02-16 16:40:30','Chiclana - CÁDIZ B','Jugador diestro, en el partido actuando primero como delantero centro y después como mediapunta, con una estatura algo superior a 1''85 m y complexión delgada. En el partido no se puede valorar mucho, pero tiene un físico llamativo y está siendo importante en el Mirandilla siendo juvenil.','RP','Seguir'),
  ('f4eaa14c-c91d-5b93-8e58-07f18cffd21f','6122a764-a31a-56fd-8703-f1ab12892eb2','2026-02-16 16:42:21','CESA SUB 16','Jugador que para mi es de rendimiento absoluto, y al que le veo poco recorrido de cara a futuro.','AV','Descartar'),
  ('196ccf6d-78c9-5bfe-994d-828e77b7197d','42ce8165-964a-57fe-b98b-5ab2dee32919','2026-02-16 16:43:59','CESA SUB 16','Jugador que no tiene la edad , reconocido abiertamente por el padre, el jugador no tiene nivel para mi para ir hacia delante, su forma de jugar como extremo solo se basa en tener mas fuerza, para mi no es rápido ni tiene un nivel alto de ejecución con balón.','AV','Descartar'),
  ('96f4e0eb-a429-5a63-96a6-f67b5e44a72c','ccf89672-77f6-5934-855a-8aa2baf1b8d2','2026-02-16 16:44:49','Chiclana - CÁDIZ B','Lateral izquierdo con una estatura alrededor de 1''80 m y piernas largas, quizás pueda crecer un poco más; y complexión delgada. Jugador correcto en defensa y con recorrido y ciertos recursos en ataque. Está jugando casi todo en DH y lleva 4 titularidades en 3ª RFEF con el Mirandilla. Siendo un jugador con margen de crecimiento físico y futbolístico, y viendo que el Cádiz puede apostar mucho por él, yo me lo plantearía.','RP','Decidir'),
  ('43349edf-738e-5b9c-93f7-9a1a7a5eb03b','d2c8e140-24e8-541c-9e6e-80a8b724127b','2026-02-16 16:46:05','cesa sub 16','Jugador con muy poco margen de mejora, para mi ya hecho, y que actualmente solo da rendimiento. Para mi es mas el nombre, que tiene por lo que ha sido sobre el proceso que otra cosa.','AV','Descartar'),
  ('088b2400-5a2e-5766-b0a9-44cf083f4748','2620d953-892e-5992-95f4-e45941828b1d','2026-02-16 16:49:53','CESA SUB 16','Jugador muy serio a seguir en el centro del campo, para mi le puede faltar fisico pero es un buen perfil mediocentro estilo Albelda.','AV','Seguir'),
  ('183e6161-2665-5b5a-88cf-8bcc025ed8c2','4a8b2f31-5840-5299-a143-021657aa3dc1','2026-02-16 16:51:25','cesa sub 16','Jugador con para mi poco recorrido, si estuviera en algúna otra escuela profesional de la comunidad no habría ido a la selección valenciana, para mi es un mediocentro muy correcto pero que no puede jugar a ritmos altos. Si mejora eso puede seguir siendo valido, a nivel defensivo le falta fisico para ganar mas duelos.','AV','Descartar'),
  ('0cf89c19-8067-5764-a5d8-897cd4bdd1d8','d9622b1f-9958-5427-b978-0ed91faaeda4','2026-02-16 16:58:58','Chiclana - CÁDIZ B','Centrocampista diestro con una estatura alrededor de 1''85 m y complexión delgada. En el partido no hay tiempo de valorar mucho, pero gana un par de duelos y deja buenas sensaciones.','RP','Seguir'),
  ('da2f47db-d202-5e5b-82ba-5d8ea6d586e2','b6bcaa57-f8c1-574f-ada6-2548d4f3598e','2026-02-16 17:11:50','Chiclana - CÁDIZ B','Centrocampista de primera altura con un perfil físico poco interesante.','RP',NULL),
  ('e2c43c0f-24e0-5629-822d-a8324b384243','c41e5f7b-3c53-5cdb-9f3c-da2aa1d1126e','2026-02-16 17:12:52','Chiclana - CÁDIZ B','Delantero centro diestro con una estatura alrededor de 1''85 m y complexión más o menos fuerte. En el partido no se puede valorar mucho, pero va bien a duelos y al espacio. Buenas sensaciones.','RP','Seguir'),
  ('6c5835bc-26bd-5886-b2c3-8e236b481544','28fbd152-d201-5ee0-ba5a-b420787b3472','2026-02-16 17:16:43','Chiclana - CÁDIZ B','Extremo diestro, en el partido jugando en ambas bandas, con una estatura algo inferior a 1''85 m y complexión delgada pero fuerte. Sale unos 20 minutos y deja algunas acciones de calidad. Parece tener buen cambio de ritmo y una zancada interesante. Cifras bastante pobres para un atacante en 3ª RFEF.','RP','Seguir'),
  ('b3a49cac-4ecc-544f-9e21-4b5f8145a7cb','e6259c68-2eab-5fbb-8f62-ab7df00ef799','2026-02-16 17:20:33','Chiclana - CÁDIZ B','Extremo de estatura baja y complexión normal. En el partido disputa 5 minutos y toca uno o dos balones.','RP',NULL),
  ('3e2a3698-5f41-59db-9540-a4272d12895b','4ee3dc89-6b1a-5837-b97a-f21e46774c13','2026-02-17 09:48:36',NULL,'Extremo / mediapunta de estatura baja, rápido, explosivo. Tiene habilidad para generar en conducción y en 1v1, pero su toma de decisiones es pobre y no es capaz de generar en último tercio.','NB','Descartar'),
  ('76bb017a-e38d-5c29-b137-c4428e75fca6','2586033e-fd54-570c-97d5-ede8470701d6','2026-02-17 10:37:28',NULL,'Extremo reconvertido a lateral/carrilero derecho de capacidades físicas extraordinarias (supera el 1.80 m, complexión atlética, fuerte y compacto, veloz, con ida y vuelta). 

Destaca especialmente por su empuje, capacidad para ganar metros en conducción y llegar a último tercio. También con recursos en espacios cortos. Técnicamente es irregular, no es pulcro para realizar controles y pases. Centros mejorables. Su zancada es brutal. 

En fase defensa es intenso y agresivo, aún con margen de mejora pero no da mal rendimiento. Poderoso en el juego aéreo, sale de zona para anticipar y afronta duelos con frecuencia.','NB','Firmar'),
  ('373d3ec6-80a8-5ee8-91c9-16ba900ac1e6','28843d0e-b994-578d-8f48-1af87a770e4a','2026-02-17 13:33:42','SEVILLA B - Teruel','Central diestro con un perfil físico medio para la posición. Buen jugador, nada destacable','RP',NULL),
  ('2eb31b10-9490-5747-8d22-2d8f36e3af03','6e969d08-6390-56b0-8dbe-eb47415dbaf4','2026-02-17 13:37:10','SEVILLA B - Teruel','Centrocampista diestro para actuar como mediocentro o en doble pivote. Estatura baja, pero buen nivel técnico, ritmo de juego y de distribución de balón','RP',NULL),
  ('f1f89f27-bed4-58c4-a9ed-8a30991e94a5','c93fece2-a8f8-5ae1-a1fd-f351db87e5ac','2026-02-17 13:39:26','SEVILLA B - Teruel','Centrocampista zurdo de segunda/tercera altura, en el partido actuando como interior con recorrido. Estatura algo superior a 1''70 m, complexión delgada. Jugador ágil y con un nivel técnico para controles, giros, conducciones y pases. Tiene cierta capacidad de eliminar rivales porque es dinámico y tiene un muy buen manejo de balón. En la segunda parte juega un rato de extremo diestro y me ha gustado más: explosivo para eliminar a su marca y conducir o poner el balón en el área. 

Buen jugador, pero me cuesta verle como talento top.','RP','Seguir'),
  ('9dce1cb0-7c32-54f7-937d-b3549de7b6b0','54d068d7-92c5-5ef9-9104-556670b8dea6','2026-02-17 13:45:05','SEVILLA B - Teruel','Delantero centro zurdo con una estatura algo superior a 1''85 m y complexión fuerte. Se mueve bien por todo el frente de ataque para buscar el balón y tiene calidad y criterio para participar. Bien en duelos. De momento no está haciendo cifras.','RP','Seguir'),
  ('e78d8a51-4d36-5bbd-8cb0-8af8411c7cea','011c5824-7520-58c0-866c-2689898a63b3','2026-02-17 13:53:10','SEVILLA B - Teruel','Lateral izquierdo con un perfil físico medio para la posición. Buen jugador, pero nada destacable','RP',NULL),
  ('9bdb6b80-6489-5417-a76a-60773b9751ae','bb1bed7a-8314-5973-b0b2-c4c1ca76b061','2026-02-17 13:54:11','SEVILLA B - Teruel','Atacante diestro, en el partido actuando como extremo, con una estatura alrededor de 1''80 m y complexión fuerte. Sigo sin ver una punta de velocidad diferencial. Tiene un buen perfil y no está rindiendo mal en 1ª RFEF, pero de momento no es un jugador determinante.','RP','Seguir'),
  ('e82f03f9-364e-5435-86db-375c6413eae1','657e7fdb-9b93-5ee4-bbe5-a2ad666eb656','2026-02-17 13:56:43','SEVILLA B - Teruel','Centrocampista zurdo de segunda/tercera altura, para actuar como interior con llegada, mediapunta o incluso segundo punta. Estatura algo superior a 1''75 m, complexión delgada. Nivel técnico muy alto para controles, giros, conducciones y pases, con capacidad para eliminar rivales. Le falta peso en el juego, pero tiene acciones de mucho nivel.','RP','Firmar'),
  ('a58358a4-bad3-5452-9c68-1b85ef99bb8c','c6e3f413-7b7b-57bc-a75f-cac9750248ea','2026-02-17 13:58:11','SEVILLA B - Teruel','Extremo zurdo con un físico muy ligero, aunque rápido, explosivo y con cierta capacidad de desborde.','RP',NULL),
  ('51409f95-e675-56e6-8f3b-6328c6ab2fb6','34ab4c58-b2c0-5fa1-89b5-20cd2cb8af47','2026-02-17 13:59:24','SEVILLA B - Teruel','Atacante diestro, en el partido actuando en banda derecha, con una estatura alrededor de 1''80 m y complexión fuerte. Es potente en carrera y agresivo en los movimientos. Con balón está bien, pero no tiene ningún recurso muy diferencial. Jugador con potencial que tendrá que aprender a potenciar sus cualidades para sacarles rendimiento.','RP','Seguir'),
  ('8e477ce4-6c82-52c1-8fd5-51d564a6fd0c','4927782b-b372-5985-870c-e0265752ebaa','2026-02-17 15:45:39','Daniel Yañez vs Noruega','Jugador con mucho desequilibrio y desbordd aue suele ir hacia delante y que es vertical, ademas de determinante.','AV','Firmar'),
  ('4e439b39-c7dc-52db-aa40-b38b594a04f5','efe326d8-b336-572e-9ffc-d6f344102799','2026-02-17 17:43:37','vs Maracena','Debut en Betis. Delantero de cualidades físicas destacadas.','NB','Seguir')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('c264bb11-5487-57e5-ae1c-b39268e0f8c6','1be8aeaf-dc9c-50f7-b978-a84bb0165011','2026-02-18 13:35:46','AMOREBIETA vs Ejea','Delantero centro diestro con una estatura algo inferior a 1''85 m y complexión normal. Se mueve bien y tiene un juego de espaldas bastante decente. Técnicamente está bien y tiene criterio para mejorar jugadas en campo rival. En el último tercio es agresivo y casi siempre busca una opción que acerque el balón a la portería y cargar área. Le falta mejorar cifras','RP','Seguir'),
  ('bb55102d-0784-57fe-8a34-0e17b77c5351','5fcfa2a5-33ae-5664-bc07-8fb6dd6891fa','2026-02-18 13:44:28','Amorebieta - EJEA','Centrocampista diestro de primera/segunda altura, para actuar como mediocentro, pivote o interior con recorrido. Estatura algo inferior a 1''90 m, complexión delgada pero fuerte. Técnicamente correcto para distribuir y con una buena capacidad para los duelos, especialmente por arriba. Muy intenso. A ras de suelo comete un par de imprudencias en el partido y una de ellas acaba en penalti en contra.','RP','Seguir'),
  ('4a95e57f-cd15-51b3-b10c-1516a3c828f7','c7dd4e84-d7b3-550b-a784-92d84d62ff5e','2026-02-18 13:50:06','Amorebieta - EJEA','Central diestro con una estatura alrededor de 1''85 m y complexión fuerte. Me ha parecido rápido en carrera, especialmente para corregir. Agresivo, le gusta defender hacia delante y tratar de anticipar al delantero. Tiene buenos fundamentos defensivos y un nivel de concentración y de tensión muy elevado, en el partido no comete apenas errores. Ganador en duelos aéreos. Con balón es correcto en cuanto a técnica, y además es atrevido para tratar de filtrar pases cuando la jugada lo permite. 

Es un jugador que por condiciones tengo la impresión de que puede resistir muy bien el paso de las categorías. Me gustaría verlo en directo para confirmar sensaciones.','RP','Decidir'),
  ('69d038a1-fb92-593d-9544-280956b4fb92','af06e69a-152a-534f-8118-fad6d3713b69','2026-02-18 18:59:31','vs Irlanda','#6 de condiciones físicas espectaculares: cercano al 1.85 m, potente, veloz, ágil. 

Zurdo, de poco uso de derecha. Buen nivel técnico, calidad para juego asociativo, vertical para soltarse. 

Es ganador de duelos, fuerte para ir al choque, agresivo en presión. Puede ir hacia atrás y hacia adelante. Juega últimos minutos de central. 

Prototipo de centrocampista top, firmar sí o sí.','NB','Firmar'),
  ('fb2711dd-c527-55c3-b38f-453d42f0225a','156bb2db-85c0-5349-9984-58bf3fee011d','2026-02-18 19:42:38','vs Olot','#6 de estatura baja, tren inferior potente, no lo veo destacando especialmente. No es el tipo de 6 de físico imponente. Es típico catalán.','NB','Descartar'),
  ('1f62371f-be54-5001-82c2-6c7a2969e9c0','2f2423fa-0156-576b-9cd2-e34d5d22dada','2026-02-18 20:44:55','vs Olot','#8 diestro de estatura aprox 1.80. Creo que su físico no termina de ser el ideal, le falta más ritmo.','NB','Descartar'),
  ('95d280f6-e05d-5e2c-9b28-30e67e279a2e','02c89ceb-1b60-5123-bcff-e9603faccf1d','2026-02-19 10:22:22','vs Poblense','Central diestro de buen perfil físico: estatura aprox. 1.85 m, de complexión atlética, es fuerte, veloz, ágil. Utiliza la zurda con naturalidad.

Busca avanzar con balón en conducción y pases interiores. Precisión de pases mejorable, pero tiene la virtud de jugar con fluidez y manejar ambos perfiles. 

En defensa es agresivo y valiente, sale de zona con frecuencia, afronta duelos, busca anticipar. Rápido yendo al cruce y en cobertura de profundidad.

Es perfil de central interesante.','NB','Seguir'),
  ('06f3d21d-dc25-57ac-b251-1ef271331e88','793a7352-ed12-5a0e-ab42-d5c1819b2ef6','2026-02-19 10:35:07','vs Poblense','Mediapunta de físico promedio, poco poderoso. Poco impacto en juego. Sensación de ser jugador de buen nivel técnico pero ritmos bajos.','NB',NULL),
  ('712cacab-3f8b-5ba2-b392-b1382e5332f8','63545f92-65c9-5b61-8908-712a6d0f11af','2026-02-19 10:42:03','vs Valencia B','Delantero centro de estatura media-baja para posición, complexión robusta, físico poco vistoso. No es un jugador poderoso. Poco impacto en juego más allá del gol de rechace.','NB','Descartar'),
  ('31d63fa0-e9ab-5113-970b-1072d8a5c63a','54276fa1-cba3-529a-93f0-46314b16a930','2026-02-19 11:52:07','Alcorcón - NÀSTIC','Central diestro con una estatura alrededor de 1''85 m y complexión más o menos fuerte. Da la impresión de ser lento en carrera y algo pesado de movimientos. Jugador correcto en defensa, que resuelve más o menos bien todas las acciones y que no comete demasiados errores. Con balón es correcto y tiene capacidad para batir líneas de vez en cuando. Buen jugador que puede crecer y terminar jugando en primera división, pero sin características ni potencial top para llegar a la máxima élite.','RP','Seguir'),
  ('9caa256b-7de9-5208-90bc-3da75b620be8','a5fc9a4f-fce5-5d0a-acee-0d35c594936b','2026-02-19 11:56:28','ALCORCÓN - Nàstic','Lateral izquierdo con una estatura algo inferior a 1''80 m y complexión más o menos fuerte. Jugador con recorrido y cierta calidad, con capacidad para participar en el circuito asociativo del equipo y centrar con peligro. No parece top técnica ni físicamente.','RP',NULL),
  ('b5728e2d-cff0-58f5-8d3a-37ffce5ef0ef','cbe69a4d-d5c0-515c-8686-e868405f857c','2026-02-19 11:58:07','Alcorcón - NÀSTIC','Lateral derecho con una estatura algo superior a 1''75 m y complexión normal. Bien técnicamente y atrevido a la hora de sacar la pelota, con recursos para progresar mediante pases verticales y conducciones. En el partido recorta un par de veces para superar a su rival y sale explosivo. Tiene bastante recorrido. En defensa es intenso, pero aún puede mejorar tanto en el 1vs1 como en el duelo. Jugador interesante.','RP','Seguir'),
  ('16d0484b-677c-58cf-bf4c-c08839773dd7','68f30246-db1a-5035-bbc3-7531d92a7ab7','2026-02-19 14:42:44','vs Olot','Mal perfil físico, no lo veo','NB','Descartar'),
  ('c1efac7c-e4fc-5616-aa2d-6be71492190f','5f54ea98-a622-5f57-a31d-2ecd48e174b3','2026-02-19 16:00:21',NULL,'Extremo de características interesantes, perfil Doblas. Creo que tiene cosas, buen físico, con 1v1, vertical. Siendo de último año tampoco lo firmaría.','NB',NULL),
  ('9adcb54b-adb4-55d4-a43c-5b0869284077','db4526f8-a0a4-5847-86ae-49d3bb79e16d','2026-02-19 17:10:28','UD LOGROÑÉS - Zaragoza B','Extremo diestro, en el partido jugando a pierna natural, con una estatura alrededor de 1''75 m y complexión normal. Técnicamente muy bueno y bastante eléctrico para desbordar. Tiene buenas cifras esta temporada. Buen jugador pero es algo mayor y físicamente no es sobresaliente.','RP',NULL),
  ('c3f17eb8-f5e4-5226-91fe-13553ec8b5a2','66edd4ba-c479-59f6-833c-3191e44653b3','2026-02-19 17:14:54','UD LOGROÑÉS - Zaragoza B','Extremo diestro, en el partido actuando a pierna cambiada, con una estatura algo inferior a 1''80 m y complexión normal. Jugador técnicamente sobresaliente, especialmente en cuanto a manejo de balón y recursos para desbordar y buscar área rival. Le gusta recibir al pie, desequilibrar y buscar último pase o disparo, aunque también carga bien el área cuando la jugada va por banda rival. Es rápido, especialmente en movimientos, con mucha electricidad para fintar y arrancar. Sus cifras de producción están bastante bien: 0.63 G+A por 90''.','RP','Firmar'),
  ('abf0db1c-f5d2-5ab3-a695-30216f623297','759cde65-0742-5ce0-a816-b8f1b1891234','2026-02-19 17:18:02','UD LOGROÑÉS - Zaragoza B','Centrocampista diestro de primera/segunda altura, en el partido actuando en doble pivote pero muy adaptable a la posición de mediocentro o interior si se le da vuelo, ya que tiene mucho recorrido y abarca campo. Estatura alrededor de 1''80 m, complexión delgada. Jugador muy intenso en las acciones, tanto ofensivas como defensivas, y de un gran despliegue. Se mueve muy bien para recibir entre líneas, sabe tratar el balón y tiene llegada. Buena técnica para controles, pases y conducciones, siempre con intención de progresar. Buena capacidad de robo también.','RP','Firmar'),
  ('d0d9721d-c666-5723-8034-d167ba3ed45a','fa27ca5e-6bd7-5b3e-92f1-cfe6f04a8b98','2026-02-19 17:21:12','UD Logroñés - ZARAGOZA B','Lateral derecho con una estatura alrededor de 1''85 m y complexión más o menos fuerte. Jugador muy agresivo en la acción defensiva, buscando siempre encimar para cortar jugada o evitar que el rival se dé la vuelta. Ganador en duelos. Con balón tiene una técnica correcta y suele buscar acciones progresivas. No le he visto tanto recorrido, pero su equipo es un desastre.','RP','Seguir'),
  ('7c51d99d-84e4-5e88-a004-7f80c5d31ed1','bcd23ce3-bfab-5467-9288-fb632102c045','2026-02-19 17:23:49','UD Logroñés - ZARAGOZA B','Central zurdo con una estatura alrededor de 1''85 m y complexión fuerte. En el partido me ha parecido lento y está horrible con y sin balón.','RP','Descartar'),
  ('9dc38b1b-3787-5aeb-9bb9-1e9797890731','31491b1d-d6d7-57c8-983f-9a9376a001e4','2026-02-19 17:25:04','UD Logroñés - ZARAGOZA B','Extremo diestro de baja estatura y complexión delgada. Es rápido y tiene cierto desborde, pero es muy ligero.','RP',NULL),
  ('b1f316b2-19c1-5a94-8463-987c09f861c3','7db83ad2-ff8e-59f5-82c8-a44f5a1eebee','2026-02-19 17:26:20','UD Logroñés - ZARAGOZA B','Centrocampista zurdo de primera/segunda altura, en el partido actuando primero como mediocentro y después más escorado a banda. Estatura algo inferior a 1''90 m y complexión delgada pero fuerte. Agresivo en duelos y con cierta capacidad de robo. Bien con balón para dar continuidad a la circulación y ayudar al equipo a progresar.','RP','Seguir'),
  ('2b420668-4699-541b-a49e-8efb719a3d32','30633296-1284-531e-8095-6e6b16ada6cf','2026-02-19 17:29:13','UD Logroñés - ZARAGOZA B','Centrocampista diestro de tercera altura, para actuar como mediapunta o falso extremo, aunque también se podría adaptar a la posición de interior. Estatura alrededor de 1''75 m, complexión delgada. Tiene un nivel técnico altísimo, pero en el partido está bastante mal. Dudas sobre el perfil físico.','RP',NULL),
  ('1724f063-97ce-5d26-b2f4-a8131ca634c7','444ab917-8d4b-5445-8230-8a063ee925d4','2026-02-19 17:30:58','UD Logroñés - ZARAGOZA B','Delantero centro diestro con una estatura alrededor de 1''75 m y complexión delgada. Jugador muy móvil que debería jugar en banda o acompañando a otro delantero. Buen nivel técnico y bastante dinamismo, pero genera poco.','RP','Seguir'),
  ('81a4b25d-e072-57f5-a5a8-5a2143d9670d','cac8f5a4-78b8-5fd9-a963-b34b039fce46','2026-02-19 17:32:20','UD Logroñés - ZARAGOZA B','Centrocampista zurdo de primera/segunda altura, para actuar en doble pivote o como interior. Estatura algo inferior a 1''80 m, complexión más o menos fuerte. Jugador intenso en duelos y con una buena capacidad técnica para distribuir. Su rendimiento en el filial no está siendo excelente, pero el equipo no acompaña.','RP','Seguir'),
  ('79a2d24d-ea72-5ec2-ab3a-6b0712f3015f','9a83f5d5-d688-51c5-9fdd-7c5dd8a3809d','2026-02-19 17:34:16','UD Logroñés - ZARAGOZA B','Delantero centro diestro con una estatura algo inferior a 1''80 m y complexión normal. Es más perfil mediapunta o segundo punta. Viene bastante a recibir y trata de dar continuidad al juego de espaldas, pero tiene poco peso.','RP',NULL),
  ('63d8373e-f863-55a5-ac07-007aa69b8486','75e90f23-f4d4-5eef-8381-4208595e7606','2026-02-19 17:35:32','UD Logroñés - ZARAGOZA B','Interior con un perfil físico bastante pobre. En el partido no deja demasiado.','RP',NULL),
  ('18bdb96f-e591-51d7-a1f1-7449caac883c','742d116a-2c3d-5666-b587-cbc08744aee6','2026-02-19 17:36:29','UD Logroñés - ZARAGOZA B','Central diestro con un perfil físico medio para la posición. Poco que evaluar en el partido.','RP',NULL),
  ('ce49b2f5-8e30-5a48-98d5-e454c3ccd4f8','c7dd4e84-d7b3-550b-a784-92d84d62ff5e','2026-02-20 11:19:42',NULL,'Prince Amponsah es un defensa central de estatura cercana al 1.85 m (diría que no lo supera), de complexión robusta, buen punto de agilidad y velocidad para la posición. 

Diestro, con poco uso de zurda. Con balón destaca por su buen pase largo y capacidad para meter pases por dentro. No tanto en conducciones. Tiene buenas intenciones, técnica mejorable. Pie aceptable, sin ser élite. 

En fase defensiva es agresivo, expeditivo para salir de zona, se impone en los uno contra uno. Algunos problemas de timing y de cadera en ciertas situaciones. 

Me parece un central que está bien, pero que no es excelente en nada. Lo veo para dar salto de categoría pero necesito verle más cosas para firmar.','NB','Seguir'),
  ('f8c9ccaf-b9f4-50d4-8b79-e56a7fa7f7c6','3a2b4fa7-685d-5d76-b73d-baa16718f4ab','2026-02-20 15:04:00',NULL,'Mediocentro de estatura media-baja, complexión fuerte, rápido y ágil. Con buen nivel técnico para superar presión, vertical en juego asociativo, le gusta progresar en conducción y acercarse a área rival. Es intenso en presión, rendimiento mejorable en duelos. 

Me sorprende que haya sido tan irregular porque es buen futbolista, le vi cosas interesantes. Seguirlo.','NB','Seguir'),
  ('1547848d-b346-58c5-b540-5557088d6262','24c4c209-23ba-575f-81b3-4b766b1182cc','2026-02-20 22:26:53','vs Villarreal B','De lateral derecho puede evolucionar por características. Bastante peor que Masqué y Navarro de todas formas ahí. No creo que sea su posición, sobre todo en defensa.','NB',NULL),
  ('14ec9c6f-a7d6-59b9-a96c-1e908e4aba90','dc503b30-fe10-54fe-852c-8d76dd467bc9','2026-02-20 22:28:53',NULL,'Es mediocentro que puede jugar en Segunda próxima temporada (o primera extranjera). Buen jugador, de tipología interesante, recorrido y con ciertos recursos con balón. Bastante lejos del nivel élite de Diatta.','NB','Seguir'),
  ('e7c26960-abea-519f-af6c-4d49d05656a6','4b6242c8-3e41-5c17-a6de-973c21563012','2026-02-20 22:30:54','vs Betis B','No lo veo con suficiente poderío físico como para marcar diferencias más arriba. Tiene regate, es vertical, busca encarar. Pero por físico no lo veo.','NB',NULL),
  ('d409e685-d8fe-535d-a16c-7058d22bb8bc','da445527-beea-5ce6-acee-fd59a4397337','2026-02-20 22:34:54','vs Betis B','Por condiciones físicas, nivel técnico y sobre todo perfil es jugador a firmar. Ya sea como mediocentro (creo que es su posición) o jugando en banda. 

Ahora, me parece que Moussa por ejemplo tiene mayor potencial.','NB','Firmar'),
  ('cf394bb8-ab36-53d1-b865-6de47d450696','47642bb4-5af7-5bc2-aa9c-5c963e7063c9','2026-02-21 00:21:34','Vs Portugal 1','Es el mejor del partido, pero esta muy hecho, ya muy crecido y con todo el tren inferior ensanchado, es espectacular en espacios reuducidos y acciones em campo rival.','AV','Descartar'),
  ('c1d67ec1-98a5-56a1-84d6-6243a79f2d77','dca03474-e29a-53c1-a449-1a8c1d0d0ef1','2026-02-21 00:24:50','Vs portugal u15','Jugador muy serio y muy cumplidor rapido y ganador de duelos, tiene gran velocidad de desplazamiento y mucho control de los timings, gran capacidad para mejorar y aprender','AV','Seguir'),
  ('29f51b35-513a-569f-a101-c819d234324e','107d7317-e77f-5c82-91c1-80a51fb1c2f2','2026-02-21 00:27:31','Vs portugal u15','Central espectacular, gran plants fuerte y con mucho nivel en duelos y velocidad gestual.','AV','Firmar'),
  ('6ba888f0-68dd-5e5b-aa17-a8a2cfd94696','740463c4-cc32-594a-a6f0-5771ff724a72','2026-02-21 00:28:28','Vs Portugal U15','Bruno es un mediocentro completisimo, que esta en todos lados, llega a todo y gestualmente es rapido y tiene nivel tecnico','AV','Firmar'),
  ('2371d441-0549-52a7-8638-62ef7676d663','c2263afc-5411-560a-87cd-159e982e0d47','2026-02-21 00:29:29','Vs Portugal U15','Jugador sobrevalorado, el esta bien y tiene nivel, va hacia delante y es el extremo que buscamos en nuestro perfil. Pero esta para mi sobrevalorado por el mundo del futbol','AV','Firmar'),
  ('b8e1252a-68c5-55cd-b2c5-c4a89e8375ac','bfc9ac49-1dd7-5749-ba5e-99951ecd2147','2026-02-21 00:31:10','Vs Portugal U15','La sub 15 y el futbol, esta plagada de jugadores sobrevalorados','AV','Descartar'),
  ('ed0cd21f-f277-53c1-92ff-296f94069947','cccea9cb-d4f0-5501-9eef-bb40e5beb24b','2026-02-21 00:33:15','Vs portugal u15','Jugadorazo, perfecto en lo que buscamos, con capacidad para crecer y estar a buen nivel, con mucha proyeccion a futuro, debe mejorar en la velocidad gestual','AV','Firmar'),
  ('65df3a46-c222-541a-9075-0e923733dbcc','e37f069f-26ae-5186-8e65-8d31cb23bb05','2026-02-21 00:34:40','Vs Portugal u15','Es el mejor','AV','Firmar'),
  ('ea59aea5-c902-5e4f-9e06-00e7e10771db','d6ab76eb-94d5-507a-b5ef-a7cb3de31a55','2026-02-21 00:36:21','Vs Portugal U15 + Cesa /Sub 16','Jugador muy simple, que nunca se complica y siempre scierta. Dificultades para ser vertical y regatear, en espacios reducidos va muy sobrado. Tiene que mejorar en medias distancias y a nivel fisico','AV','Seguir'),
  ('c57a05a5-0189-5698-9096-769281282ea7','ee127d9a-a664-5ab4-b352-4440e4a7494d','2026-02-21 00:37:56','Vs Portugal U15','Jugador muy bueno pero que en el centro del campo debe jugar mas adelantado sin suficiente ritmo de juego para ser determinante','AV','Descartar'),
  ('04ed54cc-ba3a-5b67-a159-6c74eaad8e2b','cd5c248a-fba1-5b53-b508-f6236f70b4f1','2026-02-21 00:40:23','Vs Portugal U15','Jugador rapido y con nivel para desbordar bueno en espacios reducidos mejorar en remate pero en lo ofensivo es determinante','AV','Firmar'),
  ('e9b6f311-6a91-5f85-89cd-8174ca919339','6190d33a-27c4-58d3-8292-3e000114117f','2026-02-21 00:41:32','Vs Portugal U15','Hoy ha estado arrugado, pero es muy muy bueno','AV','Firmar'),
  ('51c63653-a297-57c4-b2d4-2172fe4deefe','8c04f16f-0cf8-5346-8e3c-2464197d760e','2026-02-21 00:42:14','Vs Portugal u15','Acabara jugando como lateral, no tiene desborde.','AV','Descartar'),
  ('7efc1ef4-7b26-5fed-ad93-dd96e64180c5','034277cd-6845-5618-a80a-6764f1f6f016','2026-02-21 00:44:16','Vs Portugal u15','Jugador con buen pie, fisicamente no necesita mucho mas, pero es rapido, si. Ser un portento es rapido. Con el balon muy bien se ha ddesenvuelto bien. Y sin balon muy intenso y correoso','AV','Seguir'),
  ('1867fe3c-3d89-5ff9-9328-bd8749e8cbf5','df13ea0c-6c79-5850-bb6b-66f729dd0b8e','2026-02-21 12:06:27','vs Castellón','Perfil físico integrante a primera vista pero nada.','NB','Descartar'),
  ('d9b62127-e535-5cfa-b649-b46eeae098d5','f743e2f9-231b-512e-931d-d04173b41109','2026-02-21 14:14:31','vs Ferrol','Dudas serias a nivel físico para transferencia a primer equipo. Tendrá sus oportunidades porque es apuesta de club pero lo veo endeble, y no puede jugar como extremo. Debe ser 10. Rol muy específico. No me termina de convencer.','NB',NULL),
  ('4bb43e19-8da8-5ed3-ae2a-5894c258da71','11abe195-d641-5a37-95e7-64a57debad8f','2026-02-21 14:18:13','vs Ferrol','Juega por dentro. Jugador de estatura media-baja, fuerte, rápido, explosivo. No tiene demasiado impacto en partido pero sí que deja acciones de nivel, sobre todo por ritmo. Es jugador en el que apostaría.','NB','Firmar'),
  ('4c0d1900-a7c7-5c9d-8507-ed96317af117','98f8a33f-ad30-552f-a337-8757c9646cfd','2026-02-22 02:57:29','vs Utiel','Central zurdo de condiciones físicas ideales para posición, de potencial alto por características y margen de mejora.','NB','Firmar'),
  ('4ec8ad9c-2390-5508-bb72-fcb9f97f4279','ecf817f1-9ce3-5ef0-8a29-4ef503421b56','2026-02-22 02:59:51','vs Utiel','Me parece perfil parecido a Kareem en condiciones, aunque siendo más bajo. Es un jugador que puede explotar si crece en último tercio ya que es muy rápido y genera peligro individual y yendo al espacio.','NB','Firmar'),
  ('373397c6-a862-5b84-8cac-6236e08a7ad0','fe26fc32-7830-56d4-8413-5f741d4ce9c6','2026-02-22 15:57:51','CASTELLÓN JUV. A - Valencia Juv. A','Central izquierdo en línea de tres que despuésha jugado como carrilero, pero perfil claro de lateral. Estatura algo superior a 1''75 m, complexión delgada. Jugador muy agresivo para chocar y muy inteligente defensivamente, con un buen timing y calidad para la acción defensiva. Con balón es bueno técnicamente y tiene recorrido. Suele encontrar buenas soluciones para hacer progresar al equipo.','RP','Seguir'),
  ('fdeefc47-a68c-5bf4-977e-03b343780585','83d173c8-72d4-5ad5-8289-11851d5260a1','2026-02-22 15:59:16','Castellón Juv. A - VALENCIA JUV. A','Extremo diestro con una estatura alrededor de 1''85 m y complexión fuerte. No me ha parecido rápido ni muestra demasiada calidad para el 1vs1. Sí es muy agresivo en la toma de decisión a la hora de verticalizar y finalizar jugadas.','RP',NULL),
  ('5319fe63-5487-5c0e-8408-1b4cae73a298','f4a1efb6-8451-57d5-9a20-160cb83e50de','2026-02-22 15:59:45','Castellón Juv. A - VALENCIA JUV. A','Delantero centro con una estatura algo superior a 1''75 m y complexión normal. Rápido en carrera. Buen nivel técnico y mucha inteligencia para moverse y participar. Muestra un gran instinto en último tercio y marca dos goles tras dos buenas definiciones, una con el pie izquierdo y otra con la cabeza.','RP','Seguir'),
  ('c78a6645-6f3d-5d19-87ea-49287c35bc5e','7e30c9ff-719b-562c-bc31-15e3bec5924d','2026-02-22 16:00:31','Castellón Juv. A - VALENCIA JUV. A','Centrocampista diestro de segunda/tercera altura, en el partido actuando como interior con llegada. Estatura alrededor de 1''90 m, complexión fuerte. Tiene una zancada muy interesante. Técnicamente muy bueno y agresivo en la toma de decisión. Verticaliza con facilidad, tiene buen rango de pase y llegada a área.','RP','Firmar'),
  ('96c371fc-a8a9-58ea-8fef-9bbd9b065ddc','5056e523-027d-5bff-b15d-a0a9f3fffca1','2026-02-22 16:01:27','Castellón Juv. A - VALENCIA JUV. A','Extremo diestro, en el partido actuando en bamda izquierda. Estatura alrededor de 1''75 m, complexión fuerte. Potente en carrera. En el partido muestra agresividad con balón verticalizando en un par de ocasiones. Antes le había visto como delantero y no me había gustado, pero como extremo es interesante.','RP','Seguir'),
  ('83ff7b23-8d56-5bd7-8bbb-346a258f93a4','4ab062c6-aaca-59a1-be76-7f6811373b37','2026-02-22 18:01:05','OVIEDO B - Deportivo B','Central diestro con una estatura alrededor de 1''85 m y complexión más o menos fuerte. Defesivamente es agresivo y contundente, dominante en juego aéreo y en la defensa del área. Con balón es justo y no parece muy rápido.','RP','Seguir'),
  ('a4561245-aca1-565b-bb60-65cbabe1224f','5e0f8326-6c73-5b49-b1f1-0fe8855d0235','2026-02-22 18:55:35','Oviedo B - DEPORTIVO B','Centrocampista diestro, primero actuando cerca de la base y después como interior con llegada. Estatura algo inferior a 1''85 m, complexión normal. Tiene calidad con balón y criterio para pasar y a la hora de conducir para escapar de presiones.','RP','Seguir'),
  ('b439ab93-3600-5bda-9c6b-d086b688d016','64954140-0262-5391-bbc8-3bcda129c639','2026-02-22 19:00:24','OVIEDO B - Deportivo B','Lateral izquierdo con una estatura algo superior a 1''80 m y complexión fuerte. Técnicamente bien y con una buena velocidad, especialmente la arrancada. Participa bastante a todas las alturas y tiene una buena capacidad para escapar del primer rival y resolver la acción ganando metros en conducción, pase o centro.','RP','Seguir'),
  ('4094effc-5555-52d6-9c8f-3f612a1f83ef','aeb8cbbd-3d9c-5a3f-ace7-0cc1a7163b2a','2026-02-22 19:27:42','Castellón Juv. A - VALENCIA JUV. A','Central diestro con una estatura algo superior a 1''85 m y complexión fuerte. Agresivo y muy contundente en la accion defensiva. Siempre busca chocar al delantero y suele imponerse en el duelo, especialmente por arriba. No es especialmente rápido. Con balón es correcto.','RP','Seguir'),
  ('29dfead6-76d9-506b-b460-cfc3d12c2e57','e61b292f-aab5-58e4-8fbf-8c5f6188f2be','2026-02-22 19:46:37','vs Salerm','Mala impresión en persona. Físico poco estético, menos de 1.80 m, robusto. No tiene talla para ser delantero centro. No tiene recursos para jugar en banda. No lo veo.','NB','Descartar'),
  ('3826e9b1-8147-5d51-99ad-9d9da5461411','4ffb9187-c303-5ba5-bce6-87c54fc3c23c','2026-02-23 10:32:24','VALENCIA JUV. B - Torrelevante Juv. A','Lateral izquierdo con una estatura alrededor de 1''80 m y complexión delgada. Buen nivel defensivo, especialmente en duelos aéreos, aunque también se ha mostrado seguro en el 1vs1 y al corte. Con balón es bueno técnicamente y, aunque no aporta nada muy diferencial, sí puede participar con acierto en la circulación de balón y dejar alguna acción de calidad en campo rival.','RP','Seguir'),
  ('c21808b5-9e9e-5780-8ae3-7e09dea15219','3b5dc9c5-9c92-5083-80f8-0289e6a01243','2026-02-23 10:34:40','VALENCIA JUV. B - Torrelevante Juv. A','Central diestro con una estatura alrededor de 1''85 m y complexión delgada. Piernas largas, y con buena zancada, aunque no me ha parecido rápido. En el partido marca un gol y está bastante serio defensivamente. Con balón es justo. Perfil interesante, aunque lo he visto muy por hacer.','RP',NULL),
  ('49d48682-5732-57c5-ba72-900229a83f94','8d3d19d4-dc41-5f0c-a532-53afc9531f2f','2026-02-23 10:41:09','VALENCIA JUV. B - Torrelevante Juv. A','Centrocampista diestro de primera altura, en el partido actuando como mediocentro. Estatura algo superior a 1''75 m y complexión fuerte, no sé si con un físico demasiado hecho. Jugador muy agresivo en duelos y con una gran capacidad de robo. Con balón tiene buena técnica para distribuir e incluso para conducir y escapar de presiones, pero en muchas ocasiones en el partido ha estado precipitado.','RP','Seguir'),
  ('b5a15bc5-5857-50bb-b054-0ba6ac67ed9a','cc890730-3ab7-5c10-95f7-91e5f4e3bb86','2026-02-23 10:54:11','VALENCIA JUV. B - Torrelevante Juv. A','Centrocampista se segunda altura, en el partido actuando como interior con llegada. Me ha gustado el perfil físico, pero futbolísticamente no he podido evaluar mucho.','RP',NULL),
  ('66467d83-73a4-5fc4-a5da-e6b48046258f','81f295a5-a42f-5527-a5a3-ea92275a3faf','2026-02-23 11:04:08','Valencia Juv. B - TORRE LEVANTE JUV. A','Extremo diestro, en el partido actuando a pierna cambiada, con una estatura algo inferior a 1''80 m y complexión delgada. Tiene una arrancada explosiva y es muy agresivo con balón. Técnicamente tiene recursos para desbordar, sobre todo en carrera.','RP','Seguir'),
  ('e90526fc-058d-595e-96f3-d7063ce351a6','39fb0657-a285-53f3-a01b-44dce9db3f27','2026-02-23 11:07:39','Valencia Juv. B - TORRE LEVANTE JUV. A','Jugador diestro de banda, en el partido actuando como carrilero izquierdo, aunque me gustaría verlo como extremo. Estatura alrededor de 1''75 m, complexión delgada. Muy agresivo en el duelo y también con balón, con intención de verticalizar en todas las acciones. Rápido y con una buena conducción, en el partido tiene alguna buena jugada esquivando un par de rivales por banda.','RP','Seguir'),
  ('d5b2b1ea-7fb1-5584-8ebf-ab28826db891','95f92406-ac3b-59ea-9ed3-4c172f4a0f77','2026-02-24 12:28:19','Vs levante','Jugador con una demostracion de fuerza y potencia innatas muy altas, que ademas es vertical en sus acciones y es capaz de regatear con mucha facilidad. 

Le veo como un jugador muy prometedor en los proximos años dentro de su estructura y comparandolo con los jugadores de su edad lo veo adquiriendo una gran relevancia. En vivo gana mucho','AV','Firmar'),
  ('255a82e6-bcc6-5dba-ac21-3028a1cbf975','95f92406-ac3b-59ea-9ed3-4c172f4a0f77','2026-02-24 13:10:13','Vs fundacion','Jugador que mas me ha impresionado este año en espacios reducidos, muy capaz de resolver situaciones bajo presion y salir de forma vertical bajo presion de 3 o 2 oponentes, y con capacidad para ser determinante','AV','Firmar'),
  ('de8186e2-0758-557a-abcc-bbb0b0dab60b','7d95c3b7-f358-5d29-a7a3-28b73b305d38','2026-02-25 12:40:54','vs Terrassa','Central diestro de estatura aprox. 1.85 m, delgado, espigado, ágil, con recorrido, velocidad ok. De buenas condiciones físicas en general. 

Con balón es agresivo para jugar hacia adelante, romper líneas con pases, se siente cómodo incorporándose a campo rival. No me parece fino técnicamente pero genera por verticalidad. 

Es valiente para defender, afrontar duelos e ir al choque. Bien en defensa de profundidad. Es un defensa central interesante. 

Verlo en directo y valorar si nos interesa.','NB','Seguir'),
  ('23165834-c243-515d-9364-ab988c6b1188','c058cc00-b874-53d4-a2c0-2a7e250d78af','2026-02-25 20:07:32','UYL','Jose Gaitán: Extremo diestro por izquierda. Estatura media-baja, complexión fuerte, de tren inferior potente. Capaz de resistir choques. Es rápido y explosivo en primeros metros. Con aceleración y recorrido hacia atrás. 

Jugador vertical, que busca situaciones de uno contra uno con frecuencia. Ataca bien los espacios. Tiene recursos en el regate. Es extremo que genera, tiene buen golpeo y pisa área. En mi opinión es diferencial y tiene condiciones interesantes para la élite.','NB','Firmar'),
  ('2fc81157-1b1b-5f56-adc9-fd6fc3d8a02b','d66722d4-dcaf-536b-865f-2212df6f39fc','2026-02-25 20:09:53','UYL','Hugo López juega como delantero/segundo punta. Jugador de gran nivel técnico, juego entre líneas, explota espacios. Tiene ritmo y es vertical. Gran golpeo de balón y recursos para crear ocasiones. Mejor finalizador que pasador. Cierto que lo limita para la élite que sea un jugador tan concreto en cuanto a rol, pero lo veo evolucionando.','NB','Seguir'),
  ('0e6fb840-4c2c-52fa-a3c5-9638123de0cb','2d609880-ce02-55bb-a68a-a021d5a778ca','2026-02-25 20:11:54','UYL','Delantero centro de buen nivel, de estatura aprox 1.85? y complexión delgada aunque fuerte. Es dinámico y participa fuera del área. Creo que le falta algo más de velocidad para atacar espacios. En el área bien. No me parece un talento top pero sí un delantero con posibilidades de crecer.','NB','Seguir'),
  ('839399e2-7bbd-5c16-ad8f-b5b9396e58aa','3a2b4fa7-685d-5d76-b73d-baa16718f4ab','2026-02-25 23:44:20','vs Sant Andreu','Teo Michél es un centrocampista perfil #8 de estatura media, complexión delgada, fuerte, destaca especialmente por su agilidad y velocidad. Es jugador de MUCHO ritmo, vertical y agresivo en sus acciones. 

Capaz de progresar en conducción, tiene buena técnica para superar presión en espacios reducidos. Le gusta soltarse y pisar último tercio. 

En fase defensiva es jugador agresivo, que no rehuye duelos, y se impone bastante. Sobre todo destaco que abarca mucho campo. 

En mi opinión es jugador de categoría superior. Por perfil creo que puede evolucionar considerablemente.','NB','Firmar'),
  ('94b78934-724b-50fc-b020-2f99d068d8e4','da37327b-d719-5e44-9349-177ca884a0f9','2026-02-26 00:07:34','vs Sámano','Lateral derecho de estatura media, complexión fuerte, rápido, explosivo en primeros metros, con ida y vuelta. 

Bien en conceptos defensivos, sólido en uno contra uno en contra, cuerpeando, anticipando, en presión en campo rival. En general aplicado defensivamente e imponiéndose.

Con balón técnica aceptable, sin ser destacado. Es vertical para asociarse, juega hacia adelante, es capaz de asociarse y aparecer por dentro. No parece tener grandes recursos en el uno contra uno. Mala ejecución de centros.

Verlo más.','NB','Seguir'),
  ('7f6e3d77-5339-58b9-b62b-eb3b3a9c3d1a','78351cbb-81b8-57a5-94bd-db56fe56e735','2026-02-26 00:26:00',NULL,'Mediocentro de perfil físico medio en cuanto a estatura, fortaleza...parece con bastante ritmo. Es jugador vertical, juega hacia adelante, gira bien, progresa en conducción, tiene buen nivel técnico, supera rivales en corto. Con buena recuperación, sin ser imponente en duelos. Es un jugador de buen nivel, que seguramente salte de categoría, pero al que me cuesta ver como élite.','NB',NULL),
  ('45116871-abdb-57d9-870a-6ab75aa66f80','7d95c3b7-f358-5d29-a7a3-28b73b305d38','2026-02-26 10:12:49','CASTELLÓN B - Barcelona B','Central diestro con una estatura algo inferior a 1''90 m y complexión delgada pero atlética. Buena velocidad. Partido prácticamente perfecto con y sin balón, sobre todo en la primera parte. Lectura, timing y calidad defensiva top, además de ser intenso en las acciones y agresivo para anticipar. Técnicamente muy bien. Con balón no ha cometido ningún error, ha ayudado al equipo a progresar e incluso ha tenido alguna conducción hasta campo rival. Cuando el Castellón ha atacado en posicional en campo contrario, ha participado bien en el último tercio. Muy buen jugador y gran perfil, la única duda es la edad.','RP','Decidir'),
  ('ee79d756-b998-561c-95cc-05d077d393e1','385bd0c6-e2db-5f3e-a000-8d5ba4d12bec','2026-02-26 10:17:26','CASTELLÓN B - Barcelona B','Jugador zurdo de banda, en el partido actuando como carrilero derecho pero con perfil de extremo. Estatura algo superior a 1''80 m y complexión más o menos fuerte, aunque ágil. Bien en duelos. Agresivo en los movimientos, va al espacio y tiene calidad para el 1vs1 y el centro.','RP','Seguir'),
  ('7469cfff-356b-5ff4-96ea-1451556751c8','a282ce53-7abc-5f23-843d-8ea463a42c29','2026-02-26 10:19:12','Castellón B - BARCELONA B','Lateral izquierdo de estatura baja y complexión fuerte. Rápido. Partido bastante malo, con errores defensivos constantes.','RP',NULL),
  ('e3fb8aba-71fe-5480-a6af-3b8060749aef','e8c1d7a8-c74f-54c6-8375-23b3b430fac0','2026-02-26 10:20:32','Castellón B - BARCELONA B','Central zurdo con una estatura alrededor de 1''90 m y complexión fuerte. Visualmente pesado, no parece muy rápido. En el partido muestra un nivel correcto en defensa y con balón.','RP',NULL),
  ('2f39559f-a686-5c98-a3bb-86cd0ec5b67e','6ca7a462-18c5-5a5c-8405-5822a9d14e46','2026-02-26 10:21:56',NULL,'Central diestro con una estatura algo superior a 1''85 m y complexión normal. En el partido marca un gol en propia portería, pero en general está muy sólido y con balón muestra cosas.','RP','Firmar'),
  ('68914f97-76a8-517f-9044-012fb3908a01','f0aee2cc-d724-57a9-9b72-8a367bc13a03','2026-02-26 10:25:10','Castellón B - BARCELONA B','Lateral derecho de estatura medio-baja, complexión normal. Perfil centrocampista de manejo de balón. Técnicamente sobresaliente, con un dominio del balón muy alto y con recursos para escapar de presión a través de fintas y cambios de ritmo. Suele mejorar jugadas a través del pase. Agresivo en duelos.','RP','Firmar'),
  ('1bfeb8fc-92ef-576c-af4c-a4fc91e7211d','2749c568-716b-5c6c-abc7-080d03fcda24','2026-02-26 10:27:50','Castellón B - BARCELONA B','Centrocampista diestro de primera altura, en el partido actuando como mediocentro. Estatura alta, complexión normal. Nivel técnico alto para la distribución y buem ritmo de juego. Bien en duelos, sin destacar.','RP','Firmar'),
  ('209caf4f-9829-50ee-a088-e5860346c325','c2e49b61-aef3-57a8-a899-007eeeb90577','2026-02-26 10:31:18','Castellón B - BARCELONA B','Centrocampista zurdo de segunda altura, en el partido actuando como interior. Estatura media, complexión normal. Nivel técnico muy elevado y gran manejo de balón para quedársela, escapar de presión y distribuir.','RP','Seguir'),
  ('9d055e37-3e1a-535b-b387-a2c03c7915f4','8b2af5eb-f3d2-5594-973d-4e08ac8efc08','2026-02-26 10:34:02','Castellón B - BARCELONA B','Centrocampista zurdo de segunda/tercera altura, perfil mediapunta, en el partido actuando como interior. Estatura media, complexión ligera. Nivel técnico muy alto. Jugador dinámico y ágil con capacidad para romper líneas a través de la conducción y el pase. Peligroso en ultimo tercio.','RP','Firmar'),
  ('db75da10-7b60-5e1b-bd8f-c5a67d0c9d2f','31c26b78-9265-5cd1-b7bb-a2de31d5e63b','2026-02-26 10:49:31','Castellón B - BARCELONA B','Extremo diestro, en el partido actuando a pierna cambiada, con una estatura baja y complexión normal. Nivel técnico elevado y buen cambio de ritmo. En el partido no deja mucho.','RP','Seguir'),
  ('a5ad5ac0-8108-549c-ab99-df73adaf769a','f242b686-83be-55c5-bbc7-9098daaabe6d','2026-02-26 10:49:59','Castellón B - BARCELONA B','Extremo diestro jugando en derecha. Estatura media, complexión normal. Bien técnicamente y con cambio de ritmo. Tiene recursos para el 1vs1 y en el partido provoca varias faltas.','RP','Seguir'),
  ('3c438ee2-c4fa-54c6-a29d-86d82714a6d7','45650f08-5d69-5549-a10e-0ffa6a13a30a','2026-02-26 10:50:37','Castellón B - BARCELONA B','Extremo diestro, en el partido actuando en banda izquierda. Estatura baja, rápido y potente en carrera, tanto con balón como al espacio. Nivel técnico muy alto y buen cambio de ritmo para desbordar. Agresivo en el último tercio. Es mayor, pero ha jugado bastantes partidos en Segunda y tiene buenas cifras en 2ª RFEF esta temporada.','RP','Seguir'),
  ('7fe29b50-8501-50cd-b0dc-41e151c94d01','611b6f74-3322-5cfe-bfc7-2495b7083cb8','2026-02-26 10:51:55','Castellón B - BARCELONAB','Centrocampista diestro de segunda/tercera altura, en el partido actuando como interior. Buen manejo de balón para controles, giros y pases. Bien escapando de marca y acelerando jugadas.','RP','Firmar'),
  ('c22552ce-abc6-5c15-9995-cf072b60a613','6978206f-1ef8-5d2d-9535-56b1d4c18bb6','2026-02-26 10:52:39','Castellón  B - BARCELONA B','Centrocampista diestro de primera altura, en el partido actuando como mediocentro. Estatura media, con potencial para superar 1''80 m, complexión normal. Buen manejo de balón y bastante calidad en distribución.','RP','Seguir'),
  ('cca90ce9-41ac-58d1-a71e-21074c444228','05af3b9b-95ef-5a30-b7e7-a90d4228e817','2026-02-26 10:54:45','Castellón B - BARCELONA B','Extremo zurdo, en el partido actuando a pierna cambiada. Estatura algo superior a 1''75 m, complexión normal, pero con un gran potencial por ser 2010. Pocas acciones que evaluar, pero ha chocado bien un par de veces y ha ido alguna vez al espacio.','RP','Firmar'),
  ('1571912e-8a3a-5af7-b216-247662cd97c3','08c6a535-f492-529b-868a-7f2e9349a922','2026-02-26 12:45:09','vs Córdoba','Central izquierdo de apariencia física excelente: estatura aprox. 1.90 m, piernas largas, aún con musculatura por ganar. De velocidad normal, sin destacar. Me preocupan sus primeros metros hacia atrás.

Es un central con un potencial enorme, le destaco su voluntad (y cierta capacidad) para filtrar pases y jugar hacia adelante. Sin tener gran técnica tampoco. 

En fase defensiva es jugador proactivo, que busca anticipar y salir de zona. Le falta punto de contundencia y solidez en duelos.

Me recuerda a Noah Obioma en etapa juvenil. Quiero que tengan en cuenta que es un central que no firmaría hoy por RENDIMIENTO, pero sí me parece un jugador al que apostar por POTENCIAL.','NB','Firmar'),
  ('26738219-42ac-5c35-90b0-540ddf933885','046638b7-c5d9-5071-b67f-91870b5ee487','2026-02-26 12:52:18','vs Córdoba','Lateral izquierdo de físico poderoso, vertical, con recorrido, es rápido. Bien en acciones defensivas, juega hacia adelante. Se le ve poco, buen perfil para seguir. Pocos minutos para valorar.','NB','Seguir'),
  ('d409ce66-3997-52d8-a91f-3b77625d7c0d','c41e5f7b-3c53-5cdb-9f3c-da2aa1d1126e','2026-02-26 13:57:08','vs Córdoba B','Delantero centro de estatura aprox. 1,85 m, complexión física espectacular. Muy fuerte y potente, compensado en tren superior e inferior. Es rápido, con aceleración en primeros metros. 

Me parece un delantero con unas condiciones espectaculares, determinante yendo al espacio, con capacidad para producir por sí solo, bien en el área. Activo en defensa.','NB','Firmar'),
  ('5c511ceb-6289-5d9d-9300-2d5497aa809e','70e5f80d-c6fa-5cd6-9d47-3b06d2140634','2026-02-26 13:58:56','vs Córdoba','Delantero centro grande, pero lo veo algo tosco y lento','NB',NULL),
  ('7075a14d-fcbb-53a7-ba3c-55f52c9d4eaf','d9622b1f-9958-5427-b978-0ed91faaeda4','2026-02-26 14:00:52','vs Córdoba B','No le veo nada especial. Pocos minutos. Físico ok, delgado, tampoco me parece excelente.','NB',NULL),
  ('55e88b6b-b145-5b85-8406-0c6e0de0069e','92413171-dce1-5ef4-96c3-af04b1a78973','2026-02-26 15:26:21','vs CD Tenerife Juv A','Opinión similar a partidos anteriores. Creo que le falta un punto de velocidad/explosividad para atacar espacios e irse en carrera. No hay dudas sobre nivel técnico y recursos en regate, pero le falta ese punto para verlo como top.','NB','Seguir'),
  ('7514a9b5-4087-53fd-aae2-a3eaa27c4500','5a991caf-8ce5-5a87-ba49-48f02eb90218','2026-02-26 16:45:11','vs Olot','Juega de central diestro. Condiciones físico-técnicas top, potencial muy alto. Le falta aún hacerse a posición, de hecho me gusta más de 6. Pero tiene condiciones muy buenas.','NB','Firmar'),
  ('4b8ba19c-f282-543b-af78-c37b229d43de','47642bb4-5af7-5bc2-aa9c-5c963e7063c9','2026-02-26 21:48:32','vs Portugal 2','El mejor jugador sobre el campo, y el mas vertical y determinante, pero esta muy hecho.','AV','Descartar')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('35ec7dc2-c376-523a-990e-ae60aad87ae7','dca03474-e29a-53c1-a449-1a8c1d0d0ef1','2026-02-26 21:49:31','vs Portugal 2','Jugador con un estilo de juego muy agresivo, con todas las condiciones técnicas para mi para ser un central en 1º nivel, sobretodo a nivel defensivo,  con balón, se viene demasiado arriba y comete errores de valiente, lo cual no es malo, lo unico que genera dudas es su fisico porque con esa altura no podrá ser central.','AV','Seguir'),
  ('67668f1d-1775-574e-a559-301d1c9fd952','107d7317-e77f-5c82-91c1-80a51fb1c2f2','2026-02-26 21:51:15','vs Portugal 2','Central de jerarquia y mucha contundencia, con balón tiene claras sus limitaciones es rápido y va bien al corte, es nuestro perfil claramente.','AV','Firmar'),
  ('2a1d053f-2af9-58a5-9298-1cdcd88fb6a1','740463c4-cc32-594a-a6f0-5771ff724a72','2026-02-26 21:52:27','VS Portugal 2','Es un jugador con mucha inteligencia táctica, muy parecido a Albelda jr, en este partido ademas para mi demuestra tener un paso mas adelante que todos en duelos.','AV','Firmar'),
  ('4e8d2baa-ddbf-556f-8b9e-d35dac090097','c2263afc-5411-560a-87cd-159e982e0d47','2026-02-26 21:53:36','vs Portugal 2','Juega 5 minutos, no realiza nada especial salvo un tiro desde el centro del campo.','AV',NULL),
  ('2ee44daa-c405-5421-bf82-352da342aaaf','b0c255df-79bc-5829-94cd-540862a61d01','2026-02-26 21:56:00','Vs Portugal','Mediocentro a tener en cuenta, es riojano, y tiene bastante nivel, debe mejorar en ritmos de juego','AV',NULL),
  ('38e07c96-cfdd-5ea8-a2f9-c7b701f0b6e9','b7b56d7d-21c3-57ab-b18c-209e13630287','2026-02-26 22:04:57','VS Portugal','Delantero con una planta muy importante y con bastante nivel técnico, gana muchos duelos y con el tiempo mejorara la lectura de espacios, no es especialmente rápido.','AV','Firmar'),
  ('0ba67432-c351-51e8-a1f0-c9095417b5c0','bfc9ac49-1dd7-5749-ba5e-99951ecd2147','2026-02-26 22:06:17','Vs Portugal 2','Se echa al equipo a la espalda, y tiene una gran confianza en si mismo, sin embargo para mi tiene mucho de fisico ya hecho y no es un jugador de ritmos altísimos como Thiago polo.','AV','Descartar'),
  ('2f53c446-db6f-5da2-96da-1b14ef8b2cd5','e37f069f-26ae-5186-8e65-8d31cb23bb05','2026-02-26 22:07:36','vs Portugal 2','Juega poco, pero a gran nivel, es un jugador excelente para nuestro proyecto.','AV','Firmar'),
  ('153a4bc7-bd59-5890-9fca-ecf0c5bc1410','d6ab76eb-94d5-507a-b5ef-a7cb3de31a55','2026-02-26 22:08:34','vs Portugal 2','juega el partido entero y se le puede ver mas, para mi el jugador esta muy lejos de lo que buscamos.','AV','Descartar'),
  ('5d504b6e-bb55-59a3-978f-cd25ea77d7e0','ee127d9a-a664-5ab4-b352-4440e4a7494d','2026-02-26 22:09:25','Vs Portugal 2','Juega el partido completo, y realiza un gran partido, para mi tiene acciones que generan dudas pese a su fisico, creo que puede evolucionar para bastante bien.','AV',NULL),
  ('2344ba7e-e2c0-5cd7-b14c-d3a9933be8ec','cd5c248a-fba1-5b53-b508-f6236f70b4f1','2026-02-26 22:10:41','vs Portugal 2','Para mi el jugador mas destacado del equipo en general, mucha habilidad para el 1x1 y mucha intención de ser vertical y eficaz, futbolista con muy buena pinta.','AV','Seguir'),
  ('0c466fda-f79a-527c-967f-e653bd462f80','0069bc9a-9cb9-5d78-9a30-846fecbf77ba','2026-02-26 22:12:24','vs Ceuta Ja','Para mi este chico debe mejorar muchísimo como delantero en movimientos y acciones finas, para poder estar al nivel de jugadores de la misma estructura.','AV','Descartar'),
  ('436a5cbf-bc35-5fd4-ba1f-afb28db74f0f','069198cc-637a-5f6d-b5ca-62835d455c5b','2026-02-26 22:13:28','vs Ceuta JA','Para mi el jugador tiene mucho ritmo de juego, esta en muchos lugares a la vez y tiene buenas acciones con balón, sobretodo en acciones mas finas de presión en espacios reducidos, puede desarrollarse bien en el futuro.','AV','Seguir'),
  ('4437b9e3-ccaf-5844-9c35-b25a68cabb84','45c87fa0-afce-5996-9241-65dba2d4335a','2026-02-26 22:15:00','VS Ceuta Ja','Es un jugador mediocentro- mediapunta, muy acomplejado y que siempre busca ser el centro en todas las acciones provocando perdidas y ganancias muy escasas en la progresión del juego, tiene que hacer un gran cambio de mentalidad en su futbol si quiere llegar a filial.','AV','Descartar'),
  ('d0f56b07-db7b-55ef-bf39-0997009512c7','e855c97b-de6f-596b-bd2e-9f8962ba411a','2026-02-26 22:16:35','vs ceuta ja','para mi uno de los centrales mas deficientes en velocidad y capacidades defensivas. pese a tener buen fisico, no veo que este jugador pueda llegar a estar en 2ª division.','AV','Descartar'),
  ('c313851c-2618-559e-87fc-1eaf2cceff77','4db4bdc4-077f-5a3a-b6d4-7e1816c71c20','2026-02-26 22:19:16','VS JEREZ','Perfil muy de nosotros, jugador fuerte rápido y vertícal, para mi con balón en acciones finas esta muy bien y se atreve a subir con balón, jugador interesante.','AV','Seguir'),
  ('4d9b7bc5-4f3c-5e3c-b22a-4ca7ab216049','5d5ca150-fb6f-5ca5-868f-f03d81b87568','2026-02-26 22:20:21','vs Jerez','Jugador de mucha presencia y jerarquía en el partido, quizás el que mas, en los momentos difíciles se echa el equipo a la espalda y coge mucho protagonismo, por perfil igual le puede costar pero, hemos de estar pendientes.','AV',NULL),
  ('6766c973-50f8-5d99-a985-20c5e8fb92ce','b8a0da97-0535-5a0f-b2dd-d4e54a8da487','2026-02-26 22:23:41','vs jerez','sale 30 minutos, para mi es un jugador muy interesante, con un conocimiento nulo del juego, pero que siempre va hacia delante y que tiene calidad y condiciones de sobra para tener mucho éxito en las situaciones de 1x1, para mi es un jugador que si gana confianza en sus capacidades y obtiene regularidad, se va a parecer mucho a Jesus Rodriguez.','AV','Seguir'),
  ('aae10890-0a54-51a5-b68e-6e99a8a006d2','f164647d-f803-5042-95f8-3aedd0af0fb9','2026-02-26 22:38:28','Vs Dinamarca Sub 16','Jugador muy top, con. Una inteligencia tactica por encima de lo demas, entiende el juego a otra velocidad y ademas en condiciones con sus iguales esta muy bien','AV','Firmar'),
  ('a06a6a7c-0771-5b7a-83f1-d969dbc49dc7','a83c332e-9a41-5bda-9acd-486481a9f1a7','2026-02-26 22:31:14','VS JEREZ','Para mi es un jugador con un gran potencial y capacidad a nivel fisico, en cuanto a balón, lo vi muy bien, y creo que es un jugador infravalórado ahora mismo por el club y con unas condiciones excelentes para su posición.','AV','Seguir'),
  ('b7465a6b-334f-57e4-a16b-18f4e41bf4da','38bed638-5f1b-5460-9a41-a11070614fae','2026-02-26 22:47:53','vs Dinamarca u16','Me deja un poco frio en cuanto a si de verdad tiene condiciones físicas para la elite, por lo demás es un central muy bueno de su generación.','AV','Firmar'),
  ('ff0ce07c-5d33-54db-88e8-56ea9e58d554','9fcd16af-6358-5246-bc75-e61af9a864f6','2026-02-26 22:50:55','VS Dinamarca sub 16','Jugador con todo lo bueno que debe tener un mediocentro en el fc Barcelona, pero del atlético, para mi no le da con ese fisico.','AV','Descartar'),
  ('9f59394e-ea72-54a6-9efe-0189f675912e','312836fc-fc81-54e8-8ec0-3f663b64771c','2026-02-26 22:51:59','VS DINAMARCA U16','Partido completisimo, ha sido el jugador que mas ha encarado y que mas se ha ido del rival en las situaciones de 1x1 demostrando ademas capacidad para ser eficaz y vertical,','AV','Seguir'),
  ('c8a5bf72-7f95-5be3-a79c-da054ff98fa4','24289a04-e455-5289-ace4-9bb7da9e0e75','2026-02-26 22:53:16','VS DINAMARCA SUB 16','Jugador de un ritmo de juego altísimo, y con unas altísimas capacidades para jugar en niveles mucho mas superiores y a un nivel muy alto.','AV','Firmar'),
  ('ab702ecd-e303-5a56-93a0-acaa303576cf','57cef1a8-67f4-5b44-bc47-7224e7f5fdab','2026-02-26 23:00:56','VS DINAMARCA SUB 16','Jugador de un ritmo muy alto, con unas condiciones excelentes en el centro del campo, sobretodo para jugar como mediapunta.  Eficaz. y rápido en espacios reducidos.','AV','Firmar'),
  ('f51e95ed-2c75-5c37-a22f-8bb955076cc9','e82f5fe0-8b18-5ced-9eac-ffc77741505c','2026-02-26 23:10:30','VS DINAMARCA SUB 16','Jugador muy blando en duelos y con pocos recursos en area, tiene gol y siempre lo tendrá, pero en elite le va a costar mucho','AV','Descartar'),
  ('c05f3d8c-ad7d-57b5-8ee0-bcff86795993','51eb8cbb-308a-59df-b76a-04960033302c','2026-02-26 23:14:21','vs Dinamarca sub 16','jugador muy poco fisico al que le costara mucho poder hacerse un hueco en el futbol profesional','AV','Descartar'),
  ('05c686c0-161f-5a0a-87b9-7bc58ead739d','061b7652-9f8e-5a6f-b766-b09701e52e1a','2026-02-26 23:18:45','vs Dinamarca sub 16','Jugador super interesante, con un perfil bueno, creo que puede seguir ganando altura, para mi uno de los jugadores de esta selección con mayor nivel y capacidad de ser vertical.','AV','Firmar'),
  ('cd3e3ce6-ae90-53b4-9172-b8c43b32ba31','0642d9f6-8bbe-5d72-86f5-aff9f5ebf770','2026-02-26 23:22:49','vs dinamarca sub 16','Es incomprensible que este jugador vaya a la española plano sin cambios de ritmo y con no excesivo nivel con el balón.','AV','Descartar'),
  ('da6fc80b-1cca-57db-bdbc-d16b0ea83d5a','6e04933c-8e30-5047-952c-11d028235952','2026-02-26 23:24:36','vs Dinamarca sub 16','Sale 15 minutos pero demuestra cosas interesantes, capacidad de desborde tiene mucha, para mi le falta un poco de fuerza en la aceleración pero es mejorable, con un prototípo bajito, aun asi lo suple con mucha calidad individual para encarar y irse en los 1x1, con un cambio de plano para empezar a acelerar muy interesante ( por ello cuando este mas desarrollado a nivel fisico, con una buena musculatura puede ser muy difícil de defender)','AV','Seguir'),
  ('42821893-a4f6-51af-b110-080e693e17c1','e03ef9d7-1d13-5c80-ba5d-a5fd3b567152','2026-02-27 12:26:47','HUESCA JUV. A - Zaragoza Juv. A','Lateral izquierdo de estatura medio-baja, pero con una complexión fuerte y con potencia en duelos y en carrera. Jugador rápido y agresivo con balón, casi siempre que recibe intenta verticalizar a través de conducción. Nivel técnico correcto, aunque con cierta habilidad cuando encara a su marca. Recorrido largo y un cambio de ritmo interesante. En defensa es intenso.','RP','Seguir'),
  ('b75c30e8-5fc2-59b7-85df-9af77b334823','976ae02f-ae62-5a8e-b573-ba60c990b08d','2026-02-27 12:39:19',NULL,'Extremo diestro, que suele jugar a pierna natural. Poco uso de izquierda. Tiene unas condiciones físicas excelentes: alto, de complexión delgada pero potente, muy rápido y explosivo. Perfecto para la posición de extremo. 

Se nota que a nivel técnico y de entendimiento del juego le cuesta aún, pero lo veo lógico por su proceso de formación. Es jugador con unas condiciones naturales muy interesantes, capaz de generar en conducción, atacando espacios y pisar área.

Firmar.','NB','Firmar'),
  ('64677c82-0809-5aa4-91fe-222ea012972b','741d991e-c401-534c-bb39-b36b5517a352','2026-02-27 12:43:09','vs Mosquito','Delantero centro de 1.90 m aprox, potente, bien de agilidad y velocidad para tamaño. Me parece un atacante muy completo, capaz de sumar fuera del área, con nivel técnico y entendimiento para asociarse. Con presencia en el área y recursos para finalizar.','NB','Firmar'),
  ('cbf78d31-2039-5559-ac92-08a4a6a7a5e5','7156b701-fca5-5287-89f0-bfef0420f96d','2026-02-27 12:42:41','HUESCA JUV. A - Zaragoza Juv. A','Central diestro con una estatura algo inferior a 1''85 m y complexión delgada. Parece rápido corrigiendo y es agresivo para intentar anticipar. Ganador por arriba. Con balón es correcto, pero no aporta grandes ventajas. Partido bastante serio.','RP','Seguir'),
  ('84d7e844-5699-52e7-b8ed-93d600931cee','054d71e3-b7f2-5abb-9efe-60655c9263a0','2026-02-27 12:52:38','HUESCA JUV. A - Zaragoza Juv. A','Central diestro con una estatura alrededor de 1''90 m y complexión delgada. Por movimientos no parece rápido, pero un par de veces que ha tenido que corregir no le he visto particularmente lento. Ganador de duelos por arriba y partido muy serio al corte y en la defensa de área. Con balón es correcto.','RP','Seguir'),
  ('f13a73cf-fac0-5938-8cf6-dafb4cd3c863','e7b28390-d322-56cd-a998-0ea25c2b1f1d','2026-02-27 13:02:13','Huesca Juv. A - ZARAGOZA JUV. A','Central diestro con una estatura algo superior a 1''85 m y complexión fuerte. Agresivo, bien defendiendo hacia delante. No es excesivamente rápido, pero no me ha dado la sensación de ser lento. Es intenso en las acciones y bastante ganador en duelos. Ha cometido algún error en 1vs1. Correcto con balón.','RP','Seguir'),
  ('d4c04115-caef-5a0d-a258-ad1e4240c10e','a3feda98-b530-5c81-a2e2-f1f6e7f868ff','2026-02-27 13:18:06','Huesca Juv. A - ZARAGOZA JUV. A','Centrocampista con una estatura algo inferior a 1''85 m y complexión fuerte. Me ha gustado el perfil físico y el despliegue sobre el campo, pero me ha dejado algunas dudas con balón.','RP','Seguir'),
  ('c1a8de88-7199-59ae-8b59-e95689a25a43','0ca7c28b-2192-5e76-a2be-ccb4358615c2','2026-02-27 16:57:05','PONTEVEDRA - Lugo','Centrocampista zurdo, en el partido actuando en doble pivote. Estatura alrededor de 1''80 m, complexión delgada. Buen nivel técnico con balón, poco en cuanto a intensidad, agresividad en duelo o ritmo de juego.','RP',NULL),
  ('e5333d2a-8050-5cbb-9da5-95697bb06f21','91ce153d-e698-53cc-801d-822eed34be4a','2026-02-27 16:58:18','PONTEVEDRA - Lugo','Extremo por derecha. Rápido y con un 1vs1 interesante, pero bajito y con poco peso en el partido.','RP',NULL),
  ('511b4836-6904-5514-919b-9ef09699175b','b4bd2e1f-afde-5847-a7b7-e605b53b7a87','2026-02-27 16:59:20','PONTEVEDRA - Lugo','Delantero centro diestro de estatura media y complexión ligera. Es intenso, se mueve bien y con balón deja algún detalle, pero no le veo un jugador diferencial.','RP',NULL),
  ('03cdfd69-df9b-56f6-8143-1c58886f9380','40025efd-413b-5e9c-96fc-7f5bff131e33','2026-02-27 17:00:53','Pontevedra - LUGO','Lateral derecho de estatura media y complexión normal. Buen jugador que puede crecer, pero no he visto nada muy destacable por físico, técnica o recorrido.','RP',NULL),
  ('1e8145e1-7b22-5bce-941e-36d45b734805','ce56a102-585b-57dc-9b00-a8f1855473b0','2026-02-27 17:02:28','Pontevedra - LUGO','Lateral izquierdo con una estatura cercana a 1''80 m y complexión delgada, con piernas largas. Es agresivo en defensa y suele saltar a por el rival para cortar jugada, pero tiene algunos errores de lectura. Físicamente preparado para repetir esfuerzos, en el partido sigue haciendo alta intensidad en el descuento. Tiene mucho recorrido y con balón es muy vertical, con un buen cambio de ritmo e intención de progresar siempre, incluso a través de conducción.','RP','Seguir'),
  ('37086166-fccc-5856-87b2-47ed13e63105','30ad7f02-191a-50a4-aded-398c60d79850','2026-02-27 17:06:41','Pontevedra - LUGO','Extremo diestro jugando en izquierda. Bajito, explosivo y con un 1vs1 decente. Poco peso en el partido y no tiene muy buenas cifras.','RP',NULL),
  ('2477c489-bc3e-50f5-94ed-331fe18f6a52','ab383fa7-fe57-5de4-b6a6-075a038f3032','2026-02-27 17:07:25','Pontevedra - LUGO','Interior de estatura medio-baja, poco impacto en el partido.','RP',NULL),
  ('7121e3da-c86e-5fae-b7bd-5fade8c0fe70','d056c032-8bc3-58ea-8432-2cfba11635e3','2026-02-27 17:13:30','Pontevedra - LUGO','Interior de estatura media y complexión normal. Entra en el partido con su equipo jugando con un jugador menos y no tiene mucha participación. Seguir por edad.','RP','Seguir'),
  ('c0fa5aac-924b-5300-9f8b-940182adc6ad','3cfaf681-48d0-53e4-b400-e3b8e91be3a1','2026-02-27 17:15:18','Pontevedra - LUGO','Delantero centro diestro con una estatura alrededor de 1''90 m y complexión fuerte. No parece rápido. Entra en el descuento y no participa mucho, pero tiene un perfil muy interesante.','RP','Seguir'),
  ('6e540624-3f49-501f-9b86-c64fd9bacdd3','c6fa1037-44ec-5e3e-aaef-7b3246aa2b76','2026-02-28 14:18:02','vs Alhaurin','Misma opinión. Es un central aún por terminar de hacer pero con unas condiciones y un potencial muy interesante.','NB','Firmar'),
  ('f5016874-0ea9-503c-bded-5d8fd4a9d70c','8102f726-96ab-5d2e-8aca-9680c62d73e1','2026-02-28 14:19:07','vs Alhaurin','Condiciones físicas espectaculares, en diferencial en este sentido. A nivel de entendimiento del juego y técnica aún por mejorar.','NB','Firmar'),
  ('1ec6fc07-742c-534e-b234-319fa68d25d5','3e396cdd-7cfd-5984-b4ac-23433caf2d6f','2026-02-28 14:19:56',NULL,'Estatura de 1.85, complexión delgada, buena zancada. Es rápido sin ser explosivo, de hecho creo que le falta un punto más para jugar en banda. Jugador de buen nivel técnico, vertical en acciones, le gusta encarar y tiene recursos. Me gustaría verlo atacar más espacio y generar en carrera.

Es un buen jugador, me deja algunas dudas como extremo. Por dentro, más cerca del área y entre líneas, me parece mejor.','NB','Seguir'),
  ('b9eb7e93-5321-56de-81a6-271bacf3da44','94ac9314-0695-51c9-9b80-5d3385506240','2026-02-28 17:59:26','Vs Tabernes blanquea','Muy bien en acciones de 1x1 defensivo, rapido y fuerte en duelos, le cuesta muchiisimo los balones con trayectoria aerea, le he visto muchos errores en ese aspecto.','AV','Descartar'),
  ('5d95e17e-3d21-5eaf-bfa4-826b613b047d','293e833b-50fe-586b-9b90-5af41eec6a48','2026-02-28 20:28:07','vs Granada','Central zurdo de buenas condiciones físicas: 1.84 m aprox, complexión fuerte, rápido y potente. Se impone en duelos, tiene buena lectura, capaz de defender profundidad. Progresa con balón con pases por dentro y conducciones. Lo veo en Primera División.','NB','Firmar'),
  ('cfb9e2fa-c869-594e-bf72-008472699411','b20c80ee-8c5b-5fc0-b4ef-c4f7cd0f1e0f','2026-02-28 20:30:08','vs Málaga','Lateral derecho agresivo para afrontar duelos individuales, aunque con ciertos problemas para imponerse y a nivel táctico. En ataque no toma demasiada altura, recursos ok sin destacar. Por perfil/edad es interesante aunque le falta.','NB','Seguir'),
  ('de2c51d6-4637-5785-bbc7-6eaea8da4cb3','2fefe7f2-8d94-5858-b4e5-ca26071d7dcf','2026-02-28 20:32:59','vs Granada','Extremo que va a otro ritmo, por encima del partido. Muy rápido y explosivo, peligroso al espacio y en conducción. Cierto que se difumina a medida que pasan los minutos pero es perfil para tirar hacia arriba seguro.','NB','Firmar'),
  ('00047090-dc4a-5822-bcf3-24aacda27a5b','1e98ab55-17e8-59ff-beb6-2a0fd2378f07','2026-02-28 20:34:31','vs Granada','Físico muy malo','NB','Descartar'),
  ('b86f61d5-3568-5bf8-8f1b-3ed2d58aa0e7','78925c35-8ecc-5020-92c2-16c3f2d02f29','2026-02-28 20:36:34','vs Granada','Perfil físico modesto, creo que le va a condicionar para subir de nivel. Sí que va a tener cartel en Primera pero no lo veo como jugador que destaque en niveles superiores.','NB','Seguir'),
  ('f0a4925a-7025-5228-a952-38180fb2a2b7','8d79de77-1579-5ce6-9e65-58f95ea27260','2026-02-28 20:38:02','vs Granada','Misma opinión que en anteriores. No me llama la atención por nada en especial pero sí que es un delantero que se mueve bien y tiene presencia en área. Interesante por movimiento en verano. Perfil Hugo Duro','NB','Seguir'),
  ('d1c6d444-d150-5ea0-8186-987f8e4e20d7','d73a8091-6159-5ce6-8a97-836dcd5a1927','2026-02-28 20:39:17','vs Málaga','Es buen mediocentro, rápido y dinámico, con presencia en ataque y defensa. Agresivo en presión, afronta duelos. Se suelta en ataque, juega hacia adelante. Me sigue dejando dudas su físico para niveles superiores.','NB','Seguir'),
  ('2a350a0d-f93b-59c8-8a74-602444ab1e98','551a445d-f976-56ec-8691-c06c64e6791b','2026-03-01 07:00:15','vs Oviedo','Misma opinión. Lateral izquierdo que por tipología es menos interesante que otros, pero que tiene recursos en ataque y en defensa para estar arriba. Preparado para jugar en Primera la próxima temporada.','NB','Firmar'),
  ('6a159421-6f37-5c43-9ad6-c7ff9cdc69af','13a848f1-428b-5bcd-b641-49b608fc16ef','2026-03-01 12:35:47','vs Roda','No es de firmar.','NB',NULL),
  ('1480e545-15b9-5ca1-8e4a-89cc68a70429','2dfbb9ba-ba60-5e15-b652-c5fc24cbb2dd','2026-03-01 12:37:07','vs Roda','Es jugador con empuje, que se adapta bien al puesto de carrilero. Le falta para ser extremo. Físico poco destacado.','NB',NULL),
  ('41987532-8d84-51fd-a3a9-c7bb6a32e7e3','61bacbb6-8b01-5917-8d00-f7c34cd49000','2026-03-01 12:38:06','vs Betis','Extremo puro, desequilibrante, con personalidad para el 1v1. Dudas sobre su crecimiento físico, ya que le cuesta','NB','Seguir'),
  ('4e3e9984-cb63-5ae9-97cd-a6f148d33974','3b76ec9b-0609-5acc-bdd5-416fb7feb213','2026-03-01 18:00:40','vs Getafe','Opinión parecida a últimos partidos. Le falta más físico, uso de derecha e impacto en general. Es buen extremo pero con limitaciones.','NB','Seguir'),
  ('b9bdcffc-fc16-5d46-9fb7-d1d8c359ac50','8e80a690-488c-5a22-8a4b-42acddc9f8bd','2026-03-01 18:02:30','vs Getafe','Me parece el jugador con mayor impacto del equipo y también el de mayor transferencia a niveles más altos.','NB','Firmar'),
  ('4e178a47-d042-5f72-be28-756f562a7747','63b65099-f3f3-5aef-afa8-876d9731f880','2026-03-02 11:30:12','FUNDACION VS PATACONA','Jugador con un gran perfil fisico, con unas condiciones excepcionales rápido y técnicamente muy bueno. Capacidad de repetición de esfuerzos y ejecuciones muy tops en centros laterales.','AV','Firmar'),
  ('b99822d5-178e-5e32-876b-f2ee655094b3','2620d953-892e-5992-95f4-e45941828b1d','2026-03-02 11:32:06','vs Patacona','Estuvo flojo en duelos y le costo mucho en espacios reducidos lento con balón y debe mejorar en la preparación de las acciones.','AV','Seguir'),
  ('d668be4e-c38d-5b9a-829c-29ec443cac10','3b5dc9c5-9c92-5083-80f8-0289e6a01243','2026-03-02 11:34:12','VS TABERNES BLANQUES','Jugador por encima de la media en sus condiciones, con muy buen perfil en duelos aéreos y que estuvo brillante. Muy buen nivel de acciones con balón','AV','Seguir'),
  ('7ca0da93-51f7-570a-8369-d29afbee14ca','e8e7f246-a7be-50d1-af60-9d540740722c','2026-03-02 11:35:25','vs Tabernes Blanques','Unico jugador de ataque de su equipo capaz de encarar y ir hacia delante, efectivo en sus situaciones de peligro. Esta mejorando mucho últimamente y esta volviendo a su mejor nivel.','AV','Seguir'),
  ('052ff120-b59c-52e2-9dd7-a4377ec03276','fd24a655-1327-57e0-914c-32247ffd8dea','2026-03-02 11:37:42','VS LEVANTE','Jugador con un buen perfil fisico pero que todavía no alcanza una versión positiva suya, para mi con unas capacidades físicas altas, pero al que le falta un poco de calidad en acciones sencillas de pases intermedios y situaciones de conducción con balón, creo que debemos seguirle por si mejora su relación con balón.','AV','Seguir'),
  ('c5127d57-1052-58f0-8da3-3642fce2334d','45080b56-6d23-5e5b-8607-6cc38cf96896','2026-03-02 11:39:39','vs levante','Jugador con un perfil fisico muy parecido a de Roa, pero con ya una capacidad alta a nivel de duelos y muscular, mejorando muchísimo con balón y siendo un jugador muy importante en su equipo, creo que es un jugador que pese a tener a Enzo en esa posición puede ir creciendo dentro del club, aun asi también puede tener condiciones para ser central, por velocidad y fuerza y también por ser capaz de jugar con pases filtrados, muy buena relación individual con el balón.','AV','Firmar'),
  ('96d374f4-c652-5ccd-b855-253da8495379','bc8cb2ea-81b1-5b79-b03d-53e4ba6ef98f','2026-03-02 11:41:57','vs levante','El jugador ha progresado mucho durante los últimos años y esta teniendo un rendimiento muy alto, sus condiciones son muy buenas fisicamente y aunque no lo ubicaría como extremo, el jugador en esa posición ha crecido mucho.','AV','Seguir'),
  ('cd592d1b-a3e6-5743-8666-a1ce7958fb30','817899a9-d9d5-58e4-815f-df059f50c7eb','2026-03-02 11:45:00','VS Levante','Jugador que cumple claramente con el perfil fisico, y que tiene unas grandes condiciones, con unas piernas y una masa muscular muy altas para su edad, con una estatura de entre 180 cm y 175cm. 

Tiene un futbol de momento en el que se atreve poco y no hace cosas determinantes, tiene que intentar ser mas determinante y jugar mas hacia delante, capacidad de finalizar.','AV','Seguir'),
  ('8cec2803-ce97-53f5-8203-c4f820fc43a6','f164647d-f803-5042-95f8-3aedd0af0fb9','2026-03-02 11:49:48','vs Valencia','Jugando con la gente de su edad, se nota que el chico esta en otra liga, en acciones de giros y como superar lineas rivales en conducción  o con pases el chico tiene una visión muy buena de los tiempos y sabe ejecutarlo bien, porque tiene calidad.','AV','Firmar'),
  ('d314d8ff-341e-5ee7-8c22-e83b9e233d25','1f214528-e2aa-59fd-b32b-2212275b211f','2026-03-02 11:54:29','vs valencia','Perfil fisico adecuado, con parece mucho margen de mejora, pero que a nivel mental al jugador le cuesta mucho, para mi un jugador para ir siguiendo y viendo como progresa.','AV','Seguir'),
  ('bd809bea-1d0c-5e57-9bc4-5cdeee1be52a','33aab9a1-13fa-587d-84c0-07b3f64a1680','2026-03-02 11:55:53','VS Valencia','Para mi un jugador que es todo lo contrario a lo que buscamos en nuestro juego y que debe mejorar mucho la toma de decisiones, un perfil parecido a Marc santos pero mucho peor en todos los aspectos del juego.','AV','Descartar'),
  ('06ac51fd-f7ba-5dfd-8e1d-e12ae1844981','d24eb8f3-cf61-5823-b1ca-dced3558ea4e','2026-03-02 11:57:05','vs Valencia','Unico jugador del Levante,  que fue capaz de provocar cosas en el campo rival, ganador de duelos ante Anas y con capacidad de ser determinante.','AV','Seguir'),
  ('7f7fe472-5ea3-5eaf-bd36-0f126088f99d','291f7c8f-31e3-5feb-ba7d-04dc101b2b41','2026-03-02 11:58:36','vs Buñol','Central muy alto,  y con complexión delgadíta, para mi rápido en giros, pero visto en un campo pequeño, fue un ganador de duelos durante todo el partido y completo un partido de mucho nivel, para mi sin duda un jugador al que debemos seguir.','AV','Seguir'),
  ('daa2b4f5-0a57-5448-b8f2-2a434e4ededc','ecf817f1-9ce3-5ef0-8a29-4ef503421b56','2026-03-02 12:00:20','vs Buñol','Delantero, no muy alto, pero muy rápido, complexión delgada y con nivel para mi técnico muy alto en espacios reducidos, creo que puede ser mas peligroso como jugador de banda que como jugador delantero centro, será muy interesante verle en partidos donde actue como extremo, para mi tiene gol y capacidad de ser determinante','AV',NULL),
  ('3d7b604e-6776-56ff-a2de-95ab82b2e6e1','a048706c-57ed-56e7-9c1c-eaf7ed81af94','2026-03-02 12:05:35','vs cd Buñol','Jugador con unas condiciones físicas idóneas, perfil de banda ya sea extremo o lateral muy interesante, en espacios tan reducidos le costo con balón, pero para mi es un jugador a tener en cuenta.','AV','Seguir'),
  ('cc8f5d3e-385b-5f0d-8067-8097d208b77d','e4126341-d2f6-59d5-a285-72d0696fbfe3','2026-03-02 13:09:42','CASTELLÓN CAD. A - Torrent Cad. A','Centrocampista diestro, en el partido actuando en doble pivote. Bien de estatura, complexión normal. Bastante calidad técnica para manejar el balón, escapar de presiones y distribuir.','RP','Seguir'),
  ('56bcb329-d93d-54d0-b2c3-b3aa994f7bbb','038fe3bd-cbaf-5996-9abb-70b053d6c412','2026-03-02 13:12:40','CASTELLÓN CAD. A - Torrent Cad. A','Atacante zurdo, en el partido actuando de enganche. Alto y complexión fuerte. No es rápido en carrera pero tiene un cambio de ritmo potente. Es creativo con balón, agresivo en los movimientos y transmite sensación de peligro en el último tercio. Va fuerte al choque con los defensas.','RP','Seguir'),
  ('717ca547-87fc-56f2-9ea2-63c6dffbcd2a','7f0ba287-94f4-52c9-9b33-f1051fc9a440','2026-03-02 13:14:14','Castellón Cad. A - TORRENT CAD. A','Delantero centro zurdo, bajito, con mucha movilidad y mucha calidad técnica con el balón en los pies. Es agresivo en la toma de decisión y dinámico para moverse en el último tercio. El perfil es más de extremo o mediapunta.','RP',NULL),
  ('dcc48ac6-cd9f-5b6a-b638-2734335f1848','40a87b80-143a-5f4f-b167-f867babb5657','2026-03-02 13:15:04','Castellón Cad. A - TORRENT CAD. A','Delantero centro diestro con un perfil físico interesante en cuanto a altura y corpulencia. En carrera no me ha parecido lento. Es agresivo y choca bien, pero no tiene demasiada técnica ni criterio con balón.','RP',NULL),
  ('7c11db43-ab91-5ddf-a28e-1f520cd8c3f4','4679ba77-4527-5a5b-bbbf-c3540a6030f7','2026-03-02 13:15:40','Roda - LEVANTE B','Centrocampista diestro de segunda/tercera altura, en el partido actuando como interior con cierto recorrido. Estatura algo inferior a 1''90 m, complexión delgada. Partido correcto pero para mi gusto discreto, sin cometer errores y participando pero sin demasiado peso en el juego ni en el resultado final.','RP','Seguir'),
  ('3c23cdda-8f50-5501-9447-db9604560cf8','98f8a33f-ad30-552f-a337-8757c9646cfd','2026-03-02 14:18:49','vs cd Buñol','Jugador que ha mejorado mucho de principios de año a ahora, con unas condiciones brutales rápido y fuerte en duelos por arriba, si es capaz de ganar 5kg de músculo, se puede hacer un hueco grande en 1ª plantilla.','AV','Firmar'),
  ('1a78441b-df14-5573-81b6-c83e3e10ab3d','3b946d9e-b958-55e4-9207-1ba4306d421d','2026-03-02 15:45:32','vs Las Palmas C','Extremo zurdo, de buen manejo de derecha. Perfil físico medio, de estatura media-baja, delgado, poco poderoso, rápido y explosivo.

Jugador vertical, agresivo en sus acciones, busca 1v1 con frecuencia, tiene regate. Poca participación y toma de decisiones mejorables. Ver más.','NB','Seguir'),
  ('5d30535e-e234-539f-a1f1-71711935e528','c2910e39-576f-5d41-857f-bbb131c1e84c','2026-03-02 15:48:59','vs Las Palmas C','Perfil de atacante interesante, me gustaría ver en campo para quitarme dudas sobre perfil físico (estatura, sobre todo). Jugando como delantero centro se mueve bien fuera del área, tiene buena técnica, es ágil y rápido.','NB','Seguir'),
  ('53a012ea-e9d3-5306-b955-e5c1f5c4bca4','a486798c-0dee-58b8-8d58-35c5f5818ec7','2026-03-02 16:53:01','vs Trival','Marca diferencias físicas, es extremo poderoso, muy rápido y explosivo, potente. Con cambios de ritmo, genera en carrera y yendo al espacio. Desequilibrante, con regate, capaz de meter balones en área. Me parece un perfil de extremo muy interesante.','NB','Firmar'),
  ('6215f55d-cdaf-5c1f-8b6c-5708f9157cdc','3bd975d9-6e54-5e89-96cb-403aea6fcbf7','2026-03-02 16:58:33','vs Trival','Lo veo estancado, con poco impacto en juego en los partidos esta temporada. Ya jugando como lateral. Creo que le va a costar el paso a la élite.','NB',NULL),
  ('266a5a7e-3a45-5670-9df1-0a8764235721','3a2b4fa7-685d-5d76-b73d-baa16718f4ab','2026-03-03 09:28:08','vs Alcoyano','#8 de estatura media, fuerte, muy rápido y ágil, dinámico. Es fuerte yendo al choque, maneja las dos piernas, juega hacia adelante, tiene buena técnica. Gana metros en conducción, progresa por dentro, busca pases entre líneas. Gira, soporta presión. Tiene recorrido y es trabajador en fase defensiva. 

Me parece jugador por encima de la categoría, destaca por tener un gran ritmo.','NB','Firmar'),
  ('a71a72fb-73ad-5ae9-b8d6-752a19268832','c7dd4e84-d7b3-550b-a784-92d84d62ff5e','2026-03-03 09:46:24','vs Utebo','Defensa central de 1.85 m aprox, de complexión robusta, fuerte, rápido y ágil. Es diestro, con poco uso de zurda. 

Con balón es vertical y agresivo, juega hacia adelante con pases por dentro, gana megtros en conducción, busca pases largos con bastante precisión. 

Pocas acciones de duelos individuales, aunque muestra fortaleza y agresividad para afrontarlos. Corrige bien, sale de zona y es capaz de defender profundidad.','NB','Seguir'),
  ('a92a426e-3884-5a1b-ab36-14c3dffafd6c','fe0497d4-3c16-56ca-bcf3-aa9b6ef1f322','2026-03-03 10:02:05','General','Extremo diestro, normalmente a pie natural. Poco uso de izquierda. Jugador de estatura media-baja, de complexión robusta. Especialmente rápido y explosivo, con punta alta de velocidad en carrera.

Es extremo con toma de decisiones mejorable, que aún no ha conseguido regularidad. De hecho ahora recién está comenzando a jugar con más frecuencia. De todas formas, sus condiciones son muy interesantes, recuerda a Baba Diocou. 

Peligroso yendo al espacio y en carrera, donde marca diferencias por velocidad. Es capaz de superar rivales en 1v1, pese a no tener técnica tan depurada. Pisa área con cierta frecuencia, aunque debe mejorar.','NB','Seguir'),
  ('3ac99b41-623d-5ffe-9c31-0c1de7f9bdc6','e8c1d7a8-c74f-54c6-8375-23b3b430fac0','2026-03-03 11:02:13','vs Valencia B','Central zurdo de nivel para categoría superior. Físico top, imponente en duelos individuales, bueno con balón. Maduro para fútbol profesional.','NB','Firmar'),
  ('1e0232e4-0fda-55fa-a7e4-f5bee132ae31','f0aee2cc-d724-57a9-9b72-8a367bc13a03','2026-03-03 11:07:09','vs Valencia B','Juega de #8. Físico promedio: estatura baja, delgado, poco poderoso. Con recorrido. Es intenso en su juego. Agresivo sin balón para afrontar duelos y en presión. Mucha calidad con balón para progresar y generar.','NB','Seguir'),
  ('83670d16-2fea-5281-a803-10dbe77b0499','be7d6b5d-248c-5984-a652-3dafc7472d3d','2026-03-03 11:10:12','vs Valencia B','Llama la atención por su físico, pero tampoco me da sensación de imponerse demasiado ni de terminar de asentarse en posición de delantero centro. Me deja dudas.','NB',NULL),
  ('e4d93c0e-045b-53b9-a024-6b011543b78a','f242b686-83be-55c5-bbc7-9098daaabe6d','2026-03-03 11:11:25','vs Valencia B','Perfil físico top para posición. Mucho vértigo, veloz, explosivo, con 1v1 y buen centro.','NB','Firmar'),
  ('1623a1bf-823d-51fc-8969-bc80975e1f82','2f11ef02-aef0-5f04-bd94-4c56642f093b','2026-03-03 11:12:48','vs Barcelona B','Lo veo en fútbol profesional próxima temporada, con trayectoria similar a Iker Córdoba. Buen prototipo físico, destaca por complexión atlética. 

Sin embargo, creo que tiene bastante que mejorar. Con balón sí que genera sensación de poder marcar diferencias, aunque no lo hace tanto en el partido. Defensivamente irregular, yendo a destiempo y con problemas para ir hacia atrás en ocasiones.','NB',NULL),
  ('fc8c8d02-d5fe-5243-8e85-f82482b9119c','02c89ceb-1b60-5123-bcff-e9603faccf1d','2026-03-03 11:16:20','vs Barcelona B','Central de buen perfil físico: bien de estatura, fuerte, rápido, ágil. Es agresivo en fase defensiva y progresa con balón. Me da sensación de que puede ir a más.','NB','Seguir'),
  ('f13c974d-6ef4-5ab2-9bf8-c691f187b921','bd30c830-2f42-5e94-94c5-aa10aa19fabf','2026-03-03 11:18:13','vs Barcelona B','Centrocampista de estatura cercana al 1.80, complexión muy fuerte, ágil, con recorrido. Trabajador en fase defensiva, sólido en duelos individuales, muy agresivo. Con balón tiene calidad para distribuir y acercarse a último tercio, aunque debe darle más ritmo a la circulación. Le falla la cabeza, preocupa ese aspecto.','NB',NULL),
  ('75a875bd-4fb7-5b87-9ae6-2f565a57f5b6','70b245a8-07a4-5a82-b89f-808bbf019cbf','2026-03-03 11:21:05','vs Barcelona B','Creo que no le va a dar como extremo, pero sí puede ser un buen lateral derecho de llegada en conducción/explotando espacios + centro. Jugador de buenos atributos físicos.','NB','Seguir'),
  ('fb7987f6-66e8-5765-9b84-3a90bcad2a8b','e7b28390-d322-56cd-a998-0ea25c2b1f1d','2026-03-03 16:55:45','vs Manresa','Central diestro de estatura aprox. 1.85 m, buenas condiciones físicas en general. Poco impacto en partido, está en el proceso de adaptación de los africanos. Seguir, misma academia que Saidu.','NB','Seguir')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('13febcb9-6ce6-56c5-9d10-2fa23259388a','b8a0da97-0535-5a0f-b2dd-d4e54a8da487','2026-03-03 22:11:46','vs Utrera','Extremo puro, de buen perfil físico: alto, delgado, con zancada, rápido. Tiene 1v1, es vertical en acciones, va hacia adelante. Irregular en toma de decisiones y finalización pero nada preocupante. Jugador a tener en cuenta.','NB','Seguir'),
  ('4083ee52-b935-5a7f-a525-434a0011504e','046638b7-c5d9-5071-b67f-91870b5ee487','2026-03-04 14:17:07','vs Betis','Lateral de buen perfil físico, vertical, con buena capacidad para conducir. Irregular a nivel técnico y en fase defensiva. Perfil interesante, aún en proceso de adaptación pero deja buenas sensaciones.','NB','Seguir'),
  ('012ab7c6-406b-5bc8-8aad-9ec9e136edd5','09a1829b-dd76-5ff6-bf8f-fc4d4fd7a9d7','2026-03-04 15:10:53','vs Boadilla','Mediocentro de buen perfil físico, box-to-box, dinámico y agresivo. Llegador, con buen golpeo de derecha y pase. Es perfil Diego Lacosta.','NB','Seguir'),
  ('32c6ab6c-f0a7-504e-89cf-c15c5528d908','5ac693e1-ede7-5532-846f-531665308edc','2026-03-04 15:12:46','vs Boadilla','Centrocampista que puede ocupar cualquier rol, incluso jugando en banda (su posición en Málaga). Buen perfil físico-técnico, muy hábil para generar, asociarse y llegar a área.','NB','Firmar'),
  ('5d9c6b08-c52e-5bba-910f-693d9cfe7938','2d368c13-58ad-5ffc-9a63-dfc64b4eb9bc','2026-03-04 15:15:30','vs Boadilla','Perfil de extremo vertiginoso, rápido y encarador. Le falta físico (es bajo, delgado y no potente) y uso de izquierda, ya que se vuelve previsible. Me deja dudas su evolución.','NB',NULL),
  ('4ab9f4ab-d07d-567c-8872-d9624fdd0481','af06e69a-152a-534f-8118-fad6d3713b69','2026-03-04 15:17:05','vs Boadilla','Perfil físico top, con buena técnica y comprensión del juego. Trabajador en fase defensiva. Adaptable a distintos puestos y roles. Transferencia a fútbol profesional. Por su evolución lo veo como un #6 más que como #8, pero puede jugar ahí.','NB','Firmar'),
  ('923e1913-67ed-54ae-b142-69ff462f2bc6','ceb7bffd-c4fc-5fc7-a43a-1088fcbc2a96','2026-03-04 15:44:52','vs Utrera','Parece que lo están adaptando a posición de lateral derecho, donde también da un gran rendimiento.','NB','Firmar'),
  ('3cdfe339-920f-52e6-8da8-03c85c7474fa','eb6a3e2a-11ff-58c0-b7c6-32df8f19dc2d','2026-03-05 12:37:39','General','Lo veo con físico demasiado desarrollado (sin ser tan alto ni dominante). Más allá de sus goles no le veo virtudes fuera del área. Me cuesta verlo en categorías más altas.','NB',NULL),
  ('b14de7ee-5064-5053-b5da-9e25e6b10abc','cba88c07-51ac-57cf-9173-24730e9e24ec','2026-03-05 16:19:38','General','Extremo diestro por izquierda. Buen uso de zurda. Es extremo de estatura media para posición, complexión delgada aunque con sensación de potente, muy rápido y explosivo. Jugador encarador, con 1v1, buena técnica, genera peligro individualmente. Giros muy rápidos, cambios de ritmo. Toma de decisiones mejorable  y también ejecución de finalizaciones. Me parece un perfil muy interesante.','NB','Seguir'),
  ('33e1c27e-cce6-509c-acb1-d96ffd2a72e3','0f09d115-3828-5481-8022-c5bc9b79db34','2026-03-05 16:53:05','vs Asturias','Extremo zurdo a pierna natural. De buen físico, cercano al 1.80 m, potente aunque con margen de crecimiento en cuanto a musculatura, buen punto de velocidad sin ser explosivo. Jugador que me recuerda a los Gamón, Mauro Roca...lo veo buen futbolista aunque con probable paso a posiciones más atrasadas. Finaliza bien pero le falta algo de chispa y regate.','NB','Seguir'),
  ('7ccaf845-9e82-5c4c-8826-314ab1b466e7','1b35dbe4-1e7a-5e19-a536-89f694f20083','2026-03-06 11:13:49','vs Rayo Vallecano','Lateral derecho al que no destaco ni por perfil físico, condiciones técnicas ni físicas. Normal, por debajo de estándares RM en mi opinión.','NB',NULL),
  ('eeb515f5-06f8-5e62-8879-3e3409d71cfa','1c4dc383-b594-5dab-98ef-97d420b7956c','2026-03-06 11:15:10','vs Rayo','Potencial de primer nivel. Perfil físico espectacular.','NB','Firmar'),
  ('81648a08-33c7-5088-baed-8530b9e7902c','fc6cee27-b26e-5ee7-8272-8146ffb74520','2026-03-06 11:16:01','vs Rayo','Mediocentro de gran perfil físico-técnico, dinámico en su juego, con recursos técnicos, fortaleza defensiva. Es muy completo. Potencial alto, transferible a fútbol profesional.','NB','Firmar'),
  ('f6a67575-b021-5709-ad15-073a318d5323','6d230e2b-b0c7-57a2-8d2d-5ef2ab5a3aa3','2026-03-06 11:16:55','vs Rayo','Delantero centro con condiciones muy similares a Álvaro Rodríguez, quizás con más musculatura que el otro a su edad. Es 1.90, rápido, juega bien de espaldas, va al espacio. Completo.','NB','Firmar'),
  ('045aebbd-9569-56b9-a79a-6d0bfd2c55f4','56915473-4e84-5468-b6db-8b51f0c359e1','2026-03-06 12:51:06','vs Atletico','Pivote de buen perfil físico, aún por hacerse en cuanto a estatura y fuerza. Con balón progresa en conducción, le gusta soltarse y jugar hacia adelante, tiene calidad para asociarse, es vertical en acciones. En fase defensiva tiene recorrido y posicionamiento. Es buen recuperador, mete pie. Me parece jugador interesante.','NB','Firmar'),
  ('ff61e6dd-4136-5969-b701-27cb6b023ba5','3d33d5f9-88a1-5da7-a047-bf7943d9691a','2026-03-23 13:00:00','vs Majadahonda','Delantero centro de perfil físico top, con buen juego fuera del área, jugando de cara y girando, buen nivel técnico. Me parece interesante, de lo mejor en su posición.','NB','Firmar'),
  ('04eeec3e-4757-59b8-bcb7-2086654041ac','36e34a28-4ee3-5a31-b735-6f80b2e33e87','2026-03-06 20:06:41','RACING JUV. A - Oviedo Juv. A','Central diestro con una estatura media para la posición y complexión delgada. No me ha parecido lento ni corriendo hacia detrás ni hacia delante, y además es agresivo y tiene un buen nivel de tensión. En el partido gana prácticamente todos los duelos. En salida aporta ventajas, tiene personalidad para retener el balón y buscar pases verticales.','RP','Seguir'),
  ('1e588df3-79bd-580b-9ca0-218ace7c46c8','ae0873d3-ffa0-5c97-bdd3-6d9689b7deda','2026-03-06 20:07:56','RACING JUV. A - Oviedo Juv. A','Lateral derecho con una estatura algo inferior a 1''80 m y complexión delgada, pero atlética. Buena aceleración y sobre todo velocidad punta. En duelos choca bien, pero le falta un punto para imponerse. Con balón está verde y no siempre toma la mejor decisión, además de que le falta un punto de finura. Sí ayuda al equipo a progresar recibiendo alto gracias a su recorrido y a algunos cambios de ritmo con balón.','RP','Firmar'),
  ('e602714d-a449-5e36-a29f-aa88747fa8ee','ecfd20cd-9b66-558a-b758-8f21a6f5ee79','2026-03-06 20:08:46','RACING JUV. A - Oviedo Juv. A','Centrocampista diestro de primera/segunda altura, en el partido actuando primero en doble pivote y después como mediocentro único. Estatura alrededor de 1''80 m, complexión delgada pero atlética. Con balón tiene una técnica correcta y un criterio decente para dar continuidad al juego, pero no aporta grandes ventajas. Sin balón sí es un jugador que genera a través del alcance que tiene, y la intensidad con la que afronta los duelos. Tiene cierta capacidad de robo también.','RP','Seguir'),
  ('d829b50d-8530-5b4b-93a1-c9e3173b3029','e5d88814-6bd5-5411-ac00-090329d78b87','2026-03-06 20:11:12','RACING JUV. A - Oviedo Juv. A','Centrocampista diestro de segunda altura, en el partido actuando como interior. Estatura alrededor de 1''85 m, complexión delgada. Jugador de ritmo alto, que abarca campo y que va bien en duelos. Con balón no tiene una técnica destacada pero es agresivo y casi siempre verticaliza a través del pase o la conducción. No participa mucho, pero siempre intenta mejorar jugadas.','RP','Seguir'),
  ('2d6d784e-2007-5dd1-9578-aa32c3355416','8c8610a1-e876-548d-9e62-1f24d7cce004','2026-03-06 20:15:35','RACING JUV. A - Oviedo Juv. A','Delantero centro diestro con una estatura alrededor de 1''85 m y complexión delgada. Con balón no deja mucho, pero es muy intenso tanto para duelos como en movimientos sin balón. Sensación de ser rápido en distancias largas.','RP','Seguir'),
  ('2a8d5acd-0576-573f-9ebd-94b8046fa031','bfa56b39-773f-5ff3-a807-f4cccffce184','2026-03-06 20:18:34','Racing Juv. A - OVIEDO JUV. A','Centrocampista diestro de primera/segunda altura, en el partido actuando en doble pivote. Estatura alrededor de 1''85 m y complexión fuerte. No parece muy rápido ni de movimientos ni en carrera. Poderoso en el duelo y con cierta capacidad de distribución.','RP','Seguir'),
  ('e66dc538-4c38-51b9-b2bb-3f026eecd69b','e3c4baaf-a65e-566d-a51e-7d13f01290e1','2026-03-06 20:20:51','Racing Juv. A - OVIEDO JUV. A','Delantero centro con una estatura algo superior a 1''85 m y complexión fuerte. Lento y en el partido no está acertado en duelos ni con balón.','RP',NULL),
  ('4da25531-6fda-5ed2-b9a7-8b3bd1937f11','a19737d0-2122-540f-b016-8b595505e959','2026-03-06 20:23:31','OLOT JUV. A - Espanyol Juv. B','Lateral izquierdo de estatura baja y complexión potente. Me ha parecido rápido y en el partido se muestra muy seguro tanto en acciones defensivas como ofensiva, sin ser un jugador de grandes recursos.','RP','Seguir'),
  ('1a5b6e30-9b6d-54fe-a3c3-2936120d47e7','1739e250-c971-5c27-a8cb-79bcc400d921','2026-03-06 20:25:51','Olot Juv. B - ESPANYOL JUV. A','Central diestro con una estatura algo superior a 1''85 m y complexión fuerte. Tosco de movimientos. El Espanyol pierde 2-0 con dos errores graves por su parte, pero es un jugador de unas condiciones muy interesantes a futuro. En el partido se impone en una gran cantidad de duelos por físico y agresividad. Su técnica, tanto defensiva como con balón, es mejorable, pero parece algo razonable dentro del desarrollo del jugador.','RP','Decidir'),
  ('596417a8-0d2b-5964-9a79-7659e9f097da','56c7600b-f4e5-57b5-a422-49931a55c435','2026-03-06 20:27:43','Olot Juv. A - ESPANYOL JUV. B','Lateral derecho de estatura media, pero con un físico interesante: fino pero fuerte, muy ágil y potente en duelos. Defensivamente es top, cuesta mucho superarle en el 1vs1 y en el tiene un porcentaje de duelos ganados muy próximo al 100%. Con balón, aunque tiene una técnica correcta y es hábil, tiene margen de mejora para aportar ventajas reales al equipo. Sí tiene bastante recorrido, y de hecho termina el partido de extremo. Quiero ver algo más.','RP','Decidir'),
  ('696d04ee-ab6e-5258-8bd5-325a8f5addf9','16d6116b-2e93-5ef7-bd43-792839a68036','2026-03-06 20:30:12','Olot Juv. A - ESPANYOL JUV. B','Extremo diestro, en el partido actuando a pierna natural. Estatura media y complexión normal, pero rapidísimo y con un cambio de ritmo brutal. Jugador con una técnica correcta en primeros contactos, pero con una habilidad muy grande para fintar con el cuerpo y hacer cambios de dirección. Si recibe al pie, tiene mucha facilidad para generarse situaciones de centro. Siempre sale a su pierna derecha y en el partido, aunque mete varios centros tensos y de calidad, no llega a conectar con rematadores.','RP','Decidir'),
  ('b43bc274-6ea4-5049-b816-9d1928b2fd1f','8063ad7f-fffa-5912-9662-6431027949df','2026-03-06 20:33:49','Olot Juv. A - ESPANYOL JUV. B','Delantero centro diestro de estatura alta y corpulento. No es especialmente rápido, pero no me ha parecido lento en carrera y es ágil de movimientos. Jugador sobresaliente ofreciendo apoyos al equipo y jugando de espaldas. Gana duelos en situaciones bastante desfavorables y a menudo consigue buenas descargas. Tiene criterio y buena técnica con balón.','RP','Seguir'),
  ('2e24a578-d2b6-5104-81c9-9c1c546da21d','8d710a95-ab1e-5c1e-8618-772e6a4b137e','2026-03-06 21:01:23','vs Murcia','Central diestro de condiciones físicas excelentes, potencial de máximo nivel. Aún con aspectos por mejorar pero es jugador de Primera.','NB','Firmar'),
  ('b35dcb55-f740-5c1c-b3ad-00d1cfb13557','7e30c9ff-719b-562c-bc31-15e3bec5924d','2026-03-06 22:32:12','Vs Albacete','Gran partido, si es capaz de mantener este nivel, puede llegar lejos.','AV','Seguir'),
  ('62e2b1c2-4ddb-561e-99f7-c98284dbc56b','aeb8cbbd-3d9c-5a3f-ace7-0cc1a7163b2a','2026-03-06 22:34:50','Vs Albacete','Central fuerte con intensidad y nivel, claramente esta para lr subiendo hacia arriba','AV','Firmar'),
  ('8364eb17-6824-54e0-b6cb-ece9124e44a2','b8b8aa80-d41b-58e1-939d-33d8eeeed79d','2026-03-06 22:38:36','Vs Albacete','Partido discreto, aun asi tiene una gran influencia en el juego y es determinante numerosas acciones de regate y desborde','AV','Firmar'),
  ('9e2cb880-0432-50aa-b5c6-9026cc643181','2fca2493-701f-5ef3-b2ed-345e292d79d0','2026-03-06 22:40:00','Vs Albacete','El jugador esta a un gran nivel. Para mi tiene todo lo que hay aue tener para llegar en su posicion, jugador myy interesante y del perfil.','AV','Firmar'),
  ('87aa8fee-b70c-5ebe-b74b-204df1d21576','b20b25e5-19a1-5966-ad72-58afaef5d7ee','2026-03-07 12:19:43','vs Castellón B','Insuficiente. Descartar por el momento.','NB','Descartar'),
  ('95cc7113-9045-510e-b8a1-905f6e3fbc64','cd4c52df-c37e-59d2-b472-f91b085cf326','2026-03-07 12:22:54','vs Histórics','Delantero centro de buen perfil físico: alto, delgado pero potente, da sensación de tener bastante por crecer. Rápido yendo al espacio, intenso, finalizador.','NB','Seguir'),
  ('0d8bdfe0-be4a-5d98-be0c-8b038c16933f','956cd0d7-3604-5735-a357-9829daef1ea9','2026-03-07 12:24:50','vs Histórics','El mejor del equipo, por condiciones, conceptos, nivel técnico. Físicamente no destaca y por eso hay que ver evolución. Juega de central, claramente no es su posición.','NB','Seguir'),
  ('e54c5b98-fc18-5ed1-8203-b504deb8df48','b8a0da97-0535-5a0f-b2dd-d4e54a8da487','2026-03-07 13:22:52','vs Seneca','Extremo diestro por izquierda. Buen uso de izquierda. Perfil físico interesante para posición, buena estatura, complexión atlética, delgada. Rápido y explosivo. Genera en conducción, tiene 1v1, vertical para buscar situaciones de desequilibrio. Buena finalización.','NB','Firmar'),
  ('3fbd3623-3064-5531-adc9-dbbe76abd0ab','ee67da3a-ab30-5042-81ef-1988913886e6','2026-03-07 13:26:00','vs Seneca','Mediapunta que puede evolucionar en 8 si sigue ganando trabajo defensivo. Es jugador zurdo con gran nivel técnico, visión de juego y llegada a área. Me da sensación de que debe subir punto de ritmo pero es futbolista interesante. Buen físico en cuanto a estatura y fuerza.','NB','Seguir'),
  ('ecae0593-5941-5726-a7eb-b2a5571c5c7c','4db4bdc4-077f-5a3a-b6d4-7e1816c71c20','2026-03-07 13:28:00','vs Seneca','Lateral derecho potente, rápido, con despliegue y recorrido. Tiene condiciones físicas muy buenas, transferibles a niveles superiores. Es agresivo y trabajador. Técnica ok, sin ser excelente. Genera en carrera.

De YF igual que Mario Navarro, intentar por ahí?','NB','Seguir'),
  ('4f8b4f48-2a52-5b93-8dfe-e05f86ce0424','657e7fdb-9b93-5ee4-bbe5-a2ad666eb656','2026-03-07 14:08:30','vs Betis B','Potencial de primer nivel, ya lo veo preparado para dar el salto.','NB','Firmar'),
  ('c242f3d4-cc28-529c-8c0c-88bc1a9a1e7c','d798ec05-56a8-58d6-b29a-f7ccddd102d6','2026-03-07 14:09:11','vs Sevilla B','Potencial de primer nivel, ya lo veo preparado para dar el salto.','NB','Firmar'),
  ('f046b103-82bf-59fa-b471-bee36fa16162','af06e69a-152a-534f-8118-fad6d3713b69','2026-03-07 14:46:59','vs Alcala','Mediocentro que puede jugar en las 3 posiciones por dentro, en mi opinión su lugar ideal es #6 u #8. Para #10 lo veo algo rígido. Es de complexión física espectacular, buenas condiciones técnicas, trabajo defensivo.','NB','Firmar'),
  ('86e19455-9637-5418-a09e-fe2cf14a1608','3509c5c1-e31f-5a62-acc1-91a82feb0d51','2026-03-07 14:51:36','vs Alcala','Lateral zurdo de buenas condiciones físicas: es alto, fuerte, potente para ir al choque. Perfil más defensivo, ganador de duelos. En ataque no es típico lateral del Real Madrid, se asocia bien y C ando llega a último tercio busca centros.','NB','Seguir'),
  ('a2322fda-473d-5de0-aecc-664e6eff37ba','20f52adf-a1e0-542b-949e-5af92f727e98','2026-03-07 17:59:52','vs Hercules','Extremo de estatura media-baja, tren inferior fuerte, rápido y explosivo, con recorrido. Destaca técnicamente y por su capacidad para generar ocasiones. Jugador autosuficiente que es capaz de "buscarse la vida" pese a estar aislado del resto del equipo. Es trabajador en defensa.','NB','Seguir'),
  ('446a0326-0a30-5a19-b6bf-239d0c22ee37','dc54a879-903a-5749-880c-7f0bb4b4a835','2026-03-07 20:31:30','vs Real Madrid (fuera)','Opinión similar a última vez, lo veo prototipo de central con transferencia a fútbol profesional. 

Poderío físico, sólido en duelos, agresivo para afrontarlos. Con balón bien, juega hacia adelante, le gusta conducir y superar líneas. Algo lento en primeros metros pero lo compensa.','NB','Firmar'),
  ('8a201100-5a7d-5ed3-bad7-6ff7f3c542ec','d0b0577d-baa1-5a77-b86b-e9127670c505','2026-03-07 20:33:28','vs Alcobendas','Central de condiciones físicas muy buenas, completo por su solidez en fase defensiva y recursos con balón. Me recuerda al tipo de central Mario Rivas, fiable y regular. No tan espectacular como Joan, ni con tanto potencial como Lemaitre, pero aún así a firmar.','NB','Firmar'),
  ('32f99051-792d-5003-b607-06cf5c4e8923','fcfcad7c-2733-5728-b273-f79dcce28ed9','2026-03-08 15:09:37','vs Villarreal - Levante B','Extremo de estatura media, complexión muy fuerte, rápido y explosivo. Genera peligro en carrera, sobre todo en espacios largos. Tiene facilidad para generar ocasiones. Me resultó interesante.','NB','Seguir'),
  ('187d4311-fd80-5d6c-b4f3-1621dc035c50','56bd0455-c4b6-5a47-93fb-bf0fa60c78ae','2026-03-08 22:07:00','vs Valencia Juv B','Mediocentro de gran perfil físico, prototipo box-to-box con presencia en ataque y defensa. Buen nivel técnico, sobre todo destaca por ganar metros en conducción y procesar por dentro, pisa ultimo tercio con frecuencia. Muy agresivo en fase defensiva.','NB','Firmar'),
  ('08a76cce-a163-58c9-9a98-9898d8325861','fa85303a-3bd7-52d6-8444-e2c8991e6128','2026-03-08 22:09:54','vs Valencia Juv B','Buen perfil, aún algo inconsistente. La próxima temporada en Juv A no va a jugar, al menos primeros meses. Ver cómo se desarrolla.','NB','Seguir'),
  ('ca4888dc-ed7f-5954-bcfd-5eaf1d63b455','e8e7f246-a7be-50d1-af60-9d540740722c','2026-03-08 22:11:10','vs Villarreal Juv B','Le veo posibilidades como lateral izquierdo, me recuerda a Masque en estilo de juego. Pese a físico de estatura baja, es fuerte y agresivo para ir al choque. Noto evolución en conceptos defensivos, cierra bien a Fode. En ataque llegando desde atrás es peligroso.','NB','Seguir'),
  ('6151158f-86e3-59aa-b22b-0d6aeb789545','94ac9314-0695-51c9-9b80-5d3385506240','2026-03-08 22:12:51','vs Villarreal Juv B','Creo que es jugador con buena salida de balón y condiciones técnicas positivas en general, pero al que le falta mayor fortaleza física (y centímetros) para posición de central. Apuesto antes por Lacasa.','NB',NULL),
  ('04b3edfa-004e-569c-8d65-0acabd7c9e21','1a633f3b-0484-5887-82c4-a60cc6f7af51','2026-03-08 22:14:18','vs Soneja','Premier League.','NB','Firmar'),
  ('a53dfe28-4e8e-58ea-9438-e054d0ab2202','f3a5c847-6d90-5c6a-9f37-a9a21629c971','2026-03-08 22:17:27','vs Soneja','Extremo/lateral de estatura media baja, fuerte, rápido y explosivo, con recorrido. Jugador con recursos técnicos interesantes, tiene 1v1, es vertical en sus acciones, tiene criterio para decidir en último tercio. Trabajador en fase defensiva.','NB','Seguir'),
  ('8fe164fd-b973-5c7d-b3f5-da71d2004a4a','d83250c0-c246-5a29-ac8f-571965383612','2026-03-11 09:57:16','vs Las Palmas','Pocos minutos de juego. Primera impresión negativa, mal perfil físico para posición.','NB',NULL),
  ('31ccb8db-d559-5cb5-8c61-4cc07b1d38ac','a2054f2b-3333-5564-947b-9308763f84a6','2026-03-11 10:06:01','vs Alavés B','Pocos minutos, insuficiente para valorar. Perfil físico discreto.','NB',NULL),
  ('ceb70436-f832-5a7d-956e-2e7a8be19419','c7dd4e84-d7b3-550b-a784-92d84d62ff5e','2026-03-11 10:17:51','vs Naxara','Opiniones similares a partidos anteriores. Es un central con buenas condiciones, agresivo en fase defensiva y con balón. En área bastante contundente, pese a que pierde la marca en el gol. Suele defender hacia adelante y es agresivo en los duelos. En posesión busca progresar por dentro, más con pases que con conducciones. Perfil físico similar al de Boyomo (parece por debajo del 1.85, robusto, complexión fuerte).

Valorar si tiene sentido meternos en otra operación de africano...','NB','Decidir'),
  ('4812ea02-8720-5019-8b29-4b38717b3b15','3ca994ed-ce52-5bca-9710-8b14bbd43e34','2026-03-11 10:52:23','vs Burgos B','Mediocentro de estatura media, complexión fuerte, buen físico en general. Con recorrido, dinámico en acciones. Es agresivo, fuerte para afrontar duelos. Con balón es algo rígido, aunque efectivo. Muestra ciertos recursos en espacios cortos. Con rango de pases reducido. Es vertical, no gestor de posesión.','NB','Seguir'),
  ('b8cd7c7d-c993-5998-94a4-0950a2b469ff','c41e5f7b-3c53-5cdb-9f3c-da2aa1d1126e','2026-03-11 12:33:51','vs Coria','Delantero centro de perfil físico espectacular. Desequilibrante en espacios largos y yendo al espacio. Me parece un perfil ideal a potencial para élite.','NB','Firmar'),
  ('319d2ae6-0292-526a-889e-4c0b12066b52','69d66096-279d-562b-bc3a-929238fdb6aa','2026-03-11 15:52:45','vs Málaga','Extremo zurdo, de buen perfil físico, desequilibrante, vertical, hábil para ir hacia adelante. Le falta mayor impacto en este partido pero hace cosas interesantes. Es jugador a seguir.','NB','Seguir'),
  ('ac513a0d-4448-52d8-860c-ed9cec5fcde8','2647c7f7-abfe-5afd-887c-aacb72569432','2026-03-11 15:55:07','vs Sevilla','Extremo diestro por izquierda. Tiene buen perfil físico: es alto, de zancada larga, rápido, con potencia por ganar. Es jugador vertical y desequilibrante, va hacia adelante, tiene repertorio para regate. Con margen de mejora en la toma de decisiones y finalización.','NB','Firmar'),
  ('f9d7adef-1186-5903-b3dd-7958298bfbbc','a6b6bd9c-56ca-5848-8ba3-f9d3c389117b','2026-03-11 16:36:41','vs Grama','Extremo de buen perfil físico, pero con poca participación en partidos jugados.','NB',NULL),
  ('6bac5996-08c3-5f69-a4c8-b6e8c0842eb0','11abe195-d641-5a37-95e7-64a57debad8f','2026-03-11 23:20:46','vs Betis Juv','Extremo que puede jugar por dentro. Muy rápido y explosivo, fuerte para ir al choque. Peligroso al espacio, con regate y conducción. Buen último pase.','NB','Firmar'),
  ('c7f85a4c-6a7c-58e9-b96d-128e1eb278de','bf08e968-5cc5-5b3f-b51c-a894e931dbfe','2026-03-11 23:22:47','vs Betis Juv A','Mediocentro perfil #8 de estatura aprox 1.80, complexión robusta, bastante ágil, con recorrido, intenso. Jugador de buen manejo de balón, recursos individuales, capacidad de llegada. Intenso y agresivo al choque.','NB','Seguir'),
  ('3f8a5edd-236b-5a94-957c-7215849522ea','8990848a-32d3-5b66-ba89-f75dad3b517b','2026-03-12 13:08:04','vs Mallorca','Lateral derecho de condiciones muy buenas y potencial alto. Buen perfil físico: alto, fuerte, rápido, con recorrido. Llega a último tercio con frecuencia, destaca especialmente por su precisión en centros. Es intenso y trabajador en fase defensiva. Con aspectos a mejorar pero jugador de nivel top.','NB','Firmar'),
  ('1ae4c834-b8fd-5162-84af-eade1f0bf5cd','7e90fc8b-6a7a-5eb7-a735-daf74c24faff','2026-03-12 13:09:51','vs Mallorca','Central diestro de perfil físico espectacular, cercano al 1.90 de estatura, constitución top, fuerte, de buena velocidad. Es sólido en duelos por arriba y por abajo, contundente para ir al choque, capaz de salir de zona, buena defensa de área. Con balón progresa, juega hacia adelante, da pases por dentro, bien en pases largos.','NB','Firmar'),
  ('6cfd3b90-01f5-505d-a1e5-ef46ff4c5635','fc505c7b-0ca4-5de9-983f-d0e024b6fb04','2026-03-12 13:11:45','vs Mallorca','Extremo puro. Zurdo por derecha. Mucha técnica y descaro para desequilibrar en 1v1 y generar ocasiones de peligro. Con buena capacidad de finalización para terminar, tanto con tiro propio como con último pase. Me parece extremo top, potencial alto.','NB','Firmar'),
  ('b385a641-3d8e-519d-9f2a-b2ae281cccb6','95cec330-315e-5814-8c7d-14d94611acf4','2026-03-12 13:13:55','vs Espanyol','#6 de físico top: estatura cercana al 1.90, fuerte, compensado. No es rápido pero tampoco lento, llega a las acciones, tiene recorrido. Se impone físicamente. Es ganador de duelos, buen recuperador. Con balón bien en distribución, incluso puede conducir. Jugador de potencial alto.','NB','Firmar'),
  ('2d406935-c70a-5322-887d-01f951c8efbc','989ecbc7-4f24-5e72-a750-6bcbd2a6c0f1','2026-03-12 13:15:34','vs Espanyol','No lo veo con perfil físico para delantero centro. No se impone en duelos, no genera, prácticamente no participa.','NB','Descartar'),
  ('bf45c4dc-9cb1-5743-8e9c-3e77f0b249ba','4f9c2b27-9205-588f-9bc6-c9a90ab30478','2026-03-12 13:18:30','vs Mallorca','Lateral izquierdo de buen perfil físico: +1.80, fuerte, rápido, con recorrido. Jugador vertical, de ritmos altos, que juega hacia adelante. No es especialmente técnico pero tiene buen manejo y criterio para jugar. Más de volumen que de precisión. En fase defensiva es algo anárquico, debe crecer en consistencia. Yendo al choque es fuerte.','NB','Seguir'),
  ('3a32e5fe-adcc-5564-8aa5-f5744020e493','e9602a91-2142-5d52-b3c5-f8cfc86e447e','2026-03-12 13:21:16','vs Mallorca','Delantero centro de aprox. 1.84?, de complexión fuerte, ágil y rápido. Me recuerda físicamente a Roates pero más bajo. En perfil de jugador también es similar, juega bien fuera del área, de espaldas, se asocia, puede conducir, va al espacio. Le falta algo más de presencia en área. Comparándolo con el perfil de delanteros de España 2007-2009 me parece de lo mejor.','NB','Firmar'),
  ('2f0e637a-ecbf-52dd-9767-4f99beebb880','e03ef9d7-1d13-5c80-ba5d-a5fd3b567152','2026-03-12 14:52:55','vs Barcelona','Lateral izquierdo de estatura baja, fuerte, rápido, con recorrido. Da sensación de estar algo descoordinado. 

En defensa hace un buen trabajo. Es fuerte en el duelo, lee bien el juego en acciones defensivas, tiene gran retroceso, cambia de chip con velocidad. 

En ataque le falta bastante nivel técnico para marcar diferencias.','NB',NULL),
  ('8c00aabd-2615-5f23-9707-7b6ef9c97d9b','7156b701-fca5-5287-89f0-bfef0420f96d','2026-03-12 14:56:02','vs Barcelona','Central diestro de estatura aprox. 1.85, complexión delgada aunque fuerte, bastante rápido. Se muestra sólido en acciones defensivas, tanto en defensa de área como fuera de ella. Se anticipa, va bien abajo, gana por alto, domina centros laterales. Con balón deja detalles interesantes, sobre todo por intenciones de ir hacia adelante en conducción tras recuperar, sin ser top.','NB','Seguir'),
  ('a7ace88b-1db6-5d4a-9190-52108067d50d','cf3a8e8a-a043-5a3e-8037-9e2154369985','2026-03-12 15:00:08','vs Huesca','Central zurdo con condiciones físico-técnicas, y también comprensión del juego, top. Tiene potencial alto, lo veo en filial pronto.','NB','Firmar'),
  ('2ca88829-463f-5eb6-ba2f-f92c1c4bd1d5','15c931ac-6a62-54e8-838d-f6302eccd15d','2026-03-12 15:01:15','vs Huesca','Mediocentro top. Mejor como 8, puede jugar en cualquier posición de mediocampo. Jugador con condiciones técnicas y comprensión del juego excelentes. Es firmar seguro.','NB','Firmar'),
  ('2874d587-70e9-5dbd-a156-e9ec7b22da30','984e5ddc-a7ce-559b-90dd-41849d90f405','2026-03-12 16:40:02','vs Lugo','#8 de buen perfil físico: +1.85 m, espigado, delgado, ágil, con recorrido. Me da sensación de que le falta mayor presencia en el juego, puede influir más. Jugador vertical, al que le gusta ganar metros en conducción y progresar acercándose a último tercio. Ok en fase defensiva sin ser tan contundente en duelos. Necesito verle más cosas para firmar por edad/contexto.','NB','Seguir'),
  ('0f389fdc-6e04-5706-852e-c2b1dff9d410','6978206f-1ef8-5d2d-9535-56b1d4c18bb6','2026-03-13 13:20:48','vs Deportivo','#6 de perfil Barça. Jugador de gran técnica, juego asociativo, con agilidad/dinamismo para ir hacia arriba, con recursos para progresar con balón y sumarse a ataque, incluso para ser 8. A primera vista no tiene físico llamativo, destaca por recorrido. Defensivamente ok sin ser excelente. Es jugador a firmar.','NB','Firmar'),
  ('f819ac2e-371b-5932-af9f-c42af4fdd1eb','795ff7e0-dadd-5a42-ac46-97555f0b3469','2026-03-13 13:22:54','vs Barcelona','Lateral izquierdo perfil De Roa. Defensivamente aún es irregular, debe ganar punto de agresividad e incluso de comprensión. Con balón es top, tiene técnica y visión de juego. Buen físico, dudas sobre velocidad punta y agilidad. Creo que es buena pero no llega a los datos de Carlos.','NB','Firmar'),
  ('4d84b1f6-2de9-5fe2-b46b-9511c29854eb','343bee91-d35f-5c5d-9677-3eeef07a6dc8','2026-03-13 13:36:00','vs Barcelona','Lateral derecho consistente, que da un buen rendimiento defensivo y tiene recorrido para llegar a ataque. De físico hecho hace años, poca evolución en ese sentido. Jugador con posibilidades de profesional por prestaciones aunque sin tanto potencial como Nacho, por ejemplo.','NB','Seguir'),
  ('0390e441-d958-5c8d-8906-71121949fc32','29011403-ae34-53eb-adab-b32f35352634','2026-03-13 17:24:30','vs Celta 110326','Juega tocado. Aún así muy agresivo en el duelo, muy rapido reaccionando en situaciones de 1v1, muy difícil de superar, agil en primeros metros. Con balón tiene mucha capacidad de acelerar y superar rivales desde campo propio. Tiene que tener más peso y más tranquilidad en zona de último tercio.','PP','Firmar'),
  ('73b6e5cc-97bb-57c1-acb4-3e3a0ebde5dc','29011403-ae34-53eb-adab-b32f35352634','2024-04-06 17:26:47','Calavera','Óscar Masque (2007 | Lateral derecho): Lateral rápido y dinámico, con habilidad para el 1v1 y buen regate. Llega al área con frecuencia. En defensa es agresivo pero debe mejorar timing en duelos individuales. De los jugadores más destacados.','NB','Firmar'),
  ('be9140b2-fe6c-5545-b6ea-62d032f6948f','45080b56-6d23-5e5b-8607-6cc38cf96896','2026-04-25 20:55:00',NULL,'Lateral izquierdo de gran perfil físico: es alto (diría que puede llegar al 1.90 m); fuerte; ágil; rápido; con recorrido. 

Tiene técnica adecuada para asociarse, conducir e incorporarse al ataque. Me sorprende positivamente por su bien pie en controles, pases…Buenos centros también.

En defensa es sólido, gana duelos por fortaleza física, es agresivo para buscar choques.','NB','Firmar'),
  ('a9545ebc-4f24-5843-9b1e-a2f45cdf54e8','817899a9-d9d5-58e4-815f-df059f50c7eb','2026-03-13 21:05:18','vs Racing','Mediocentro #8 de buen perfil físico: estatura aprox 1.80, complexión fuerte, con musculatura desarrollada, ágil y dinámico. 

Da sensación de jugador vertical, con llegada. Es cierto que no participa mucho en juego. Me gustaría verlo más pero el perfil es interesante.','NB','Seguir'),
  ('5f898718-bda6-5015-8755-115159c31c81','e7eb00d7-495b-5b8a-81b7-f5c8508bf919','2026-03-14 12:28:05','vs Espanyol Juv B','#6 diestro de buen perfil físico: espigado, de complexión delgada, con músculo por hacer, bastante recorrido e ida y vuelta. Es un jugador inteligente para posicionarse, cubrir espacios…Con buena técnica para asociarse, típico 6 catalán en ese sentido. No es tan vertical aunque cuando llega a último tercio muestra buen golpeo. Buen recuperador. Es futbolista interesante, a firmar si le veo más partidos a este nivel.','NB','Firmar'),
  ('42b7faa0-760b-5578-9704-10a293679c1b','0cef8bca-e701-52ce-996d-b5dc3a51c7de','2026-03-14 12:38:34','vs Espanyol Juv B','Extremo diestro a pierna natural. Estatura baja, rápido, explosivo. Con desequilibrio, vertical para buscar 1v1.','NB','Seguir'),
  ('bebae5c5-74a8-5543-b917-3606fc66177d','1739e250-c971-5c27-a8cb-79bcc400d921','2026-03-14 12:41:58','vs Damm','Central diestro de buen perfil físico, aunque da sensación de algo pesado. 
Tiene condiciones interesantes pero le veo falta de contundencia en área y en duelos en general. Arriesga poco con balón.','NB',NULL),
  ('33a2156d-2693-5bd6-92de-fae7b0891dff','1fc5073a-5a9f-5c8a-b0de-ff3f4d3cc964','2026-03-14 12:43:19','vs Damm','Central zurdo de buen perfil físico en general, aunque me genera dudas su velocidad. Debe crecer en agresividad en duelos, le giran fácil e incluso regatean.','NB','Seguir'),
  ('2ab743f6-43fd-5efb-be3d-c3624046d275','210c5a49-0821-533e-b4f3-9f20e801d45e','2026-03-14 16:17:37','vs Europa','Le cuesta imponerse físicamente, da sensación de estar bastante por debajo de lo que necesita para la categoría. Primer partido y pocos minutos, no sacar conclusiones…pero debe mejorar el aspecto físico para competir. Me deja dudas en condiciones actuales, siendo consciente de que no tiene demasiado margen de crecimiento.','NB',NULL),
  ('64dfbd1e-0852-506d-8142-20bfc36cfd7f','8e80a690-488c-5a22-8a4b-42acddc9f8bd','2026-03-14 22:52:16','vs Lugo','Extremo por izquierda. Buen perfil físico, parece superar el 1.80 m. Es delgado pero bastante potente. Sostiene velocidad en carrera pese a no ser explosivo. Jugador vertical, capaz de generar por sí solo, con gran capacidad para finalizar jugadas. Es potencial de primer nivel.','NB','Firmar'),
  ('7d9ebd00-0e06-5ab2-bfc5-23775483eb8c','6d36df14-9741-52ea-8ce4-46c1307ced97','2026-03-14 22:54:23','vs Lugo','Lateral derecho de estatura media-baja, complexión fuerte, rápido, con recorrido. Nivel técnico excelente para asociarse y generar individualmente. Llega con mucha frecuencia a último tercio. En defensa aún es mejorable pero le veo evolución. Potencial de primer nivel.','NB','Firmar'),
  ('2b7ed646-582f-5f33-9a98-70b47b920ebc','64c162b1-75d3-5f34-9a00-1939664d085d','2026-03-14 22:57:09','vs Lugo','Delantero centro de aprox 1.90, de complexión fuerte, muy potente para ir al choque, con buena punta de velocidad para ir al espacio. Muestra recursos fuera del área, incluso para progresar por sí mismo, y buena capacidad de finalización.','NB','Firmar'),
  ('33ece2b9-9712-5339-8e6a-5f921fd1c6eb','42e02623-9132-57ce-950c-fb52ffd11a23','2026-03-14 22:58:00','vs Lugo','Central zurdo de estatura algo por debajo de 1.85 y complexión muy fuerte, es robusto. Buena velocidad y agilidad. Contundente en duelos individuales, agresivo y ganador. Con balón juega hacia adelante buscando progresar.','NB','Firmar'),
  ('3828c3fd-c66b-55a0-95db-9e424a89a133','cd8312ea-79bc-5921-8831-e1a9fd36221a','2026-03-14 22:59:30','vs Lugo','Mediocentro perfil #6 de complexión muy fuerte, tren inferior muy desarrollado. Jugador con recorrido, fuerte al choque, ganador de duelos, con recursos para superar presión en corto. Jugador de Primera.','NB','Firmar'),
  ('0592f227-deb6-53c7-a16b-c0bef3631db2','29011403-ae34-53eb-adab-b32f35352634','2026-03-15 16:25:11','vs Barcelona','Lateral derecho de gran fortaleza física, conceptos defensivos notables, agresividad para ir al choque, y habilidad para imponerse. En ataque genera ocasiones por sí solo, llega al área rival con frecuencia, tiene buena técnica y decisiones. Top.','NB','Firmar'),
  ('114c81ed-98b8-59b6-b47b-acb33e6ee787','d798ec05-56a8-58d6-b29a-f7ccddd102d6','2026-03-15 16:26:55','vs Barcelona','Extremo de primerísimo nivel. Jugador top.','NB','Firmar'),
  ('d40dd1e5-9a56-5d35-bde1-11ed660a8edc','d485b5cf-04b9-5a19-9ba8-385c2d042061','2026-03-15 16:29:48','vs Betis','Central promedio, no lo veo destacar en nada. Ni tampoco por físico.','NB',NULL),
  ('17cb2747-ce89-5bd4-8989-03244d48d27d','4b775f94-20f1-556f-8a78-19854e5abaa3','2026-03-15 16:30:34','vs Betis','Lateral zurdo de físico mediocre y poco impacto','NB','Descartar'),
  ('68035adc-8a6e-5229-be4b-2c70f28275de','f242b686-83be-55c5-bbc7-9098daaabe6d','2026-03-15 16:34:31','vs Betis','Extremo de estatura media-baja, rápido y explosivo. Genera en carrera más que en corto. Le falta mayor impacto en el partido, se impone poco ante De Roa. Aún así es un buen perfil de extremo.','NB','Seguir'),
  ('c39463dc-2a76-5aec-bf65-69dd91ca0dc8','a553228d-0997-53f0-b232-f74a84bbfdf0','2026-03-15 16:35:35','vs Betis','Mediocentro de estatura muy baja (más que Rica y Corralejo), de complexión fuerte (tiene tren inferior potente y espalda). Jugador al que le gusta conducir y tocar balón con frecuencia, no lo veo destacando.','NB',NULL),
  ('de6eb9c4-e244-53ac-8319-e03973bf3470','22d6011c-03d5-542e-aed8-1bb6993d011e','2026-03-15 16:39:34','vs Betis','Delantero centro de buen perfil físico: aprox 1.90, fuerte, rápido. Activo fuera del área, va bien por arriba, se nota que es peligroso en área.','NB','Firmar'),
  ('cfb9e775-bcac-5298-acb8-a18e2b0ad90b','a2e16544-e475-5639-b0f8-396e0e3f9e38','2026-03-15 16:40:50','vs Betis','Perfil extraño, seguramente su mejor posición sea por dentro. Tiene buen perfil físico pero le falta para jugar por fuera y por dentro tampoco lo veo impactando positivamente.','NB',NULL)
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('4f1d0c72-0be0-58ad-9cb4-84489e9cde42','be7d6b5d-248c-5984-a652-3dafc7472d3d','2026-03-15 16:43:13','vs Betis','Opinión similar. Marca gol y genera bastante peligro, aunque creo que le falta nivel técnico para hacerlo de forma regular. Creo que debe jugar por dentro (delantero o segundo punta), porque le falta finura para ser extremo.','NB','Seguir'),
  ('dd0da9cd-b6b6-58ad-a1e7-74b2c9ffa9c5','cc7e3d37-0671-5974-95b6-daa354779d46','2026-03-17 18:48:11','vs Brujas','Creo que es futbolista con mejor fama que rendimiento. Me cuesta verlo en niveles más altos.','NB','Descartar'),
  ('10dd1472-d96a-5f07-b066-82f5302ec10d','e17cc547-8e49-5175-b7e0-8a7cb266b528','2026-03-17 18:55:37','vs Brujas','En UYL me genera dudas por físico. Lo veo pequeño, poco poderoso, le cuesta ir al choque. No genera tanto impacto.','NB',NULL),
  ('442b48b6-aae3-5946-ba50-ee3fed2e5286','091fbc8d-6697-58ae-9757-3de2e5d1d2dc','2026-03-18 09:22:50','Garriel','Iván Garriel es un lateral izquierdo de condiciones físicas notables: buena estatura para posición, es rápido, explosivo, con recorrido e ida y vuelta, potente para ir al choque. 

Es un lateral serio en defensa, con conceptos positivos, difícil de superar en uno contra uno. Es intenso, no rehuye del contacto físico, no da facilidades. Aún puede seguir evolucionando pero está en un buen nivel en este aspecto. 

En ataque es vertical, juega hacia adelante y llega a último tercio con frecuencia. Genera desequilibrio principalmente en conducción y en espacios largos. Saca centros y remates con relativa facilidad. 

Por condiciones físicas y perfil es jugador de Primera División en el corto plazo.','NB','Firmar'),
  ('97328982-8d57-532a-92ae-953ba69e42bb','23355bf5-c220-535e-a3fc-3b650b85b822','2026-03-18 09:31:56','vs Valladolid','Lateral derecho promedio, que toma decisiones adecuadas y juega fácil. No le veo recursos en ataque como para marcar diferencias, más allá de ser un pasador correcto. En defensa es intenso aunque tampoco especialmente difícil de superar.','NB',NULL),
  ('9a0e2502-160d-5d12-87f1-31cb70f0a7a1','b455d837-13c3-588c-98fb-06717c31768d','2026-03-18 09:47:21','vs Orihuela','Ayman es un #8 - #10 de físico promedio, bastante intenso y dinámico. Es ágil y rápido, juega a ritmo alto. Jugador que va hacia adelante, diestro pero con buen manejo de zurda, progresa en conducción y es esforzado en fase defensiva. Tiene buena capacidad de finalización de jugadas. Ver más.','NB','Seguir'),
  ('1ac65306-c8f7-5ec5-930b-cd5ca72f36a8','24adceec-072c-52dd-bbba-83359c076e94','2026-03-18 10:55:06','vs Gimnastica Segoviana','Mediocentro de buen perfil físico, diestro, parece de ida y vuelta. Pocos minutos para juzgar. Ver más.','NB',NULL),
  ('aef88e08-bbb2-574a-be8b-2269aeeab52b','6ca7a462-18c5-5a5c-8405-5822a9d14e46','2026-03-18 11:43:53','Campos','Defensa central diestro de buen perfil físico: estatura +1.85, complexión fuerte aunque con margen de crecimiento muscular, ok de agilidad y velocidad. Destaca por salida de balón, nivel técnico alto y recursos para asociarse. Sólido en general, con algún problema para parar giros y cobertura de profundidad.','NB','Firmar'),
  ('8a82e155-3152-5704-8f83-1fff4199faa3','7ccda7d4-b43b-5eb0-be76-0670ccaac1bc','2026-03-18 12:12:50','MENDES','Central diestro muy fuerte muscularmente y muy rápido, con velocidad punta alta. Dudas sobre estatura, no sé si llega al 1.85 m. Es agresivo en fase defensiva, va abajo, bien en defensa de profundidad. Con balón ok sin destacar.','NB','Seguir'),
  ('a6667651-85f8-5d35-843f-4ba10e43f265','05af3b9b-95ef-5a30-b7e7-a90d4228e817','2026-03-18 13:50:45','vs Escocia','Potencial primer equipo Barcelona en proximos años. Futbolista con potencial para ser generacional.','NB','Firmar'),
  ('bb34b954-4bc5-5a03-b929-082d292131b9','a8b7da47-5ec1-5310-917c-208b2f9fccde','2026-03-18 13:52:42','vs Escocia','Es jugador de gran nivel técnico y recursos en 1v1, pero me genera dudas su físico. Es cierto que en Juvenil A es capaz de imponerse por velocidad y fuerza. Es un extremo interesante, sujeto a su adaptación a niveles más altos por físico.','NB','Seguir'),
  ('1fa0ff7b-565e-5161-8a94-d958e9ade50c','fd01dd01-a269-5401-88f4-a13a90a488d5','2026-03-18 13:54:44','vs Escocia','Juega de #9 en selección, su puesto ideal es mediapunta. Perfil similar a Toni Fdez, muy estilo FCB. Jugador que tiene nivel técnico excelente, capacidad de asociación, recursos para finalizar. No tiene físico de #9 pero puede terminar siendo. Es firmar.','NB','Firmar'),
  ('955800ea-6923-53da-8693-e1e5e3d95277','43479982-bcdd-5184-b814-a84af3ab5dba','2026-03-18 13:56:35','vs Escocia','Central derecho de perfil físico espectacular a primera vista: es alto, fuerte, de complexión atlética, compensado. Bien de agilidad, alguna duda en velocidad pero cumple. Tiene calidad en salida de balón y es agresivo en fase defensiva.','NB','Firmar'),
  ('ade7bb67-70ab-5853-bd3d-416a99f61762','a2be8163-703f-5def-8994-d0c525a0258b','2026-03-18 13:58:18','vs Escocia / Turquía','Central izquierdo de buen perfil físico, al menos tan alto como Mario Diaz (parece que ligeramente más incluso), de complexión fuerte, velocidad/agilidad normales. Destaca en salida de balón, tiene capacidad para ganar metros en conducción y pasar. Pocas acciones de duelos, lee bien el juego y previene peligro.

Me parece un central ok, no del potencial de Mario Diaz / Lemaitre / Jorge Domínguez. Si tuviese que elegir me quedo con Iker Herrera incluso.','NB','Seguir'),
  ('1e115a58-f88d-56cf-a26f-687f3db1af19','cba88c07-51ac-57cf-9173-24730e9e24ec','2026-03-18 16:29:56','vs Girona Juv B','Extremo de buenas condiciones físicas, muy rápido y explosivo. Le falta punto de precisión en acciones de 1v1, intenta ser vertical sin tanto éxito. Último pase/centro mejorable. Trabajador en fase defensiva. Necesito seguir viendo.','NB','Seguir'),
  ('8d1bca7b-b3ef-55d0-834b-17e531deb8c1','7ccda7d4-b43b-5eb0-be76-0670ccaac1bc','2026-03-19 13:22:33','vs Girona Juv A','Central diestro de estatura aprox. 1.83 m, complexión atlética, tren inferior fuerte, compensado muscularmente. Destaca especialmente por velocidad en carrera, con punta alta, aceleración y agilidad notables. 

Es jugador proactivo para defender, mejor hacia adelante. Busca anticipar, va mucho abajo con buen timing. Muy rápido para defender profundidad, le falta punto de terminar acciones defensivas, a veces duda. Cuando lo superan suele reaccionar rápido para corregir. 

Con balón juega fácil, a pocos toques, sin progresar tanto en conducción. Despeja con contundencia en área, no duda. 

Es un buen central, me genera dudas su estatura para posición.','NB','Seguir'),
  ('452defb3-5d67-544c-b5e0-1504d0b94e2d','854840c7-6245-5f9b-8133-d9a29a0adef7','2026-03-19 13:57:05','vs Badajoz','Por características es un delantero centro que puede explotar en algo muy top. 1.90 m, es rápido, piernas largas, salto espectacular. Irregular técnicamente y en finalización, pero con condiciones difíciles de encontrar para posición.','NB','Firmar'),
  ('13aa2269-5d0f-5032-8661-7f3c17dfea07','b5eb3585-c919-5d04-8793-30794804812a','2026-03-19 15:53:47','vs Mercantil','Central zurdo de físico similar a Bivol: alto, delgado, espigado. Me deja dudas su agilidad/velocidad. Por perfil interesante pero tampoco le veo nada especial en juego.','NB',NULL),
  ('68f61264-42f7-563d-9c5b-5fcf2e215130','93b97381-9e61-509a-a38e-9d7bd1149f87','2026-03-19 15:57:06','vs Mercantil','Perfil de #8 - #10 de buen perfil físico-técnico, capaz de generar individualmente, vertical en acciones. Jugador de características interesantes.','NB','Seguir'),
  ('d682835c-af90-5e54-b599-9387796db629','3870f26e-dabf-5786-8c22-8eeec91f0cf6','2026-03-19 17:53:42','vs Sabadell','Jugador espectacular, perfil muy parecido a Cherif. 6 de estatura media, delgado pero fuerte, rápido, ágil, con recorrido. Buena arrancada en conducción, rompe líneas en esos primeros metros. Dinámico, juega hacia adelante, aún irregular en el pase. Agresivo en fase defensiva, intenso en duelos, buen recuperador.','NB','Firmar'),
  ('6ad32257-06e7-558d-b10f-5bfacfb02c3c','c792d3dc-3015-5485-9fff-7139b941613e','2026-03-19 17:55:46','vs Sabadell','Extremo puro, desequilibrante, con mucho 1v1 y explosividad, capacidad de finalización. Es top.','NB','Firmar'),
  ('1ff4b87e-a4b6-552d-8104-d06213f0f372','7d95c3b7-f358-5d29-a7a3-28b73b305d38','2026-03-20 09:48:10','CASTELLÓN B - Sant Andreu','Central diestro con una estatura algo superior a 1''85 m y complexión delgada. Tiene unas condiciones físicas, técnicas y defensivas muy buenas, pero hoy me ha dejado dudas en cuanto al nivel de concentración y tensión competitiva. Ha cometido demasiados errores.','RP',NULL),
  ('d873becc-ad8a-5054-9467-92c5c0e3d2f8','0db04bac-6b60-5bb5-b5f7-de00dcf9402f','2026-03-20 09:48:46','VILLARREAL JUV. B - Elche Juv. B','Lateral izquierdo con una estatura alrededor de 1''70 m y complexión delgada. Muy rápido y con una arrancada muy explosiva. Técnicamente sobresaliente para escapar de presiones, explotar espacios y combinar con los compañeros. Defensivamente puede mejorar.','RP','Seguir'),
  ('397f9f64-4516-5211-ba97-227e97bbe091','fa85303a-3bd7-52d6-8444-e2c8991e6128','2026-03-20 09:49:19','VILLARREAL JUV. B - Elche Juv. B','Central zurdo con una estatura alrededor de 1''85 m y complexión delgada. Tiene buenas condiciones técnicas y defensivas, pero hoy le ha generado muchos problemas un delantero bajito y con sobrepeso. Dudas.','RP',NULL),
  ('d04a8449-c7a9-5164-9d33-006b11c6b574','24c00223-606d-5dc5-a82c-4af68b159afb','2026-03-20 09:49:57','VILLARREAL JUV. B - Elche Juv. B','Mediocentro con una estatura alrededor de 1''90 m y complexión más o menos fuerte. Buen nivel técnico para la distribución, pero ritmo algo bajo. A duelos va bien, tanto por arriba como por abajo, pero es algo pesado de movimientos.','RP','Seguir'),
  ('8b015f6e-1ea0-5a61-83fa-54c6b8c1416f','56bd0455-c4b6-5a47-93fb-bf0fa60c78ae','2026-03-20 09:50:38','VILLARREAL JUV. B - Elche Juv. B','Interior diestro con una estatura alrededor de 1''90 m y complexión muy fuerte. Buen nivel técnico para controlar, pasar y conducir. Agresivo con balón, siempre busca progresar, con margen de mejora en cuanto a visión de juego. En duelos es muy dominante.','RP','Firmar'),
  ('269736a3-0518-515c-ad09-711051bc344f','0d201649-7765-5c2d-9d84-fae3475c46eb','2026-03-20 09:51:05','VILLARREAL JUV. B - Elche Juv. B','Extremo diestro, en el partido actuando a pierna natural, con una estatura alrededor de 1''70 m y complexión delgada. Muy rápido en carrera y con una arrancada muy explosiva para ganar ventaja en los primeros metros, tanto yendo al espacio como después de una acción de desborde. Es habilidoso para el 1vs1 y agresivo con balón. Perfil Luismi, menos fuerte pero más rápido y vertical.','RP','Seguir'),
  ('1e3fe909-572a-5f16-8aba-0d5ee554b7c5','70bc0460-fbc3-5e9f-ba03-c97d97e8fed9','2026-03-20 09:51:44','VILLARREAL JUV. B - Elche Juv. B','Centrocampista zurdo estilo mediapunta, hoy actuando como falso nueve. Estatura alrededor de 1''75 m, complexión delgada. Sobresaliente técnicamente y con una visión de juego extraordinaria. Capaz de intervenir en varias alturas para mejorar jugadas, acelerar e incluso dar últimos pases o finalizar. Gran jugador, dudas sobre su encaje por perfil físico y táctico.','RP','Seguir'),
  ('119d92ed-41ef-5843-8e38-311bb2ee9bd5','fc505c7b-0ca4-5de9-983f-d0e024b6fb04','2026-03-20 12:36:28','vs Huesca','Extremo diferencial, con gran habilidad para el 1v1. Regateador nato, rápido, explosivo, con buena capacidad de finalización. Por encima de la categoría.','NB','Firmar'),
  ('ea37edf0-ab36-5148-bf6b-92e7d155a605','7e90fc8b-6a7a-5eb7-a735-daf74c24faff','2026-03-20 12:37:28','vs Huesca','Central de buen perfil físico: alto, fuerte, velocidad/agilidad medias. Diestro, uso ok de zurda. Es sólido en acciones defensivas, ganador de duelos, va fuerte en juego aéreo. Me genera alguna duda en cobertura de profundidad. Con balón es correcto, juega hacia adelante, suele buscar desplazar en largo, no tanto en conducción.','NB','Firmar'),
  ('c3b55ab9-feeb-5925-a665-b0789c57bafb','e03ef9d7-1d13-5c80-ba5d-a5fd3b567152','2026-03-20 12:39:46','vs Espanyol','Lateral izquierdo de estatura baja, potente, rápido. Es jugador ofensivo, gana metros en conducción, le falta más técnica para asociarse y superar en corto. En fase defensiva es agresivo, igual puede ganar mayor consistencia/timing pero hace buen trabajo.','NB','Seguir'),
  ('66c712a8-af75-5b0b-a381-e7fbabf5cbcb','af830e62-42de-5d43-9d75-f0e094a90229','2026-03-20 14:43:57','vs Zaragoza','Central diestro de estatura aprox. 1.95 m, da sensación de lento y poco ágil. Con balón tampoco destaca. En fase defensiva lo hace bien, contundente, fuerte en juego aéreo.','NB',NULL),
  ('fa04d214-3cda-5a0c-a84f-6ff3c8cedb81','229095ee-20c5-5748-b8ac-a69fb6fec1d6','2026-03-20 14:45:40','vs Zaragoza','Extremo diestro por izquierda. Buena tipología física para posición, similar a la de Doblas. Alto, fuerte, con zancada rápido sin ser explosivo. 

Jugador con recursos individuales en 1v1, buena capacidad para sacar remates desde media distancia, peligroso yendo en carrera. Quiero verlo más pero es buen perfil.','NB','Seguir'),
  ('780e0400-8a45-5d77-85fa-3abc05eccb79','f14f7895-6ce7-5349-b885-a502e47da05a','2026-03-20 14:49:32','vs Zaragoza','Delantero centro de complexión física interesante, aunque da sensación de algo pesado. Más allá de una buena acción fuera del área y otra de remate en área, poco impacto en el juego.','NB',NULL),
  ('87ac3984-23c3-552a-961a-cf35bc6ba266','cd1dcd85-ccfb-5c48-ac57-ff95c8340a6c','2026-03-21 10:44:37',NULL,'Uno de los porteros con mejor nivel/potencial sub-21 de España. Potencial Champions League.','NB','Firmar'),
  ('ff58437f-6518-558a-b707-aca7d33babb0','b3bf7333-6b04-52ef-8cfb-b06a60cacb98','2026-03-21 13:32:37','vs Torrent','Delantero centro de buen perfil físico: es alto, espigado, musculatura por ganar, parece que va a seguir creciendo. Juega bien de espaldas, se asocia, buenos movimientos en área. Seguir evolución.','NB','Seguir'),
  ('0303655a-8bf0-5861-b894-1d79a965312a','3ed055bd-40c6-5fc3-9329-bfdc32ace474','2026-03-21 13:34:28','vs Torrent','Perfil de mediocentro de gran nivel técnico, capacidad para liderar juego asociativo, toma de decisiones correcta. Con capacidad para superar rivales en corto, con uno contra uno. Es agresivo en fase defensiva aunque no tan imponente por físico. Seguir evolución física.','NB','Seguir'),
  ('d6475443-ea9f-595a-b384-58fe9eed4f26','82267212-1aeb-5bc2-bb1b-d2d7e1946aba','2026-03-21 13:36:54','vs Torrent','Es delantero centro alto, muy fuerte, de velocidad limitada, poco ágil, parece descoordinado. Tiene pinta de que no va a crecer más conociendo a sus padres. 

Le falta bastante a nivel técnico, toma de decisiones y entendimiento. Finaliza bien en área en las acciones que tiene. 

Me genera dudas su evolución.','NB',NULL),
  ('fe8313eb-8532-5275-982c-1e79549b0df7','5a991caf-8ce5-5a87-ba49-48f02eb90218','2026-03-21 17:17:46','vs Turkey','#6 completo, de perfil físico top, condiciones técnicas positivas, entendimiento del juego, capacidad de recuperación y trabajo defensivo. Perfil con gran transferencia a fútbol profesional.','NB','Firmar'),
  ('be670224-2d80-5dcf-9854-54a50cb1d431','a486798c-0dee-58b8-8d58-35c5f5818ec7','2026-03-21 17:20:51','vs Turkey','Extremo de gran perfil físico: muy fuerte, rápido y explosivo. Poderoso en carrera, genera ventajas en espacios largos, más que en cortos. De técnica va bien, sin ser excelente. Mejorable en finalización de jugadas. Perfil similar a Otorbi.','NB','Firmar'),
  ('00651698-cb86-5ad7-bc3f-9b748e874430','d24eb8f3-cf61-5823-b1ca-dced3558ea4e','2026-03-22 11:15:50','vs Don Bosco','Perfil de extremo interesante, de buen físico: estatura aprox 1.75 m, delgado, rápido, explosivo. Con buena técnica, recursos en 1v1, vertical en acciones, desequilibrante. Con buen golpeo de balón. Es un jugador que marca diferencias. 

Por entorno familiar esperar para intentar más adelante.','NB','Seguir'),
  ('78388d7d-3e98-5059-95e0-0dd4508e79ca','5f124f9f-8f09-5dfe-8e80-b35f4167512d','2026-03-22 19:12:01','vs Levante','Es buen perfil pero tiene poco impacto, le cuesta como carrilero. Le falta más físico','NB',NULL),
  ('bcaf4649-1c03-5cce-b8f3-778838a75ae7','853e1e95-f9c7-5150-af29-06f5cd577cc0','2026-03-22 19:14:11','vs Rumbo','Perfil de 8-10 interesante, de nivel técnico alto, capacidad de desequilibrar individualmente, buen golpeo, último pase, con regate. Le falta más trabajo defensivo. Es jugador de estatura media-baja, dinámico y veloz. No tan fuerte.','NB','Seguir'),
  ('09c3b707-defd-5538-8f7e-1f35999467dc','2d5a8030-f273-5dd5-b0b4-6b3bbeb4afd6','2026-03-22 19:18:21','vs Rumbo','Centrocampista #6 de perfil físico top: cercano al 1.90, de complexión fuerte, algo rígido quizás. Jugador con un potencial físico alto. Se le nota evolución en conceptos técnicos y tácticos.','NB','Seguir'),
  ('6300b830-fb71-5e6b-898c-761b11cca387','3d6f9d42-789a-5418-bd0c-050a335e3795','2026-03-22 19:20:53','vs Rumbo','Lateral derecho de estatura media, delgado, rápido, explosivo, con ida y vuelta. Buen perfil físico para posición. Es un jugador interesante, aunque creo que le falta impactar más en juego y fortalecerse defensivamente. Me gustaría verlo en DH antes de decidir, ahora mismo no lo firmaría aún corriendo el riesgo de que lo firme otro.','NB','Seguir'),
  ('332e5c87-87f8-55a7-8a1b-ea4d55ed4a8d','5ee8a63e-d5b9-53d4-b349-9b25c76fcf56','2026-03-23 12:52:11','CASTELLÓN JUV. A - Roda Juv. A','Central zurdo con una estatura alrededor de 1''85 m y complexión delgada. Es aresivo y defiende bien hacia delante, pero es poco contundente. Con balón bien.','RP',NULL),
  ('20b1c2e8-09fd-5dae-9571-ddffe3c2f008','a368b43b-4598-5d6b-987a-e4b3bf15c986','2026-03-23 12:52:44','CASTELLÓN JUV. A - Roda Juv. A','Central diestro en línea de tres, perfil lateral. Estatura algo superior a 1''75 m y complexión fuerte. Defensivamente es contundente, pero se le nota algo incómodo cuando sale de posición. Con balón está bien y tiene recorrido.','RP','Seguir'),
  ('e4750495-130b-59e9-9f50-6886f7eec820','7b8f3b50-985b-5135-85ee-dca627e23044','2026-03-23 12:53:12','CASTELLÓN JUV. A - Roda Juv. A','Delantero centro diestro con una estatura alrededor de 1''85 m y complexión más o menos fuerte. Se mueve muy bien y tiene calidad con el balón para aportar ventajas lejos del área. En últimos metros es peligroso al espacio y carga la pierna rápido. Discreto hoy.','RP','Seguir'),
  ('854d1151-2ad4-515b-a39a-6812ee2cf2a2','e4803eec-495c-5cb4-9234-fba9c43f10b9','2026-03-23 12:54:03','Castellón Juv. A - RODA JUV. A','Central diestro con una estatura algo inferior a 1''90 m y complexión delgada. Partido correcto, con alguna acción de nivel en área. Con balón no destaca.','RP',NULL),
  ('54f76b61-e45c-5db4-8e5d-2796d1710159','2bc000e3-d8ac-5533-989e-5ad48da97d8b','2026-03-23 12:55:04','Castellón Juv. A - RODA JUV. A','Mediapunta zurdo con una estatura alrededor de 1''85 m y complexión normal. Buen nivel técnico y agresivo para girarse y acelerar, pero poco participativo hoy.','RP','Seguir'),
  ('fc3e2b8d-83a3-5a41-930b-861baa660532','16da2511-dc2b-5e7f-a0a1-8a2559dd2fbc','2026-03-23 12:55:36','Castellón Juv. A - RODA JUV. A','Extremo diestro, en el partido actuando en banda izquierda, con una estatura alrededor de 1''75 m y complexión normal. Agresivo para ir al espacio, aunque hoy le ha faltado un punto de explosividad en la arrancada. Ha ganado varios duelos por arriba y ha marcado un gol de cabeza.','RP','Seguir'),
  ('5f607937-ea9d-55ab-a103-118de7787131','cb235efe-dd4b-5a5d-9e53-a89c15d56e2b','2026-03-23 12:57:11','Castellón Juv. A - RODA JUV. A','Delantero centro diestro con una estatura alrededor de 1''80 m y complexión normal. Muy buenos movimientos en el frente de ataque y calidad para aportar ventajas al equipo. Agresivo en últimos metros.','RP','Seguir'),
  ('8c45e993-0da0-5078-81c2-5e0c98f9d675','4bb6f236-8e41-510f-865f-adaf0464749e','2026-03-23 12:58:06','VILLARREAL JUV. A - Patacona Juv. A','Lateral derecho con uma estatura algo inferior a 1''85 m y complexión delgada. Defensivamente puede ser más contundente. Con balón se desenvuelve muy bien en campo rival y jugando por dentro, incluso de espaldas, pero tiene más problemas recibiendo bajo presión en campo propio.','RP','Seguir'),
  ('34dc1bdd-aa12-5a70-966f-8c33aa08177e','99052c44-0e95-5077-980e-dd76ef2bddc7','2026-03-23 12:59:02','VILLARREAL JUV. A - Patacona Juv. A','Centrocampista diestro de primera altura, en el partido actuando en doble pivote. Estatura alrededor de 1''85 m, complexión delgada pero atlética. Seguro en el pase, sin aportar grandes ventajas. Sin balón es agresivo en el duelo y tiene cierta capacidad de robo.','RP','Seguir'),
  ('ea452f5c-762f-5f81-931d-3f1d657def79','13a848f1-428b-5bcd-b641-49b608fc16ef','2026-03-23 13:01:43','VILLARREAL JUV. A - Patacona Juv. A','Delantero centro diestro con una estatura algo superior a 1''80 m y complexión fuerte. Muy rápido en carrera y potente para chocar. Gran movilidad, busca desmarques constantes al espacio y sabe quedarse la pelota para jugar de espaldas.','RP','Firmar'),
  ('c5b52169-06d4-5787-bf56-3759be0a5ebc','f007ea82-e67b-5672-b631-b9de2c400bfc','2026-03-23 13:02:20','VILLARREAL JUV. A - Patacona Juv. A','Extremo diestro, en el partido actuando a pierna cambiada. Estatura algo inferior a 1''75 m, complexión normal. Habilidoso para desbordar y con velocidad y potencia para resistir choques. Agresivo con balón y bastante peligroso cuando recibe en último tercio.','RP','Seguir'),
  ('973d241b-3c86-5026-89ea-4e5b722815e5','7d95c3b7-f358-5d29-a7a3-28b73b305d38','2026-03-25 13:56:22','vs Cultural','No tiene condiciones para ser lateral derecho, donde está jugando por necesidad en primer equipo Castellón. Como central tiene buenas condiciones, aunque es cierto que es un jugador algo inconsistente y desordenado. Aún así tiene buen perfil físico, fuerte en juego aéreo, juega hacia adelante sin técnica tan pulida. 

Estando en Castellón: si el entrenador lo ve, intentar firmar. Sino no.','NB',NULL),
  ('175dd791-ab3c-529c-a53e-a43fd4ca73f2','b953faac-e8a0-5677-8431-5288a1a07f9d','2026-03-25 14:10:30','vs Racing','Lateral izquierdo de físico medio. Estatura media, no tan poderoso, sí que es rápido y explosivo en esos primeros metros. Jugador que va bien hacia adelante, técnicamente bien sin ser top. Sus primeros metros son buenos, genera con balón. En defensa es agresivo para ir al duelo.

Buen lateral para el contexto de Albacete, no me parece mejor que De Roa en nada.','NB','Seguir'),
  ('44217dc7-3905-591d-b968-451525116bdf','d66722d4-dcaf-536b-865f-2212df6f39fc','2026-03-25 20:44:43','vs Eslovenia','Jugador de buen nivel técnico, que se mueve bien entre líneas, con condiciones interesantes para evolucionar en la mediapunta. Tiene el handicap de no ser ni extremo ni delantero, por lo que es futbolista de contexto bastante específico. Lo veo de potencial profesional sólido pero no tengo claro que de primer nivel.','NB','Seguir'),
  ('41df67a0-9ffb-5d5c-a441-1085f848ad15','c110bc78-5b7e-5d41-b0d7-9b93ac484631','2026-03-26 13:34:31',NULL,'Central diestro de estatura cercana al 1.90 m, da sensación de que puede seguir creciendo por estructura física. Aún es algo descordinado de movimientos, imagino que por estirón. Pero tiene un punto de velocidad/agilidad adecuados para la estatura. 

Me recuerda a Román, con punto de contundencia por ganar en duelos en general, mayor solidez/agresividad, pero con una proactividad interesante para generar en posesión.  

Soy consciente de que es jugador por hacer pero le veo potencial para apostar por él.','NB','Firmar'),
  ('4b507b0e-1dca-5e53-bcd9-622f9fbe9957','fa5faf2d-9835-58bb-b866-56b9049b45d1','2026-03-26 13:47:00',NULL,'Lateral izquierdo de estatura baja, dinámico, no poderoso. No le veo nada interesante como potencial.','NB','Descartar'),
  ('39ee26fb-c652-5b77-b794-cd7df5207ee0','9e99bedc-e3b6-5de5-a887-480a9ba001b0','2026-03-26 13:54:31','vs Burgos B','Extremo de físico muy mediocre','NB','Descartar'),
  ('54a7f951-3e51-5013-94c6-9c82488347ce','18c2e7fb-01fb-5bc6-a19b-0e2befd49bc9','2026-03-26 14:01:00','vs Burgos B','Por perfil físico no es interesante. Pequeño, de tren inferior potente pero no tien estatura para 9.','NB','Descartar'),
  ('b422f4b1-88e8-57ff-bff0-25c6e756bbc9','4b6242c8-3e41-5c17-a6de-973c21563012','2026-03-27 12:42:53',NULL,'Extremo diestro, aunque prácticamente ambidiestro por su manejo de la izquierda, con una estatura algo superior a 1''70 m y complexión delgada. Explosivo para los movimientos y con cierta velocidad en carrera, pero sin ser top. 

Se trata de un jugador de desborde, que acostumbra a recibir abierto para el 1vs1 o en pasillo interior para encarar la última línea. Más habilidoso que técnico, una vez controla el balón tiene fintas y recursos ofensivos para desequilibrar, especialmente a través de cambios de dirección rápidos. Al dominar ambas piernas, puede jugar en los dos perfiles y es capaz de desbordar tanto por fuera como por dentro. 

En cuanto a duelos, su físico le impide ser muy dominante en este aspecto. Es intenso y no rehúye el choque, pero no suele imponerse. Tampoco muestra una llegada a área demasiado peligrosa: sin balón no acostumbra a romper al espacio y tampoco sabe cargar el área cuando la jugada va por banda contraria para buscar remate. Es un jugador que por condiciones podría llegar a hacer cifras, pero hasta el momento no tiene una gran producción ofensiva. 

Es un buen jugador, con desequilibrio y peligroso en el último tercio, pero por edad y perfil no creo que vaya a ser un extremo importante en la élite. Sí un buen jugador de fútbol profesional que puede hacer una buena carrera en Segunda e incluso llegar a tocar Primera.','RP','Seguir'),
  ('82ee90c1-f3e6-523b-ae32-1fb3d40b30d5','4aa3f75a-cc70-5ff1-8ee3-19e812f30711','2026-03-27 15:28:31','RACING ZARAGOZA JUV. A - Constancia Juv. A','Atacante diestro, en el partido actuando como delantero centro pero por características podría ser extremo, con una estatura alrededor de 1''80 m y complexión normal. Tiene cierta velocidad y buena técnica con balón para escapar de presiones, eliminar rivales y aportar ventajas. No va mal a duelos. Bastante movilidad en todo el frente de ataque. En el partido marca tres goles y en todos muestra buena definición. Perfil para ver algo más, si tenemos la oportunidad en directo.','RP','Decidir'),
  ('c845a894-fd23-5b59-8ca0-e9bd38ce400e','3dc5e587-9e82-548a-ac18-7a752039ac84','2026-03-27 15:44:08','Racing Zaragoza Juv. A - CONSTANCIA JUV. A','Jugador diestro de banda, en el partido actuando en ambos carriles, aunque con perfil de extremo. Estatura alrededor de 1''80 m, complexión delgada pero fuerte. Rápido en carrera y con un cambio de ritmo interesante para desbordar. Buen desplazamiento de media distancia en forma de centros al área, tanto en movimiento como a balón parado. En el partido juega unos minutos, pero me ha dejado buenas sensaciones. Ver más','RP','Seguir'),
  ('c00cb553-5c47-54fb-ba03-d7f5abda06f9','af06e69a-152a-534f-8118-fad6d3713b69','2026-03-29 15:07:12','vs Grecia','Centrocampista que puede jugar en las 3 alturas, lo veo con mayor potencial de #6 ya que creo que ahí es donde puede tener características más diferenciales con respecto a lo normal en la posición. 

Jugador de nivel técnico alto, con golpeo excelente, dominio de las superficies, visión de juego y remate.

Con capacidad para ganar metros en conducción y superar en regate en espacios reducidos. Preciso en el pase, vertical en acciones, juega hacia adelante. 

En duelos es ganador, agresivo para afrontarlos y se impone por físico.','NB','Firmar'),
  ('e92903ff-8c14-5231-8ddc-3b0d2a31850c','f007ea82-e67b-5672-b631-b9de2c400bfc','2026-03-29 15:33:12','vs Saguntino','Extremo diestro por izquierda. Jugador con poco uso de zurda, con clara tendencia a ir hacia adentro con balón. Es hábil en el 1v1, aunque su toma de decisiones es bastante mejorable. De hecho suele recibir orientándose hacia atrás. Buena velocidad, pero me da la sensación de que le falta algo más de ritmo en su juego en último tercio. 

Lo veo evolucionando en puesto más atrasado, como carrilero.','NB',NULL),
  ('040aa95f-0c4b-5dc6-ba6e-7361b53cc57a','05a30458-126e-555f-bbab-54588b17ce88','2026-03-30 15:35:36','VILLARREAL CAD. A - Castellón Cad. A','Lateral izquierdo de estatura media y complexión más o menos fuerte. Potente en el duelo y en el 1vs1 defensivo. Me ha parecido que es explosivo en los primeros metros. Con balón bien, quiero verle alguna vez más.','RP','Seguir'),
  ('c1ad3a37-81ff-5b9d-ad42-3258ed98b436','82267212-1aeb-5bc2-bb1b-d2d7e1946aba','2026-03-30 15:38:27','VILLARREAL CAD. A - Castellón Cad. A','Delantero centro diestro con una estatura algo inferior a 1''90 m y complexión fuerte. Algo pesado de movimientos y muy flojo con balón. Aporta poco.','RP',NULL),
  ('7a000cd7-7af7-5e6c-9009-5a3861d5f8c2','26bad713-122f-5f1e-899f-a048c4e9fcd5','2026-03-30 15:38:51','Villarreal Cad. A - CASTELLÓN CAD. A','Centrocampista diestro de segunda altura, en el partido actuando en doble pivote. Estatura potencial alrededor de 1''90 m, complexión delgada. No es muy rápido, pero es atrevido para conducir y en estas situaciones es capaz de resistir choques y eliminar rivales. Técnicamente es normal.','RP','Seguir'),
  ('6d91bd48-5b1f-5a9b-87c4-060ee6e188a1','1aa3d4bb-314a-55d6-bdcb-165bc02dea51','2026-03-30 15:40:09','Villarreal Cad. A - CASTELLÓN CAD. A','Carrilero zurdo de estatura medio-baja y complexión normal. No ha estado muy acertado, pero he visto un par de aceleraciones que me han gustado.','RP',NULL),
  ('453fe511-3536-5c35-b570-3a425c5c4372','94ac9314-0695-51c9-9b80-5d3385506240','2026-03-30 15:40:51','Canet Juv. A - VALENCIA JUV. B','Central diestro con una estatura algo superior a 1''85 m y complexión delgada. Buen nivel en general, tanto defensivo como con balón, pero me deja dudas en cuanto a velocidad y contundencia.','RP','Seguir'),
  ('7808ce2f-1921-5fac-a19f-a6418116f362','05d9e8ed-5404-563b-ab5e-f6b2891ae708','2026-03-30 15:42:24','Canet Juv. A - VALENCIA JUV. B','Atacante zurdo, en el partido actuando como delantero centro. Estatura alrededor de 1''85 m, complexión fuerte. Potente en carrera. En el partido busca a menudo el balón al espacio y va al duelo, pero no tiene apenas acciones con balón.','RP','Seguir'),
  ('fd5a8d23-e405-56fc-9253-1953fdaf2ad5','444ab917-8d4b-5445-8230-8a063ee925d4','2026-03-30 23:21:22',NULL,'Delantero centro que en ocasiones juega en banda debido a perfil físico: estatura media, no llega al 1.80 m, es rápido y explosivo. Destaca por movimientos en área y capacidad de finalización. Tiene habilidad para conducir, aunque no destaca por ser un atacante autosuficiente. Me cuesta verlo como #9 por su físico, pero realmente en su mejor posición.','NB',NULL),
  ('f5d5fc85-d334-5f49-919e-a29d3e6b5d28','c435f992-f0da-5bc0-b6ea-51f23beea786','2026-03-31 09:56:21','vs Zuera','Extremo diestro de buen perfil físico: estatura alta (cerca de 1.80), complexión atlética, potente, con zancada sin tener una velocidad explosiva. Igual da sensación de ser algo rígido para posición. Buen manejo de balón, capaz de sacar remates con ambas piernas, generar en carrera, llegar a área y finalizar. 

Jugador bien considerado en el club.','NB','Seguir'),
  ('1e0fa353-82ab-5688-ace8-8c5d8492ddb5','c435f992-f0da-5bc0-b6ea-51f23beea786','2026-03-31 10:41:19','vs Zuera','Extremo diestro por izquierda. Jugador de buen perfil físico, que destaca por tener buena zancada y ser potente. Capaz de manejar ambas piernas, generar desequilibrio en 1v1, ganar metros en conducción, superar rivales con regate en corto. Deja varias acciones interesantes de este estilo. Además muestra un buen golpeo desde fuera del área, potente y preciso.','NB','Firmar'),
  ('118126f9-dedf-50da-a8c5-fd3ae71da389','d0d7f737-bfae-57c9-bf38-e8a7a28a6e73','2026-03-31 13:05:48','vs Betis B','Extremo de perfil físico muy bueno: espigado, de piernas largas, rápido, potente. Deja dudas a nivel técnico y de ejecución. Perfil similar a Jerry del Valencia.','NB','Seguir'),
  ('3f19100b-c12c-535e-86f5-48b34d3d70c1','bf5cd25d-7dfe-5f71-a3a2-01a6974d69ca','2026-03-31 13:08:33','vs Betis','Central de buenos conceptos defensivos, habilidad defensiva y capacidad con balón, pero que me deja muchas dudas a nivel defensivo. Dudas sobre estatura / peso.','NB',NULL),
  ('d93d248a-f4f6-5957-8795-b4863b9da4c5','5636029c-8e0e-5a0c-8814-5291f791f1fc','2026-03-31 13:11:07','vs Betis','Es el jugador más preparado del equipo para subir de nivel. Lateral perfil Carlos de Roa, no tan impresionante físicamente, pero de estatura cercana al 1.80, potente, con zancada. Buen nivel técnico, lectura para moverse por dentro, criterio para pasar en último tercio. En defensa mejorable pero no lo hace mal, es agresivo e intenso. Tiene personalidad.','NB','Firmar'),
  ('e452423a-1188-5d34-bd72-afffd71c5f53','1c4dc383-b594-5dab-98ef-97d420b7956c','2026-04-01 01:00:24','vs Alemania','Central zurdo de perfil físico top. Destaca por su defensa de área, capacidad para ganar en juego aéreo y solidez en duelos. Salvo alguna acción, en la que le faltó mayor decisión, estuvo seguro. Con balón muestra habilidad para pasar el largo y por dentro, superando líneas. No se le ve tanto en conducción.','NB','Firmar'),
  ('bcfadd2e-3071-57ba-9a15-c39587574d42','24c4c209-23ba-575f-81b3-4b766b1182cc','2026-04-01 11:24:53','vs Bulgaria','Rubén de Sá es jugador con capacidad para jugar en diferentes posiciones, en mi opinión mejor por dentro como #8 o segundo punta. En este partido juega de extremo, siendo de lo mejor del equipo. 

Le destaco su buen físico (aprox. 1.80, delgado, rápido, ágil para giros, con recorrido y repetición de esfuerzos): Le falta un punto de habilidad en espacios reducidos pero es capaz de generar desequilibrio individual, tanto en carrera como yendo al espacio. Pisa bien área y tiene repertorio para finalizar.','NB','Firmar'),
  ('62a6f8c2-2c93-57c0-b36a-20a4663035c6','193153e1-14c5-5ead-bacc-97164aead1d3','2026-04-01 11:30:20','vs Bulgaria','Dani Fernández es extremo zurdo que juega por derecha. Buena tipología física: cercano al 1.80 m, delgado, rápido, sin dar sensación de tan explosivo. Jugador de nivel técnico alto, capacidad para moverse por zonas interiores y pisar área. Tiene recursos en uno contra uno. Se asocia bien. No es un extremo tan puro pero está habituado a banda. 

Jugador que es firmar por movimiento próximo, aunque tengo ciertas dudas sobre su impacto en élite.','NB','Firmar'),
  ('1a179d2b-70d4-5ed4-9da0-ce40b1d42ca0','6ca7a462-18c5-5a5c-8405-5822a9d14e46','2026-04-01 11:33:05','vs Bulgaria','Central de buen perfil físico, sin ser excelente. Estatura 1.85 aprox, complexión normal, velocidad ok. Es bastante seguro en fase defensiva y tiene calidad en salida de balón, pero no me parece especial ni por talento defensivo ni por aportación en juego asociativo. Dudas sobre su potencial para élite.','NB',NULL),
  ('581e898b-92ba-5d86-9ef7-81b23689f36e','c77695e6-b66f-50c1-9545-8cef3d7230c8','2026-04-01 13:02:24','vs Holanda','Central que me deja grata impresión en vídeo y en directo. Creo que tiene potencial sólido de Primera División. Buen perfil físico, muy sólido en fase defensiva, con buen pase largo. Es jugador de condiciones muy positivas.','NB','Firmar'),
  ('98eca5bb-aaa5-5a9d-b6c2-6ea7c838ff43','dc2b8717-1dec-5273-ad4b-a8462127d8fc','2026-04-01 14:41:08','vs Cádiz','Centrocampista que no destaca ni por perfil físico ni condiciones','NB',NULL),
  ('2d8d762c-7a6e-5da6-acc8-1cd2c63593ea','2fca2493-701f-5ef3-b2ed-345e292d79d0','2026-04-13 15:15:00','vs  Terrassa','Aaron Mayol:

Juega de mediocentro. Perfil físico top para posición: estatura cercana al 1.80 m, complexión fuerte, es rápido y ágil, con recorrido. Perfil de ida y vuelta, sin suficiente habilidad para dar control como #6 pero sí con ritmo para box-to-box. 

Intenso en fase defensiva, agresivo para afrontar duelos e ir al choque. Lo veo más ordenado en posesión, destacando por impacto en último tercio. Llega con peligro, envía balones con criterio al área.

Aún siendo desordenado e irregular a nivel técnico es futbolista de ritmos altos, capacitado para destacar en el fútbol actual. Es firmar.','NB','Firmar'),
  ('e06376cc-1128-5943-bf50-86eeca7c4820','3e396cdd-7cfd-5984-b4ac-23433caf2d6f','2026-04-01 15:59:09','vs Torre del Mar','Mediapunta / segundo punta de estatura 1.85 m, delgado, veloz, no explosivo. Con margen de crecimiento en cuanto a masa muscular. Jugador que destaca por nivel técnico, movimientos por dentro, habilidad en 1v1 y último pase. Tiene visión de juego para filtrar a área. Puede jugar como extremo pero me parece mejor por dentro.','NB','Firmar'),
  ('dda7281c-2171-54aa-bc12-c5ba2dbfeaff','061b7652-9f8e-5a6f-b766-b09701e52e1a','2026-04-01 17:30:40','vs Alcorcón','Lateral derecho de buen perfil físico: buena estatura, velocidad, agilidad, recorrido e ida y vuelta. Aún no está hecho. Con buen nivel técnico y verticalidad, llega con peligro a ataque.','NB','Firmar'),
  ('51223e5a-746b-521d-a894-5e360a3fe5a6','dc601b18-2693-5739-8564-d4f7bb0a1505','2026-04-01 17:32:30','vs Alcorcón','#6 de buen perfil físico, que muestra nivel técnico interesante, capacidad para superar presión en espacios reducidos, calidad en el pase. Intenso en fase defensiva, con tendencia a ir abajo. La única duda es su ritmo, da sensación de algo lento.','NB',NULL),
  ('6659871c-5980-56e4-995b-ffecd9f8684c','52f45cc3-0f17-58ec-862c-b62dc4a9f91f','2026-04-01 17:34:22','vs Alcorcon','Extremo zurdo, rápido, de buen nivel técnico, uno contra uno y golpeo. Me deja dudas su evolución física pero es un perfil interesante.','NB','Seguir'),
  ('c9cf410f-d5fd-513d-aa71-6422dfcbfa09','cf3ec630-28e3-578e-9d70-4432296f1f4c','2026-04-02 08:50:03','vs Madrid','Central zurdo de buen perfil físico y salida de balón. Ver más pero el perfil es interesante a primera vista.','NB','Seguir'),
  ('80d3e675-3cf3-5353-b43b-20277a6347bc','a9e6e5e9-9cee-511f-89b4-7e8b66d3d3d8','2026-04-02 10:51:11','vs IDA','Central diestro de condiciones físicas top: alto, piernas largas, va a seguir creciendo. Es rápido y ágil. Algo descoordinado aún pero nada preocupante. Diestro, con manejo de zurda. Destaca en salida de balón por capacidad para progresar en conducción. Aún irregular en términos defensivos pero agresivo. Jugador que combina acciones de mucho nivel con comprensión mejorable del juego. Está muy por hacer pero tiene atributos interesantes.','NB','Firmar'),
  ('85eb6cf0-4fa1-5ba2-b463-e8ca3b0648c3','4559dfaf-cb55-5444-9d46-be0a0bd08b0e','2026-04-02 10:56:49','vs IDA','Extremo diestro de perfil físico top. Irregular a nivel técnico pero con una arrancada y conducción muy interesante. Jugador salvaje, poco constante e irregular, pero con condiciones a seguir.','NB','Seguir'),
  ('9c86ac4a-91ac-54ab-a1c6-98e42ae60999','c4f72e34-20cf-5aa5-849d-655009ba77c2','2026-04-02 14:56:13','MIC','Central diestro con un perfil físico interesante en cuanto a estatura, complexión y potencia. He visto un par de acciones muy contundentes y con bastante criterio tanto en defensa como con balón. Quiero que le veamos alguna vez más.','RP','Seguir'),
  ('aa03ef10-7fd4-5cfd-9f85-c669067ac368','80ce6591-fc7b-5e08-9362-77a36f7c6c07','2026-04-02 15:03:21','MIC','Central con una estatura alrededor de 1''85 m y complexión fuerte, visualmente algo pesado pero me ha parecido bastante ágil. No sé si tan rápido en carrera. Muy contundente en acciones defensivas y buenas condiciones con balón.','RP',NULL),
  ('5cbfffdb-8cea-5a28-9b76-cb1bd4390cc7','4c9ac561-4321-593b-bb95-13a7147f5e82','2026-04-02 15:06:28','MIC','Mediocentro diestro con una gran movilidad, adaptable a posición de interior por condiciones físicas y técnicas. Estatura cercana a 1''85 m y complexión delgada pero fuerte. Bueno en el robo y con un gran despliegue en el campo. Con balón, buena técnica y personalidad para retener y buscar las mejores soluciones, también en conducción. Me ha gustado mucho, aunque el rival era flojo.','RP','Seguir'),
  ('be3ef37c-caf1-5d9e-a5a8-5140679e2e11','ec9c09c0-86fd-517c-9e64-9fcf6ee89d83','2026-04-02 20:33:45','vs Patacona','Extremo zurdo, de estatura baja, rápido y bastante explosivo. Genera peligro yendo al espacio y en conducción, con poca productividad en último tercio.','NB',NULL),
  ('3ea8c619-eb26-5cd6-a577-629d85bc89e8','c0c27708-50cf-54bc-b219-856962c200ac','2026-04-02 21:07:54','MIC','Central diestro con una estatura algo superior a 1''85 m y complexión fuerte, con margen de mejora. Potente en el duelo, proactivo para defender y con mucha jerarquía defensivamente y con balón. El rival era flojo, quiero verlo más.','RP','Seguir'),
  ('1ebfff5b-93c3-5393-94f5-7b3cb1c8f84d','1d578039-e34f-57a0-ae61-79b608c4ea67','2026-04-03 11:47:23','MIC','#6 de estatura aproximada 1.90, piernas largas, complexión atlética, margen de mejora en cuanto a potencia. Es lento en espacios reducidos y en carrera y esto lo puede limitar. Tiene una buena lectura que le permite suplirlo, aunque sigue notándose. 

Tiene buen pie para asociarse, busca ganar metros en conducción e incorporarse. Agresivo en fase defensiva.','NB','Firmar')
ON CONFLICT (id) DO NOTHING;

